begin;

insert into public.lesson_records (lesson_record_id, student_id, course_id, staff_id, lesson_date, start_time, end_time, title, content, homework, memo) values
  ('da73de3c-6d42-5120-b1ff-3449a64083bd', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-11-08', null, null, '通常 / エクセル検定対策', '前回の続きで３０時間・８章・実習４７を進めて完了させました。内容としては、マクロの使い方が複雑で結構難しいようで、分からない点を何点か教えて理解してくれたようです。今日はこれで時間となってしまいました。はるくんは、エクセル３級レベルの内容は理解しているとのことなので、次回は、本番感覚でスピードを意識して模擬問題を解いてもらう形にしたいですね。', null, '時間帯: その他'),
  ('24092a46-823a-531c-ab10-f66277182d4e', '40a476bc-72a5-5bdc-ab75-e89d5310b442', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-11-08', null, null, '通常 / 検定対策', '最初に、制限時間が３０分であること、問題文をしっかり読んで、問題文の順番で、問題文で示されたブロックを使うように、別のやり方でしないように伝えて始めてもらいました。問題解いている途中は、独り言を呟きなら進めていました。質問が一つだけあり、セリフを消す方法がわからないとのことでしたが、吹き出しを空っぽにするという、一度経験しないと分からないものなので、しっかりと覚えてもらいました。それ以外は特に問題なく、答え合わせした結果も、ほぼ問題なしで合格できるできる結果でした。', null, '時間帯: その他'),
  ('4e7f7b30-3449-5dbb-81fc-30c08a42ef81', '31feac25-f850-5d21-8e43-ed4d7badb6a0', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-11-08', null, null, '通常 / 検定対策', '検定を解いている間は、特にこれといった質問もなく、アレンジも含めて４０分ほどで完成させました。ただ音を鳴らすところを「終わるまで音を鳴らすとか」、ブロックの順番を間違えて配置したりという軽微なミスが何点かありましたが、十分合格できる結果だと思います。アレンジはクローンを使って攻撃時の魔法と、敵のドラゴンを大量に発生させていて、すごい見栄えになっていました。', null, '時間帯: その他
タイピング: ココアタイピングのストーリーが好きでいつも集中して取り組んでいます'),
  ('6d63e40d-9d82-55f0-a0a9-9b19ab0a77b6', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-11-08', null, null, '通常 / ロブロックス', 'いつも通り、時間を決めて（20分から）レッスンを始めました。何点か質問を受けて、例えば、エクスプローラの表示の仕方や、Humanoidをどこから参照できるかとか、RobloxStudioの使い方に関する質問で、プログラムに関する質問はなく、ゲームを裏でしながら、デジタネを進めていたので、ステージ２はもっと集中しないと理解できないよと伝えて、絶対理解できていないだろうなと私が感じていたところを少し教えようとしたところで、お腹が痛くなったらしく、トイレに長い時間こもっている間に、レッスン終了時間となってしまいました。ステージ２は最初から結構理解が難しいのでもう少し集中してほしいところです。', null, '時間帯: その他'),
  ('a66dbfd8-e3ac-5af4-9ee8-92b744332baa', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-08', null, null, '通常 / 検定練習', '頑張って解きすすめ、一通り終わったのですが、バグが直らないという質問を受けて一緒に見てみました。「②(繰り返し)が終わったあと」という指示を理解できておらず、その処理を繰り返しの中にいれてしまっていました。また、音を鳴らし忘れているなど読み落としも少しありました。すべてのバグの原因は確認できなかったので、次回冒頭でやるたいところです。', null, '時間帯: その他'),
  ('d7f900fc-d93b-5aff-b00a-e0c63056cf46', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-08', null, null, '通常 / 検定練習', '2級の内容を固めるか、余裕と興味がある場合は1級に挑戦するかを選択してもらいました。本人は後者を選び、難しそうだと言いつつも比較的自走して進められました。ただし、経験値の浅さもあってか「左を向くのは-90度で合ってる？」といった基礎的な部分で不安になる場面も見られました。今後はスキルの抜け漏れを確認しながら進めていきたいところです。答え合わせまでは行えなかったため、来週はその確認から入る予定です。', null, '時間帯: その他'),
  ('6bfac413-0c8f-5e4d-a747-cbdab9268c28', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-08', null, null, '通常 / 検定練習', '４級は余裕があるそうなので、3級1回目に挑戦してもらいました。問題用紙に一文ずつチェックをつけながら、丁寧に読んでいきました。3級で初めて出たスキル(変数歩動かす、AかつB、ではないまで待つ など)について質問してきましたが、軽く誘導すれば答えにたどりつけるくらいに理解していました。本人のやる気もあるので、頑張れば3級も狙えそうな様子でした。', null, '時間帯: その他'),
  ('c42ca98b-1582-56bc-a6af-91631356bcbb', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-08', null, null, '通常 / 検定練習', '先日Windowsパソコンの画面が目に合わないと言っていましたが、中くらいのChromebook(ミケ・トラなど)も合わないとのことでした。小さいChromebook(ハリー・ロン・ポチ)がよさそうです。 最初は検定問題をやる気になったので、「困ったらすぐ教えて」とだけ伝えて放任したのですが、結局すぐ脱線してしまい、アルスタジオで音をいじって遊んでいました。親御さんと話し合い、興味がもてない場合はプログラミングからイラストコースに転向する選択肢もあることについて触れました。', null, '時間帯: その他'),
  ('ed0a1ff3-1755-5e21-bfee-5110e273e33d', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-08', null, null, '通常 / 検定練習', '集中して取り組めていましたが、以下のような課題が見られました。 ・「でなければ〜する」という文を見た際、どのように処理すればよいか迷っていました。前の文と合わせて二通りに分岐していることをヒントとして伝えると、「もし〜なら／でなければ〜」の構造に気づけたようでした。 ・「他のスクリプトを止める」ブロックの使いどころがわからなかったため、遠くから止めることをリモコンに例えて説明したところ、理解が深まったようでした。 ・「②のあと〜する」という指示で②の内容を把握していなかったため、そういった場合は読み返すように助言しました。 これらの課題を解決したことで、理解を他のスプライトにも応用できました。来週以降も内容を覚えていれば、しっかり合格できそうです。', null, '時間帯: その他'),
  ('21e58f5e-c06f-55e6-995d-fcf86eb8eb72', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-08', null, null, '通常 / 検定練習', '演算(数式)の部分が複雑な問題に取り組みました。若干混乱もしていましたが、算数は得意なのもあり、演算ブロックを組み合わせる順番にも気を使ってしっかり作れていました。終わると、「モグラとネズミの区別がつかなくてやりづらい」と、モグラを徐々に変色させていくアレンジをしていました。', null, '時間帯: その他'),
  ('8c6ca00c-a568-5e53-85f8-0148273ce741', '28d52d6e-7571-5090-a2d9-492c997b719e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-08', null, null, '通常 / 検定練習', 'こんなの余裕だという態度でしたが、これまで集中できていないことも多かったので、きっちり時間を計って制限時間の意識をつけてもらいました。 分量が多めでしたが、距離や乱数などやや難しめのブロックも使えており、淡々と進められました。時間ちょうどくらいで解き終えられ、ミスもあまりありませんでした。', null, '時間帯: その他'),
  ('c1c274bb-546a-58da-aa70-1294a99ff924', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-07', '16:30:00', null, '通常 / 検定練習', 'おてほんムービーを見ずに完成させると豪語し、文章だけを見て一通り最後まで取り組みました。ただ、「全体のイメージがつかめるし、正しい動作かどうか確かめられないから見たほうがいいよ」とは伝えました。結局少しバグがあったのですが、答え合わせは最後の手段として自力で修正を試みていました。その修正もほぼこなせていました。ケアレスミスに注意しながらやっていこうと伝えて終わりました。', null, null),
  ('8c7fc978-e928-5e44-91a0-035289fea903', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-07', '16:30:00', null, '通常 / 検定練習、飛び級の検討', 'これまで4級の課題を4つやってみて余裕がありそうだったので、3級にチャレンジしました。レベルが上がったのにも関わらずスムーズに解き進めていき、30分ほどで終えてしまいました。答え合わせすると完璧でした。3級も飛ばしたいとすら言っていましたが、3級は範囲が広いので、スキルの抜け漏れを防ぐためにも受験してもらうことにしました。', null, null),
  ('0adb7afe-95df-5d88-a59a-5f52f58cf37e', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-07', '16:30:00', null, '通常 / Roblox or 自由製作', 'Robloxを進める予定でしたが、新しいScratchゲームを制作したいとのことで進めていました。ロボットにネジを取り付けて動かすゲームを作り、ネジの回転をコスチューム変化で再現するなどしていました。また、詳しい構想をメモに残し、自分のファイルに挟んでいました。', null, null),
  ('0acef734-01e5-54b8-be77-9ddc2e1208cd', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-07', '17:30:00', null, '通常 / Roblox', '振替なので、奎歩くんと一緒にレッスンをする予定でしたが、robloxゲームを遊ぶのに夢中になってしまい始めてくれませんでした。他の子と同様に開始時刻を約束しようとしましたが、「イベントの周回が終わらないから」とやめてくれず、結局最後までできませんでした。レッスン内容がサーバーとの通信にも関係してくるなど、レベルが上がってモチベーションが下がっているかもしれません。', null, null),
  ('97803aa6-6fda-5e15-a96f-6ae361570433', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-07', '17:30:00', null, '通常 / 検定練習', '比較的早い時間からやる気になってくれたので、じっくり進められていました。複雑な繰り返しの中身が理解できず、一旦飛ばしていました。ただ、そこで嫌にはならず自分のできる場所は確実に取っていました。したがって、合格に向かう態度は以前よりも出来てきていると感じます。飛ばした場所の振り返りができていないので、次回冒頭で行いたいところです。難所に対して少しでも自力で対応する術を伝えられれば、自信がつくと思います。', null, null),
  ('787e27d5-9a57-553a-8586-3d2371cdc359', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-07', '17:30:00', null, '通常 / 検定練習', '前回の答え合わせをし、バグの原因の絞り込みかたや、不要なコードを作ってしまったら削除するなど、今までに扱ったケアレスミス防止策を復習しました。その後、新しい問題に取り組みました。集中してできていました。復習に少し時間を割いたのもあり、答え合わせはできていないので次回冒頭でやりたいところです。', null, null),
  ('a651cfd6-9695-544f-98d4-b6d464605c44', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-07', '18:40:00', null, '通常 / Roblox', '基本的には繰り返しや座標変化、変数といったコードの内容を理解して作れていました。ただ、往復するはずのエレベーターが同じ場所にとどまり続けてしまうバグが出てきて、原因が良く分からないとのことだったので一緒に探りました。結果として、アンカーをかけ忘れて重力で落ち続けていたことがわかりました。 また、教材ではscriptの名前をElevatorScriptのように変えているのですが、りょうやくんは面倒だといって変えていませんでした。確かにそれをしなくても動作はするのですが、オブジェクトやスクリプトが多く複雑になってくるので、誤解なく区別するためにも名前変更はしてもらいました。', null, null),
  ('22f840dd-a19f-5a99-bdd2-4c9d73829d27', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-07', '18:40:00', null, '通常 / Excel', 'ほぼ自走できていました。Excel検定に向けて、自信のない部分を補強するように取り組んでいきました。', null, null),
  ('097657d7-6006-5b0c-b0ad-89bc0644c2cb', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-10', '16:30:00', null, '通常 / 検定練習', '今回の問題は、自分でタイピングしなきゃいけない場面がかなり多くなっていたので、やる気が下がっていき、スローペースでした。でも、コード作成に悩むことはなく、ゆっくりながら40分くらいで完成できました。本番はタイピングないから大丈夫と伝えると、よかったと安心した表情でしていました。力は十分ににあります', null, null),
  ('4aecd012-b707-5242-a38a-a7b8b85e84a8', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-10', '16:30:00', null, '通常 / 検定練習', '今回の問題は、タイピング量が多いものの、苦手ではないので、いつものペースで進めていきました。ただ、「⑥「最後」のメッセージを受け取った時、⑧をの動作を止める」のところで、止まるがどこに入れたらよいかわからず、手が止まりましh田。このメッセージ受け取りコードを作る流れは一緒でしたが、同じ考え方にならなかったです。そこで、わからないながらでの、まずはおいてみて、確かめることを勧めましたが。tryの気持ちになれず、一緒に解決しました。がくくんは1つわからんことがあると、止まってしまうので、今回の急では大丈夫ですが、今後が心配です。', null, null),
  ('28111a76-bfe8-523f-b730-96ce65fdd24e', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-10', '16:30:00', null, '通常 / 検定練習', '授業始まったら、一番乗りで取り組んでくれました。メインはそういちろうくんがみてくれので、チラ見程度で、順調よく進んでいました。こうすけんくんも「止まる」のコードのところで、悩んでいました。そういちろうくんでもうまくアプローチできていない感じだったので、自分が入って、止めるの3種の効果を考えました。そしたら、ほかのスプリクトを止める」追加で自力解決できました。', null, null),
  ('6073a5c8-6355-5dc2-bc1f-b24fb55684cf', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '83ae3e93-da56-5457-9b20-ac9382043cb8', '2025-11-10', '17:30:00', null, '通常 / 検定練習', '4時半で検定の進め方、準備を教えたので、基本はバイトの2人に任せました。途中、しゅうくんがじぶんの顔をみて質問のある感じを出していたので、、そこも2人回して、おそらくの変数の部分でしたが、対応できていました。時間内に終わり、残りは自由時間にしました。 授業時間中に、母親がいらして、検定のことに伝えました。受験のこともあるので、来年には1級を取りたいそうです。能力的には、親子大会でもかなり自分で動かすことができているので、問題はなさそうな気がします。', null, null),
  ('67844bee-2aea-58d9-963e-3541685c9874', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-10', '17:30:00', null, '通常 / ロブロックス', '今回は、動画を見ると言いながら、前半の新しいところがほぼない、2つだけを見ていました。それで終わった気になって他はずっと遊んでいました。今日はけいだいくんメインにしていたので、その状態で放置するしかなかったです。', null, null),
  ('82198b94-dde2-55df-a53b-e34075990711', '5e1dea40-5c67-55ca-a3d8-e696d9b49163', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-10', '16:30:00', null, '通常 / 検定練習', '結論から言うと、検定合格は厳しいです。 先生がそばにいないと、ほぼ進められないし、1ブロックごとに確認を取ってくるので、自分で進める力が乏しいです。特に、ブロックの場所がわからないことがかなり重症です。「歩動かす」「何秒待つ」「何回繰り返す」「隠す」などの場所が前回触れたことがあっても忘れていることがほとんどです。今回1度使ったブロックも再度使うときに、探すのに時間がかかってしまいます。ほかに、文章では「消える」コードでは「隠す」のような言葉のニュアンスの違いがなかなか覚えられなかったです。2回目の問題だったので、本番と同じ形式だったが、ヒントブロックの存在でぶっろく探しは楽になったが、ただそのまま持ってきて、次にすすでしまいそうになる場面が何度かありました。「数字はどうだったか」とこちら側からそのたびに振りかける必要がありました。なので、コードの能力が乏しいこともあるが、、文章を読んで理解することもちょっと苦手なような気がします。あと1回あるとしても、自分で進めるようにうまいアプローチが思いつかないです。', null, null),
  ('f010f4b7-1f84-564e-bbc1-852928182969', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-04', '16:30:00', null, '通常 / 検定対策', '自宅で話し合って、検定を受ける意思を確認済みです。 今日は、定義の確認をしたら、あとはくそげーとかつっこみながらもほぼ自力でできました。なんだかんだいいながら、やらなきゃいけないとは思っているようです💦', '定義のある演習をやると予告済み', '盛り上がり: 定義の引数以外は、自分でも思ったよりもできたのか、口は悪いけれどちょっと得意げにぶつぶつと突っ込みを入れていました。'),
  ('bcb962fb-2bdd-504a-a69d-598cf6c7f354', '1c7005cc-2815-558f-993a-9c7617d34c44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-04', '16:30:00', null, '通常 / 基本的なスキルを学ぶ', '物語を作ろうカードの自分の声を追加しようまで終わりました。 数字を入力するときの半角全角の違いが理解できていました。 最初に登場させる位置のコードがあまり理解できていない様子でした。(ただ答えのコードの数値を入力して終わらせようとする。) 次回は滑るように動かそうの続きから行いたいです。', null, null),
  ('cfec3ee9-9dcd-566e-95db-30b770fa0454', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-04', '17:30:00', null, '通常 / 検定対策', '入れ子にしていく演算式で、考えるのが少しいやになっていたので、細かく区切って一緒に考えてみました。1問目を対応した結果、2回目は自分でやろうとする姿勢が見られました。 「わったあまり」はわかりやすかったようですが、切り下げなど、聞きなれない言葉で混乱したようでした。', '次回、ゲームがスタートしないバグさがし。10分前に力尽きたので、バグ探しは次回に後回しとなりました。', 'タイピング: 毎パソの結果速報を教えました。まあまあかな、といった感じでした。
盛り上がり: 問題が一気に難しくなって、気力がなくなるときもありましたが、一つ教えると、それをもとに自力でやろうと頑張っていました。'),
  ('8b8fc878-6046-559c-aae8-e4ba05f3b8b4', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-04', '17:30:00', null, '通常 / 検定対策', 'ほぼ自力で問題なく解けていました。 リストにのっていない値を、含まれるではない、で書くやり方の確認だけ助言をしました。 また、問題文を深読みしすぎて、y座標を〇〇にするで混乱していました💦', '前回のバグ確認', 'タイピング: 毎パソの結果を嬉しそうに聞いていましたが、もう一段上を取りたかったようでもありました。
盛り上がり: 何問か1級問題を解いてきて、だいぶ自信もついてきたようでした。'),
  ('4708b492-13c3-5492-8dcd-8ca3c83ef93e', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-04', '17:30:00', null, '振替 / 検定対策', '自分で1番難しい勝ち負けの判定ができていました。(「かつ」と「または」を組み合わせるのに苦戦している様子は見られましたが) じゃんけんの見た目が変わらない、テキストが表示されない部分の修正も行いました。', null, null),
  ('3368a8ca-8029-5e8a-af0f-492b8a1a3966', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-04', '17:30:00', null, '振替 / 検定対策', '全体的にスムーズに進められていました。 ずっとのつけ忘れやまでの範囲間違いなどがあったのでゆっくり文を読んで作れるとミスが減ると思います。十字架の動きがうまくいかず皆んなで悩んでいたのですが、最初にお試しに作ったと思われる神父にずっと行くが動作してしまっていました。綺麗にするを定期的に使って防止したいです。', null, null),
  ('8fae1dad-85e3-5d4f-bc9a-f20251e291e7', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-11', '16:30:00', null, '通常 / 検定対策', '検定費用を持ってきたのですが、授業開始時から「つかれた」「問題はやりたくない」とうつぶせていました。長時間集中するのがだるいようです。 おうちの人と話して受けることに決めたんだよね、という話はしましたが、それでもつかれているとウダウダしていたので、とりあえず、どんな作品を作るのか、完成品を見てみようと促すと、やっと顔を上げてくれました。課題のゲームを少し遊んだ後、コードを見てもらいました。無理～とぼやくので、コードは知っているやつばかりだよね、と話し、不安要素である定義の引数のところだけ、一緒に作成しようかと誘うと乗ってきました。 結局、定義ブロックがかかわるところだけ一緒にやりましたが、実際にやれば、ほぼ自力でできていました。 今日はこれでいい、というので、残りは好きにさせました。 来週元気があったら、もう1問やろうと声掛けをして終了しました。', null, '盛り上がり: きちんとやればできないことはないのですが、とにかくだるそうです…。 それでもなんとか、一部だけ自分でやってみて、それなりに手ごたえがあったようではありました。'),
  ('29c55c13-23ae-5d68-b788-478429de5a9b', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'd45d6c5d-18cd-5aa2-99ea-932c81442c55', '2025-11-11', '17:30:00', null, '通常 / 検定対策', '前回のもぐら叩きのバグ直しを行いました。 スタートが正しく始まるようにはなったのですが、モグラとねずみが正しく表示されない部分が時間がたりず完全に直すことができませんでした。と言うブロックに(ばなな)と(りんご)のブロックを使って変数の値を表示させることができました。複雑な演算(変数の値を割った値を掛けてさらに値を足すなど)にあまり自信がない様子でした。全体的に自信の無さからやる気が落ちていたので、次回は難易度が低めのもので完成したものがきちんと動くという経験ができるといいと思いました。', null, null),
  ('d6429223-03c9-54c4-a67b-2de762c8295b', '1c7005cc-2815-558f-993a-9c7617d34c44', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2025-11-11', '16:30:00', null, '通常 / 基本的なスキルを学ぶ', '比較的集中して取り組んでいた。基本操作コース06を終わらせることができた。詰まることなく進めれていた。 15分ほど余しで単元終了したので、残りの時間はゲームをしていた。', null, '盛り上がり: 時折ふざけながら取り組んでいた。'),
  ('38035758-f4dc-55aa-b6d4-98855b587f9a', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-11', '17:30:00', null, '通常 / 検定対策', '前回のバグの理由については、「問題文の通りのブロックを使い、リスト名やメッセージ名をよく確認すること」で解決できそうなことを最初に説明しました。 前回は、リストにある文字が含まれているかどうかの判断で、リストのブロックではなく演算のブロックを使用していました。また、リストへの「追加」と「挿入」を混同していたため、こちらも問題文の通りに作ること、全部解き終わってからバグを探すのは大変なので、問題の読み落としがないように丁寧に進めるよう指導しました。 本人も納得して、次の問題をやりたがったため、応用課題4に進みました。 こちらは授業時間を5分ほどオーバーしましたが、問題自体はちょうど時間内に解き終わり、本人もおかしなところはなかったとのことでした。', '応用課題2', '盛り上がり: タイピングの認定証を嬉しそうに見ていました。 検定問題も、今日の課題はよくできたようで、すっきりした感じで帰っていきました。'),
  ('4155d514-1c95-5fc6-a5aa-f8c342028a98', '512b2f12-24bc-5afa-913a-d68b4a9f9e14', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-06', '16:30:00', null, '通常 / 基本的な書式設定の復習と条件付き書式', 'セルを結合して中央、配置、罫線、塗りつぶしなどはよく覚えていて、自力でできました。今日の新しい学びとして、条件付き書式でキャラのイメージに合ったセルの色を設定しました。覚えは早く、1つ教えるとほぼ自走できます。ネット上の画像を右クリックでコピーして貼り付けを楽しそうにやっていました。', null, null),
  ('ea7ba95c-fba3-5932-9a5c-5ac7f1677a5b', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-06', '16:30:00', null, '通常 / 検定対策', '検定問題をやったら自由時間、のためというと、取り組んでくれました💦 条件があると、すべて「もし〇〇なら」にしてしまう傾向があり、そこで行き詰って嫌になっていました。問題文の文末に「まで待つ」と書いてあるのに注目させると、あとは自力でできました。 授業時間が半分ほど余りましたが、残りはずっと遊んでいました。', null, '盛り上がり: やればさっさとできて、得意そうにもなるのですが、それ以上はなかなかやりません…'),
  ('ef0a775a-30ba-5895-a255-598470e38575', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-06', '17:30:00', null, '通常 / 基本的なスキルの復習', '検定や、時間のかかるプログラミングは疲れるとのことなので、ドリル形式の学習を勧めました。本人ものってきて、これなら眠くならないでできそう、とのこと。 F-1を自力でやったあとは、ひたすら楽しそうにアレンジをしていました。', null, '盛り上がり: コンテストの作品作りが終わってモチベーションを心配していましたが、分量とレベルがちょうどよかったのか、最後までだれずに楽しそうに取り組めていました。'),
  ('dbbe6715-47e8-5403-b659-66e63687c4a2', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, null, '2025-11-06', '17:30:00', null, '休み（振替対象）', null, null, '備考: 体調不良のため'),
  ('3c2960b4-bb69-584b-9e7f-df22ee9156d9', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-06', '17:30:00', null, '通常 / 検定対策', '悩んでいるところを聞き出し、ブロックの構成で原因となっている点を「ここ変じゃない？」と伝えたところ自分で矛盾点を理解し、問題と照らし合わせながら正解を出せていました。 話をした時に「あ確かに！」と前向きに反応出来ていたと思います。', null, null),
  ('4febb9c5-5d17-520b-ac10-df765886fb3d', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-13', '16:30:00', null, '通常 / 検定練習', '今回の問題はえみちゃんとは相性が悪かったみたいです。忘れがちな「聞いて待つ」のブロックや演算系の切り上げや四捨五入系のブロックを最後に触れられてよかったです。1時間やって修正部分の公判ができていない感じです。基本部分はよくできていたので、この調子でお願いします。', null, null),
  ('bad86169-39cb-5b57-88a7-ba5199d5a6c7', 'f3102a36-fdd8-574f-bf3c-85723faf424f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-13', '16:30:00', null, '通常 / 検定練習', 'はやばやと進め、20分もかからずに1度は終わりました。しかし、動画と見直してみると、ゴーストの消えるまでにタイムラグがありました。時間があったので、そのことは伝えずに動画に見比べて探してもらいました。ルイ君の観察眼もあって、バグは発見できてしまいました。そこからは自力で直して、残り時間はアレンジと自由奔放に遊んでいました。', null, '盛り上がり: スクラッチでガチャ系のモノを遊んで楽しむものいいが、声はほどほどに'),
  ('cc7525ae-fd38-5d17-b8ea-3bd84fad36d7', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-13', '17:30:00', null, '通常 / 検定練習', '途中でおなかをすかせた状態になりましたが、必死に食らいついて、4級の問題は最後まで解き割ることができました。1時間で終わらせたので、もう少しペースを上げれば、合格県内に行けると思います。', null, null),
  ('037b3996-00e9-5abe-ac88-b1b3f370fcb0', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-13', '17:30:00', null, '通常 / 検定練習', '問題には慣れてきたが、細かいミスの多発は今回も起こってしまいました。メッセージのいちが入れ子状態になっていたり、触れなくなるまで待つの所を「ふれるまで」にしていたり、すこーし問題文とのずれが生じています。合格点は行きますが、そこのミスをなくせばよい満点がとれるでしょう', null, null),
  ('d5f8b474-2d3b-5a26-86e8-a04161851bb3', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-13', '17:30:00', null, '振替 / 検定連取', '前回から3級にランクアップして取り組みましたが、2ミス程度で合格はできそうです。「止める」のコードの種類が異なっていたり、「もし」の中の「まで繰り返す」の入れ子が2日省目立ちました。その後は直しは、直す手順を教えて、問題文からみなすことができました。アレンジも自分好み対応できていたので、順調そうです。', null, null),
  ('3c8ab049-1561-5a08-ad88-a61ac3565214', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-13', '17:30:00', null, '通常 / 検定練習', '前回たいよう君が悩んでいたのものを解きました。途中のコスチュームの統合式の流しに鈍器されましたが、自分で作ることができました。ほかのペンや条件式をくむことがあっても、自分での力で組み立て終わり、検定時間内に作り終わりました。うん、余裕そうです。', null, null),
  ('55fddac0-b9fd-5ff9-a8ad-4ee64bb14b67', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-07', '16:30:00', null, '通常 / 細分化をしてコードを考える力をつける', 'チュートリアルは、最初は見ていましたが、見ているだけでそれに合わせて作成することができていませんでした。 隣につくとちょっとやる気になったので、細分化をするような発問をしていくことで、イベントの違いや条件分岐を一緒に考えることができました。 作成しているうちにアレンジのアイディアがわいたようで、シークレットキーでワープと裏世界へいくのを作りたいと言い出したので、キーがおされたときのブロックと座標のブロックの復習、背景の変更を学習しました。 そばにいないとウロウロしがちでしたが、そばで話を聞いてあげると自分でやりたいことを話してくれて、それを作成するための説明は聞こうとする姿勢が見られました。', null, '盛り上がり: 隣にいるときは、それなりに盛り上がってやりたいことを考えたり、形にしようとしたりしていました。自走させようとするとダメでしたが…💦'),
  ('7a7c1f39-f778-5a69-8746-98d7c0ac7f6f', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-07', null, null, '通常 / 検定対策', '「メッセージを送る」と、「メッセージを受け取ったとき」のブロックを混同していたためのバグがありました。そのせいでうまく動かなくてやる気がそがれていたようだったので、それぞれの違いに注意するよう指摘しました。 問題文の中で、現在取り組んでいるところより先の問題番号のスクリプトを止める、という指示があり、まだ存在していないスクリプトを止める、という指示に納得がいかないようで、不満そうでした💦 上記2点以外は、自分で考えて解くことができていました。', null, '時間帯: その他
盛り上がり: うまくいかなかったところは納得できたようですが、問題が変だと思う、と不満を言っていました。それでもできたところをほめると、まんざらでもないようでした。'),
  ('8721003a-9a6b-5d45-85f8-9a90c7606b5e', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2025-11-14', '16:30:00', null, '通常 / オリジナル作品の完成', 'ほぼとなりにいたが、オリジナル迷路のゴール音を入れて完成することができた。 その後は、スクラッチで自由に制作、マインクラフトのゲームをしていた。 自走については、まだこれからの状態と思う。', '彼にあった課題を提供できれば良いが、何に興味を示すかまだはわからなかった。', '盛り上がり: 思っていたより、積極的に色々なことをやっていた、マインクラフトでも諦めずにステージをクリアしていた。'),
  ('25daf85c-ebda-527b-9913-d9b81abb6585', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '7c6bdbc6-3838-5e84-bf07-a26ee6bfe976', '2025-11-14', '16:30:00', null, '通常 / 検定問題 3級練習問題', '3級練習問題を途中で迷うことなく20分で終えられていました。残りの20分はアレンジに取り組み、途中でスプライトが表示されない問題にぶつかっていたが、原因はスプライトを編集したことによって、常に壁に当たっていたことが原因であることを自分で見つけることができていた。', null, '盛り上がり: アレンジは、クローン機能を使って球数を増やし、連射機能を作っていた。そのほかにも、スプライトの中の"サプライズ"という機能を発見し、ガチャゲームが作れそうなど発想を膨らませていた。'),
  ('ee2df98a-4e99-5022-87b8-45ac8870163e', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-14', '17:30:00', null, '通常 / 検定練習', '2級練習問題はスムーズに進められていて、約10分程時間を残していました。検定の途中、隣でタイピング練習(寿司打)をしていた奎歩君に興味を示していました。余った時間でアレンジを勧めましたが、本人が希望しなかったためアレンジには挑戦しませんでした。', null, null),
  ('6c6dd631-45e9-5551-8655-ef4fa8b872c8', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2025-11-14', '17:30:00', null, '通常 / ロブロックスへの取り組みができるか。', 'ロブロックスは一切さわっておらず、スクラッチをいじっていただけで終わった。(前回から作っていたネジのゲームを、断続的に制作していた) ロブロックスについては、つくるのも遊ぶのもあまり興味がないと言っていた。ロブロックスのような3Dのゲームよりは、スクラッチのような平面のゲームの方がいいとのこと。 スクラッチで何かやりたいこと、楽しいことを聞いてもとくにありません。との回答。 もう少し、付き合いを続けないと本音が聞けそうになかった。', null, 'タイピング: 集中してそこそこ長時間やっていた。
盛り上がり: いやいややっていた感じがしたので、ワクワク感はなし。'),
  ('52a4127a-d223-52ce-9749-c56a50cb2e22', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2025-11-14', '16:30:00', null, '通常 / 検定課題', '本番のテスト制限時間の40分を10分ほどオーバーして完成していた。モグラ、ネズミの動作の演算が複雑で苦戦していた。だが答え合わせした際に演算の部分のミスは見られず完璧だった。 モグラの動きのコードに足りないものが一つあった。', null, '盛り上がり: 苦戦しながらも楽しそうに解いていた。'),
  ('2ae9c815-affe-5fb0-b435-ba411351599f', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2025-11-14', '17:30:00', null, '通常 / 検定課題', '以前やったものの復習だったのでスラスラ解けていた。答え合わせもしたがノーミスだった。最初に解いたときは苦戦していたが成長が見られた。 20分以上余ったのでその時間はゲームをしていた。', null, '盛り上がり: ニコニコしていた。'),
  ('33d3956f-3650-5bba-8b01-2530cca439ad', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2025-11-14', '18:40:00', null, '通常 / 検定課題', '僕から声をかけるまでは課題に取り組まなかったが声をかけるとすぐ取り組み始めた。 2分余しで課題をクリアしていた。コスチュームの選択ミスのみでその他は完璧だった 「端に触れたら終了」のコードに少し手こずっていた。 余った時間でもscratchをやっていた。自分でオブジェクトのデザインをしていた。', null, '盛り上がり: 黙々解いていた。わからないところは質問してくれた。'),
  ('f66d4f0c-c201-5548-9a73-98cee80a55a7', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2025-11-14', '18:40:00', null, '通常 / Excel検定対策', 'すこしボーとしている時間があった。疲れている様子。 Excelの日付表記変換、フィルター設定後の使用方法など、テキストからでは理解できていないようだったので、実際の使用方法で説明をし理解が進んだ。', '引き続き、テキストを進める。', '盛り上がり: 少し疲れが見えたが、しっかりとテキストをみながら課題をこなしていた。 わくわく感までは感じなかったが、Excelの便利さを楽しんでいた。'),
  ('1d2dd493-5ddb-5640-9df5-a94d3b8f7163', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, null, '2025-11-14', '18:40:00', null, '休み（振替対象）', null, null, null),
  ('ed1833d8-6b99-5c39-9b80-73825534c5ac', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, null, '2025-11-14', '18:40:00', null, '休み（振替対象）', null, null, null),
  ('4dd3800a-57af-5dcc-88b5-68401f71ad9d', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, null, '2025-11-14', '18:40:00', null, '休み（未対象）', null, null, null),
  ('f0298d4d-1b06-5a5b-ae43-91fc78b5fc50', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-15', '17:30:00', null, '通常 / 検定練習', '前回まではやる気がありましたが、今回かなり難しい問題だったのもあり、早々に諦めてアレンジをしようとしていました。簡単な部分から順にやることを促すと再び手を動かすことができました。難しい場所は一旦飛ばしてでも達成率6割に届けばいいことを伝えました。複数の変数がややこしかったり、慣れない文字列の連結があったりしましたが頑張って読み解いていました。', null, null),
  ('0e58ecac-18ec-5a9c-9882-f146aa1d0d3b', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-14', '18:40:00', null, '通常 / Roblox', '前回の続きで、家の位置や色をアレンジしていたのですが、レッスン動画を見ることを促すとそちらを始めてくれました。 途中、透明度を変えるはずのスクリプトを書いたとき、それが全く動作しないというバグに遭遇しました。TransparencyのTが小文字になっていたので大文字に直すなどして、スクリプトは完璧に直ったはずなのですが、それ以外にも原因があるらしく、分からずじまいでした。', null, null),
  ('98a78168-a4c1-5b7f-9edb-8b1bf8fd3024', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2025-11-15', null, null, '通常 / 検定練習', '最初に前回の答え合せを行ない、待機時間の追加&演算子の間違いの問題文の読み忘れ、違いミスがありました。 その後、一級の問題を見せたところ、難しそうとのことで二級の問題を進めました。', null, '時間帯: その他'),
  ('98c0a917-83d6-540b-8989-705a2874d26c', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-11-15', null, null, '通常 / エクセル模擬試験', '今日は、本番環境を想定しての３級模擬試験３をしてもらいました。途中で、答えを上書きするような箇所があったとのことですが、その上書き処理がうまくいっていなかったとのことで、その部分がごっそりと０点になっていたとのこと。本人曰く、その部分はきちんと溶けていたと思うとのこと。実際の点数は３５位でしたが、ミスで上書きされなかった（上書きされた？）とこが正しく反映されていれば６０点はとれたいたとの自己採点をしていました。いずれにせよ、本番で同様のミスをしたら不合格になってしまうので、その点気をつけつつ、次回以降も模擬問題をしていけたら良いかとおもいます。', null, '時間帯: その他'),
  ('9eea4dd7-1b28-539b-9e7f-ba50a3f13fed', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2025-11-15', null, null, '通常 / 試験練習', '試験練習中、やすのり君と遊んでしまい、集中が切れる場面が多々ありましたが、最後まで終らせることができました。 "もし~なら"ブロックの後に動作を追加するところを、"でなければ"のブロックに設置してしまう、問題文とは違う方法で実装してしまうミスがありましたが、それ以外は完璧に実装できていました。 アレンジとして、敵の数を一つ増やすアレンジを追加していました。 バイクランのランキングに入りたがっていたようです。', null, '時間帯: その他
盛り上がり: 試験練習後、算数が得意とのことで、学校の授業時間外にフラッシュ暗算ゲームを作成し、なかなか良い出来だったとうれしそうでした。'),
  ('e55d586a-656b-5643-8955-8350094483a9', '31feac25-f850-5d21-8e43-ed4d7badb6a0', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-11-15', null, null, '通常 / 検定対策', 'だいぶ検定問題にも慣れてきたようで、集中できていました。問題文で、一つだけ（「タイムは○○秒だよ」の表現の仕方）悩んでいたところがあったものの、それ以外は、スムーズに、アレンジも含めて制限時間内に完了させていました。答え合わせしても、悩んでいた一つの部分以外は、大丈夫でしたが、一つ気になったのが、アレンジの仕方が、問題文で示されていた内容（例えば、XX < 30）と回答しなくちゃいけない問題のところを、（難易度を上げるという意味合いで）アレンジして(XX < 15)というように変更している箇所が、何箇所かありました。この時点で、私自信このようなアレンジで減点されるか、わからなかったのですが、このようなケースだと減点されるっぽいので、設問の答えを変えるようなアレンジをしないように、次回検定問題の前に説明した上でスタートするようお願いします。', null, '時間帯: その他'),
  ('1738ef9b-3f7f-52c7-8662-bc1f62d90e9d', '40a476bc-72a5-5bdc-ab75-e89d5310b442', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-11-15', null, null, '通常 / 検定対策', '今日も、検定問題に挑戦しながら、問題文を声に出して読んだりし、鼻歌を歌いながらながら進めていました。様子見はしていますが、いつもこうなので、若干、この点気になるところです。 検定の中身としては、これまで、ことあるごとに問題文に書かれている通りに回答することを伝えていることもあり、勝手に同じような動きをする違うブロックを選ぶことはほとんどなくなってきたと感じます。ただ、今日は、３箇所くらい、問題文の読み飛ばしが発生していました。３箇所だけなので、６０％の正解率は超えるかなとは思いますが、次回以降は、鉛筆で終わったところをチェック入れながら進めることをお勧めしました。', null, '時間帯: その他'),
  ('19e15c15-2cd7-5657-9154-fa53d6b5e027', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-11-15', null, null, '通常 / 検定対策', '全力集中という感じではなく、時々、ユウトくんと話をしながら進めていましたが、制限時間内には終わっていました。 これまで何回も、問題文をじっくり読んで進めることを伝えた成果だと思いますが、簡単なミスはだいぶなくなってきました。今日は、問題文の読み間違えが１箇所あったくらいで、それ以外は全部問題なしでした。３級は大丈夫そうな感じだと思います。', null, '時間帯: その他'),
  ('177ac456-5fba-58af-8e1e-5f8f3f27c28c', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-15', null, null, '通常 / 検定練習', '自信がなくて検定受検を躊躇しているとのことだったので、以下の選択肢のうちやりやすい方を選んでもらいました。 a.前回解いた検定１級応用課題１を答え合わせする→1級に挑戦できそうか判断する→もう一問やってみる b.答え合わせは一旦飛ばし、次の問題に本番に近い形式で取り組む→1級に挑戦できそうか判断する 本人は後者を選びました。最初は手を動かしていましたが、ブロック定義などの難所でつまづいて気持ちが落ちてしまい、最終的には半分くらいしか終われませんでした。 したがって、今回の受検は取りやめ、来年春に再チャレンジすることにしました。その際に、一度答え合わせして終わるのではなくじっくりと復習をする方針を取ることで土台を固めたいという話をしました。', null, '時間帯: その他'),
  ('2859de45-5f80-583a-90aa-426d3f968249', '82396ac6-71bd-59d4-a372-57212866fd5d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-15', null, null, '通常 / 検定練習', '前回までの傾向を基に、「バグがあったときはコードだけを見ずに問題文と照らし合わせよう」と伝えて始めました。今回も実際にバグが起こり、原因が分からないと言っていたので、文章を読みながら確かめていきました。「旗が押されたとき」と「～を受け取ったとき」を同じスクリプトにまとめてしまっていたことが原因でした。それが解消した後は、ドラゴンを追加してコスチュームを変えるアレンジに夢中になっていました。', null, '時間帯: その他'),
  ('361aebd5-4ff1-59b2-95aa-57e2c5eb340d', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-15', null, null, '通常 / 検定練習', '今までよりもスムーズに解けるようになっていました。間違えていたところは少しあり、「②(繰り返し処理)のあと、以下を行う」のところを繰り返しの中に入れてしまっていました。その間違いが2か所あったのですが、2個目は自分で気づくことができました。それ以外のミスは、メッセージの名前間違いくらいでした。その修正が終わってゲームがきちんと動くようになると喜んで、何回か遊んでいました。', null, '時間帯: その他'),
  ('2906ef34-58f6-52eb-8d9c-2518dee3a360', '80660755-d846-5cdd-91a4-0ab78fe29034', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-15', null, null, '通常 / 検定練習', '2級の中でレベル高めの問題でしたが、集中して最後までたどりつけました。間違えたポイントは以下でした。 *今まで多数出てきた「りんごとバナナ」の変則的な使いかた(本質はこれまでと同じと伝えました) *変数の値を「空欄」にすべきところを「0」にしていた(→文字列で「何もない」を表すには空欄にすることを伝えました) それ以外は、複雑な文章のところも丁寧に読み解き正確に作れていました。', null, '時間帯: その他'),
  ('08399f45-7e58-5291-99a7-5e7052e72281', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-15', null, null, '通常 / 検定練習', '最後まで一通り終えるところまでは時間に余裕を持ってできましたが、ジャンプできないというバグが一つだけ直らないと言っていたので答え合わせをしました。バグの原因は以下でした。 *「自分で一から作るスクリプト」と「問題文に沿って修正する用に用意されていたスクリプト」をまとめてしまっていた →問題の構造を説明して、二つを区別してもらいました。 *色で判定するとき、スポイトで取ったにも関わらず色の値が若干ズレていた(スクラッチ側のバグ？) →どうしようもないので正解扱いにしました 原因がわかってすっきりして終われたようでした。', null, '時間帯: その他'),
  ('c20c72dc-dca5-55fc-8fec-941785f4f9bd', '2758b49a-c2b1-5cd0-9b37-3b988f2a5a09', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-11-15', null, null, '通常 / 最初のレッスン・スクラッチに慣れる', 'ほとんどスクラッチに触ったことがないとのことで、基本操作コース２から。一つひとつ説明するたびに、「はい」とか「わかりました」とか丁寧な反応が返ってきて、真面目な性格をうかがえました。ブロックについて、文字の操作、色変え、動かす、回転させる、大きさを変える等も、スムーズに理解していました。最後に、X、Y座標を設定するブロックを扱うので、X座標、Y座標の概念、それとマイナスについての概念もしっかり理解してもらえたと思います。全般的にしっかりした子で取り組む姿勢も、飲み込みも良い感じでした。 今日は、名前を動かそうということで、最後に、I,T,Oの文字を自由に動かしたり、大きさが拡大縮小したり、回転したりするようなアニメーションのようなものを作ってもらい終了となりました。', null, '時間帯: その他
タイピング: ココアタイピングも、プレイグラムをやったことがあるとのこと。タイピングはそこそこできることを確認できました。'),
  ('762ed184-aea6-5024-83ad-c5f9e0be6ec0', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-11-15', null, null, '通常 / ロブロックス', '前回、アスレチックで冒険（後編）の説明が全然わからなかったとのことで、動画ではなく、テキストを開いて、少しずつ読み進めながら、どこがわからないかを教えてもらい。Humanoidのオブジェクトをどうやって取得するかがわからないとのこと。これは、火のオブジェクトに触れてしまったら、キャラクターの体力を０にして死亡させる処理の部分。複数の複雑な処理（接触判定のイベント処理、接触判定された後に走るプログラム内の処理）がほぼ同時に走るので理解が難しいところ。細分化して教えましたが、本人はスマホ見ながら片手間に聞いてる感じで、正直理解できていないんだろうなと感じました（最終的には、真面目に聞いてもらって理解したかもと言ってたけど）。この辺の複雑な処理を完璧に理解するのは、小中学生では、かなり真剣に取り組みたい人で、それなりに飲み込みの早い子じゃないと無理な気がします。なので、最初は、「接触イベントはこのようにプログラムで書く」と、丸暗記して、突き進んでもらうしかないかと思いました。多少のモヤモヤはあると思うけど、それで進めるしかないかな、、、。（英会話の勉強もよくそんなことあったので似てるかも） あと、動画より、テキストの方がわかりやすいとのことだったので、テキストを印刷して用意してもらえると助かります。', null, '時間帯: その他'),
  ('8ce05ba2-1fae-56d5-be44-e7b94e5c5e39', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-17', '16:30:00', null, '通常 / 検定練習', '最後の検定練習でしたが、「まで繰り返す」や「せりふが消える」といった表現にまだ迷いがあるようです。「せりふが消える」のコードは、以前も同じようなことがあったので、教えたような気がしたが、忘れていました。「とめる」の種類がわからない場合には、どれか自分で試す習慣がついてよかったです。30分の時間では8割ほどで来ていたので、合格はできそうです。', null, null),
  ('d721580a-5cad-5a7c-a013-1745ec13c08a', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-17', '16:30:00', null, '通常 / 検定練習', 'まで繰り返す」の認識が勇作君と比べて、少し迷いが多いです。時間をかければ、気づくのですが、そこスムーズにできてほしいです。ほかはスムーズにできていました。途中、「そうでないとき」の表現わからなくて、自然と読み飛ばして、飛ばしたことを忘れてしまうことがありました。本番では、わからならなくても飛ばすのはいいが、忘れてしまうのはいけないので、最後に伝達しておきました。', null, null),
  ('10a06b7e-d681-5044-bd10-91f22ad7fb37', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-17', '16:30:00', null, '通常', '今回もやる気のモチベがたかったです。基本的は順調に進んでいました。岳君と同様ですが、わからないところをそのままにして、飛ばしたことを忘れて完成だと思い込んでしまうことがありました。せりふを消す」を放置していたみたいで、完成後の見直して何度も悩ませていたそうです。時間も比較的余裕があったので、合格はできそうです。', null, null),
  ('87a93a4c-348c-5787-902e-8c5b7ca51f2d', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-17', '17:30:00', null, '通常 / 検定練習', '繰り返しの範囲に悩まさせらる問題でした。最初の座標に位置決めのランダムの繰り返しが下までくくってあり、何が間違えからわからない状態でした。ヒントを少しずつ加えてもわからなそうだったので、解答のコードを見せて、「この文章の表現だとこうなる」問題文と対応させながら直していきました。そのほかの部分は、おおむねできていたので大丈夫です。最後に、「繰り返し」の範囲に気を付けるようアドバイスをしました。', null, null),
  ('c98a95b1-b829-528d-9aa5-f9d76fd66232', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-17', '16:30:00', null, '通常 / ロブロックス', '最近の態度が非常に悪いです。動画見ればよいと言葉を短絡的に受け取って、ステージの1の最初のわかっている部分を繰り返し見たり、ロブロックススタジオの方には、ただ開いてあるだけで作業はほぼ皆無です。それ以外の時間は、ロブロックスで遊んでいます。「あそぶなら、家でやれば？」とこちらから言うと、「厳しくてできない」と返されそのまま遊ぶ。教室だってお金もらってきているのもったいないと心の中で踏みとどまるました。 あまりにもやる気がないので、今日は12月の予定をあらかじめ一緒に立てました。レッツショッピング前半を終わらすとこちらが理解をできたとわかるまでと決めました。はたしてこの約束は守られるのでしょうか？', null, null),
  ('66dc267a-e6ec-597d-aa0c-abe304228310', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-18', '16:30:00', null, '通常 / 検定対策', '今日は検定前日のため、やらなきゃいけないという気持ちでは来てくれたようで、授業開始後すぐに検定をやろうとする姿勢は見せてくれました。 ただ、長続きしないというか、検定対策をしなくてはいけないのはわかっているけれど、文章を読んで地道にやっていくのが面倒で仕方がなくて、そのストレスがひどかったのか…とにかく動作が乱暴になったり、体をゆすったり、潜っていったりという態度はひどかったです。あまりにもつらそうにやっているので、一周まわって気の毒になってしまいました💦 本番がきちんとやれるなら、できそうなところは今日は飛ばして、難しそうなところだけやってもよいというと、わからないところを指してきたりもするので、一応内容はわかっている様子なのですが、口では「ぜんぶわかんない！」と駄々をこねるように言いつのったりもしていました。それでも手はちゃんと動いたりするのがちょっと謎というか、きっとわかっていないわけではないのだろうな、という感じです。 本人が落ち着いて問題さえ読めるようなら、今のレベルで対応できそうなのですが、如何せん、本人の忍耐力がどこまで持つか、といったところです。', null, '盛り上がり: 非常に珍しく、時間いっぱい机に向かって問題に取り組んでいました。その分ストレスもすごかったようですが💦'),
  ('fa827c4d-ae33-580a-8f0a-7bd5207e661c', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, null, '2025-11-18', '17:30:00', null, '休み（未対象）', null, null, '備考: インフルエンザのため、当日欠席連絡'),
  ('23456984-f8aa-50d8-a4c2-ab2a37ba75e0', '1c7005cc-2815-558f-993a-9c7617d34c44', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2025-11-18', '16:30:00', null, '通常 / 細分化してコードを考える', '紙に書きながらコードを分解して一つずつ作っていくとすんなり理解した様子だった。答えを知りたがっていたがなるべく一緒に考えるようにしてコードを組み立ていった。だるまさんが転んだ自体はうまく動作するところまでいった。「だるまさんがころんだ」の読み上げスピードをランダム化するのと、アルくんが歩いている時のコスチューム変更を終わらせればほぼ完成だと思う。', null, '盛り上がり: 一つひとつのコードが完成した時に「いいね！」と声をかけてあげると、本人もニコニコして楽しそうに勉強できていた。'),
  ('ee818cf9-d983-50cd-9a8e-2bdde06cd400', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, null, '2025-11-18', '17:30:00', null, '休み（未対象）', null, null, '備考: 振替の予定日でしたが、忘れてしまったそうです。'),
  ('0b1b8684-f399-52e7-9a76-f1b18d2c8bb1', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-18', '17:30:00', null, '通常 / 検定対策', '一級応用問題2を行いました。30分くらいで完成していて特に詰まっている様子もありませんでした。難しいジャンプの動作も問題なく動いていました。アレンジにも余裕を持って取り組めていたので本番もその調子で頑張って欲しいです。', null, null),
  ('f6034f62-0bda-55cb-88cb-c75027e9050a', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-14', '17:30:00', null, '通常 / Excel', '検定に向けて集中力を高めながら取り組んでいました。とてもスムーズにいくつもの課題を終わらせていました。', null, null),
  ('9fe9a619-d050-52ff-ba5a-e3bb053fc842', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-13', '16:30:00', null, '通常 / 検定対策', 'ちょっと行き詰るとすぐにつっぷして、もうやだーとなっていましたが、なんだかんだ言いながらも、できるところはやろうとしていました。 入力で時間をとられて先生を呼んでばかりだったので、実際はあらかじめ文字が入力されていることを説明しました。とにかくわかるところだけでもあきらめずに埋めていけば得点になることを説明し、なんとか課題を終えさせました。', null, null),
  ('96c3b857-9c1e-530e-8a1c-c7d780cae23b', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-13', '16:30:00', null, '通常 / 検定対策', '問題文の日本語をそのまま探そうとして、「左右のみしか向かないようにする」と「回転方法を左右のみにする」には「向かない」が入っていない、と言って「この問題はわからない」となるパターンがいくつかありました。問題文をきちんと読むことは大事ですが、言い回しが一言一句一致しているわけではないこと、虎太朗くんが知らないブロックはまず出題されないので、問題文からどういう動きを作ればよいのかを読み取ってほしいことを伝えました。セリフが消える、は初出なので教えました。 条件分岐のあとに入れるべきブロックを中に入れていたため、魚がうまく動かなかったので、問題文と照らし合わせながら説明しましたが、「先生すごいね！」と他人事のように感心するばかりで、きちんと理解したかは不明です。', null, null),
  ('1fee1f2c-92b1-521b-bcd7-521dd203827a', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-20', '16:30:00', null, '通常 / ご褒美ゲーム', '昨日が検定だったので、今日はお遊びゲームでした。ルイ君がアスレチックがご希望だったので、遊びになりました。最初は全然うまくいかず、ほかのゲームに目移りになりがちでしたが、集中していくと、うまくいき教室内で1番初めにクリアができました。そのごも何度もチャレンジをしようとしていたが、ルイ君たちに記録を更新されてしまったので、コスチュームのなどを変えてアレンジを楽しんでいました。', null, null),
  ('147f89cf-7434-5ce5-a722-e7535d1fbd1f', '05439956-11b9-5ac7-a44a-3e6f5a6831d8', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-13', '16:30:00', null, '通常 / 検定対策', 'アルスタジオ/検定1級応用課題2', null, '盛り上がり: まったく問題なく、30分もかからないで解き終えていました。アレンジをどこまでしていいのか聞いてきたので（スクリプトの削除はありか？など）、できているコードは残しておいて、自分が説明できる範囲でアレンジをするよう伝えました。余裕があるので100点合格を目指すそうです。問題を1題持ち帰りました。'),
  ('6b346315-ee7e-5222-a3d9-af4d7815c477', '512b2f12-24bc-5afa-913a-d68b4a9f9e14', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-13', '16:30:00', null, '通常 / Excelのグラフを学ぶ', '表の作成は自信がついたようでした。 新しい課題として、折れ線グラフと棒グラフを作成しました。 データ系列と個別データの選択の仕方を学習しました。 入力のさいのタブキーでの移動やシートのコピーなども、興味深そうに実践してくれました。 家でも少しいじってきたいとのことで、意欲もしっかりありました！', null, '盛り上がり: 好きなキャラクターにちなんだグラフの色などを選んで楽しそうでした。'),
  ('3304b367-9a6d-587f-bc41-3694b708870c', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-20', '17:30:00', null, '通常 / ご褒美ゲーム', 'アスレチックゲームで遊んでいきました。ジャンプ系のゲームを苦手だったので、開始30分たってもなかなか細い足場のところがクリアできませんでした。そこで、こちらからジャンプの高さを変えるアレンジを提案しました。そしたら、苦戦しているときよりも楽しくゲームに集中できました。そこから足場を階段状にならべ、らくーに上がれるようになって楽しく終われました。', null, null),
  ('5e5a50cf-fc53-56e2-b5e0-937a1a028c62', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-20', '17:30:00', null, '通常 / ご褒美ゲーム', '最初からルートのショートカットを見つけ、落ちるたびにリセットを繰り返し、うまくいったときには、43秒とかなりの好タイムで遊んでいました。そこからアレンジを進めてみましたが、そこまでの気分だったので、scratchのゲームで遊んでいました。最後の承太郎君の挑戦を除くと、42秒と1秒速くクリアしてしまったため悔しがって帰りました。', null, null),
  ('2ff2d0aa-cce5-5a72-bbe5-89f2c4935b82', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-20', '16:30:00', null, '通常 / ご褒美ゲームとアレンジ', '検定が終わったご褒美回で、まずは記録を狙ってみんなで遊びました。ゲームクリアまで時間はかかったものの粘り、最終的にランキング暫定1位のタイムでゴールして喜んでいました。アレンジとしてエレベーターのようなものをつけたいと思いつき、フリー素材を探していました。「この色に触れたら上にワープ」などしっかり考えながらアレンジできました。', null, null),
  ('a614908a-9c7c-5998-b2f8-912822704dbb', '57f45872-1f3e-5540-b676-bf9023444e39', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-20', '16:30:00', null, '通常 / ご褒美ゲームとアレンジ', '検定が終わったご褒美回で、まずは記録を狙ってみんなで遊びました。いい記録を出した先生に「大人げない」と言いつつ、負けじとやっていました。 その後のアレンジとしては、棒人間を野球ボールに変えていました。「ボールを回転させたいね」と誘導し、本人はわからないと言っていましたが、るいくんが助け舟を出して「角度を変えればいいんじゃない」と教えてくれていました。また、ゴールの旗の位置を近づけるアレンジもして、非公式記録(?)を更新しまくって遊んでいました。 検定が終わってテンションが上がったのもあったのか、これ見よがしにゲップをし続けてふざけていたので、「人の前ではマナー違反だよ」とは伝えました...', null, null),
  ('6647928f-d0a3-50d2-b6ee-562aa2f8d725', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-20', '17:30:00', null, '通常 / 検定練習', '計算式を日本語で書いた部分を難しそうにしていましたが、結局だいたいは自分でできていました。演算ブロックを組み合わせる順番が少し違っていただけで、ブロックの種類自体は正しく選べていました。残りの詰まったポイントは、 *「～と聞いて待つ」の「答え」が問題文に変数として書かれていたところで、「これは変数なの？」と困惑していた *算数で「切り捨て」を習っていたが、同じ意味の「切り下げ」という言葉を知らなかった 程度でした。特殊な問題に慣れることができたと思います。難しかった割にきちんとできていたので、自信を持って本番に臨んでほしいと伝えました。', null, null),
  ('27262191-04b2-5f21-95a6-90db5d193117', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2025-11-21', '18:40:00', null, '振替 / EXCEL', 'あまり模擬試験進められていない感じでした。 次のページの問題文に詳細な説明があったのですが、ひとつ前の問題文とにらめっこしてしまっていたように思います。 途中で試験終了してしまい、採点するも得点が表示されませんでした(進めてなかったからかも？)', null, '盛り上がり: 模擬試験後、棒人間アスレチックでバグを見付けて遊んでいました。'),
  ('4eb2b9b5-43c7-5e92-b036-f606359b3fae', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2025-11-21', '17:30:00', null, '通常 / 検定対策', '検定練習の採点から対応しました。 おそらく初めての3級問題？でしたが、完璧に実装できていました。', null, '盛り上がり: 検定練習後、お迎えが来るまで他の作品で遊んでいました。'),
  ('166f5a9f-889a-5b97-be84-197b0201bd95', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-11-21', '16:30:00', null, '通常 / 検定終了の息抜きゲーム', '検定終了したこともあり、棒人間アスレチックを遊ぶことからスタートしました。最初は、ゴールまで全然いけなくて、難しいと言っていましたが、マップの大きさを小さくして表示させて、どのルートを通ればいいかを考えて挑戦するようになってからゴールできるようになり、徐々にタイムを縮んで行って、この時点でのトップタイムを取れるようになりました。最後にちょっとしたアレンジを楽しんで終了しました。', null, null),
  ('8e27c729-40cc-5f82-a24e-263ea02d0082', '31feac25-f850-5d21-8e43-ed4d7badb6a0', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-11-21', '16:30:00', null, '振替 / 検定対策', '２０分くらいで検定問題を解き終わったが、いざ動きを確認してみると、ゴーストの動きがおかしくて、それが直せなくて１０分くらい悩んでいました。最終的には、ヒントを与えることで修正できました。答え合わせの結果は、「ずっと」を入れ忘れた箇所が一つのみ。単なる問題文の読み飛ばしというケアレスミスでした。また、最後に悩んでいたかしょも、ヒントを与えたため、正解はできましたが、問題文を細かく読めば、わかるようなところでした（○○の後に、AとBを順番に実施）のところを、Aだけ実施して、Bの処理は、◯◯のブロックの外に置いてしまっていました。これら全部間違っていたとしてもしても合格圏内ですが、もう少し丁寧に問題文を読み込むようにできれば、ほぼパーフェクトになるのに、惜しいなあというのが続いている気がします。', null, null),
  ('a72d9f22-e210-5c55-91e6-e0b00a1bdb0f', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-21', '16:30:00', null, '通常 / 座標の変化など', '前半はいつもより集中してくれました。レッスン1までだとアル君の動きがぎこちない(「矢印キーが押されたとき」のイベントを使用)ことを気にしていたので、それを滑らかな動きにするレッスン2(「もし矢印キーが押されたなら」を使用)に上手く誘導できました。しばらく、動画を見ながらきちんと取り組んでくれました。最後まで行きませんでしたが、授業後半は、みんなで棒人間アスレチックのタイムを競い合って遊んでいました。', null, null),
  ('aee61a28-2866-5173-bc9e-15fec7c7b841', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-21', '16:30:00', null, '通常 / 検定練習', '文字列を連結する応用の部分が難しかったですが、「数字の計算でなく文字としてくっつける」というイメージを伝えると、今まで使っていた「りんごとばなな」が使えることを察することができました。他の部分は自力でこなせていました。途中、りょうまくんが遊んでいた棒人間アスレチックが気になっていたようですが、検定練習が終わったらそれで遊ぶと約束し、モチベーション高く取り組めました。', null, null),
  ('904bfe46-ea58-5474-bde8-ec97cbe28b52', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-21', '17:30:00', null, '通常 / 検定練習', '前回解いた問題が途中で終わってしまったとのことだったので続きに取り組みました。難しい場所で止まってしまい、一緒に解こうとして重要ポイントを説明してみましたが、よく理解できないという状態で変わりませんでした。そこで、そのパートは諦めて簡単なところを確実に取る方針にすると再び手を動かしてくれました。やったところは正解できていたので自信を持ってもらいました。', null, null),
  ('f3829e86-02f9-5a1a-9bf3-81826682ecb4', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-21', '17:30:00', null, '通常 / 検定練習', '演算が難しめの問題をやりました。複雑な数式部分で戸惑っていましたが、本番を見据えて、一旦飛ばして最後までやることを促しました。そこだけで時間使い果たすのはもったいないという考え方を伝えました。答え合わせをすると、掛け算と足し算を組み合わせる順番を間違えていました。「掛け算と足し算はどっちが先だった？」と、算数を思い出してもらうとコツがつかめたようで上手くいきました。それ以外は概ねできていたので自信を持って送り出しました。', null, null),
  ('d32f0f05-21e0-50c9-aeb6-6189fa6eead6', '10db50c3-a153-502a-b455-c67362b9871c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-21', '17:30:00', null, '通常 / 検定練習', 'いつも通り解いていましたが、バグが出たことを途中で先生に報告していました。自力でやらないといけない本番を見据えて、いったん最後まで行ってからバグの原因を探すように促しました。そうしてもらったあと、答え合わせをするとミスは以下のようなものでした。 *「送って待つ」とすべきところを「送る」としていた *文字列の「～が～に含まれる」とリストの「～が～に含まれる」を混同していた 自分の間違いやすい部分を理解できたようでした。', null, null),
  ('6608ac49-067b-50e5-b038-291d99e74917', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-21', '18:40:00', null, '通常 / 検定練習', '検定にもだいぶ慣れてきて、速く解き終わって喜んでいました。アレンジとその説明を書く練習をしてもらっても制限時間に収まるくらいでした。結果も、「他のスクリプトを止める」など含めてほとんど完璧にできていました。残り時間は好きな絵を描いていました。', null, null),
  ('15d6cbef-e112-5ddc-8758-89c691a0e4cb', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-11-21', '18:40:00', null, '振替 / ご褒美ゲームとアレンジ', '検定が終わったご褒美回で、棒人間アスレチックを遊んでもらいました。たつきくんなどとショートカットルートを共有し、みんなで最速記録を更新し続けていました。アレンジとしては、マップの中からゴールフラッグを探して色を紫に変え、色判定もそれに合わせるなどしていました。', null, null),
  ('e9538f33-e536-5ce7-9415-f5ba800a84a1', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-11-21', '17:30:00', null, '通常 / ロブロックス', '最近、ロブロックススタジオに興味をなくしていたようだったので、その辺どんな感じなのか聞いてみましたが、なんとなくですが、Roblox Studioに楽しみを見出せなくてスクラッチの方が楽しいという漠然とした回答しか得られませんでした。で、もっとステージが進めば難しいことを覚えて楽しいものが作れるようになること、Roblox studioの知識は、Unityとかのゲームエンジンを使うための橋渡しにもなることを伝えると、ちょっと興味は持ったようでしたが、内心はよくわかりません。でも、今日は久しぶりにRoblox Studioをしてくれました。久しぶりなのでリハビリがてら何かオリジナル作品を作りたいということで、長方形のスタジアムみたいなのを作って、四方から大量のボールが転がって落ちてきて、スタジアムの中にいるプレイヤーがそれをよけるゲームを作っていました。そして、ボールに当たったら、プレイヤーが死亡するような方法を教えてくれと言われたので、ステージ２の２つ目の動画で説明されている、接触イベントと、プレイヤーの体力を０にする方法を教えました。おそらく細かく丁寧に教えれば、理解はできると思います。が、Robloxに関する興味がどれくらい継続するか未知数ですね。', null, null),
  ('9a797ae8-31e8-55c1-ba12-2eb6a527cac5', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-11-21', '17:30:00', null, '通常 / U16大会作品', 'U16入選という事で、今日はU16作品のブラッシュアップをしたいということで、レッスン中は、集中して取り組んでいました。エクセルの事も気にはなっていたようですが、今日は、U16作品を進めることにしました。', null, null),
  ('eb9b3db3-8485-54cf-a372-1dc7b9095ca8', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-11-21', null, null, '通常 / Roblox→棒人間', '今日はロブロックスの日だったのですが、本人はエクセルを進める気でいたようです。ただ、今日はロブロックスの日であることを伝えると、ちょっと考えて、今日はロブロックスをやると言ってくれました。が、その後に、みんなと競い合う棒人間をやってみたいとのことで、それを始めたらとまらくなくなってしまい、レッスン中はほぼそれで終了してしまいました。ただ、集中力はすごくて、最短ルートを開拓して、２０秒ほどというトップの記録を叩き出していました。今後は、エクセル検定のためにエクセルのみに集中か、ロブロックスも進めるか、相談させてください。', null, '時間帯: その他'),
  ('56b26f43-d058-5d76-81a4-4ef5eaf03a38', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-11-21', null, null, '通常 / 棒人間アスレチック', '棒人間アスレチックのゲームクリア、最短ルート探索、アレンジ等しました。同じ時間の子たちと最短ルートを共有したらしく、ものすごい記録を叩き出していました（瑞君には負けてしまいましたが）。一通り遊んでからは、ジャンプ力を高めたり、ゴールの位置を変えて難しくしたり、楽しそうにアレンジに集中していて、帰り時間になっても、もう少しもう少しと続けていました。', null, '時間帯: その他'),
  ('dc5de9aa-5d46-5aa2-9116-a0d698501ba8', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-11-22', null, null, '通常 / ロブロックスの続き', '検定を受けないとのことで、今日はロブロックスの続き。レッスン的には、ハラハラピンボールはもう十分に終わっていいくらい時間はかかっているのですが、すごい凝ったものを作っていて、なかなか終わらないようです。裏を返すと、急いでどんどん前に進もうという意識ではなく、とても丁寧に自分の作りたいもの、見た目の良いものを時間をかけてを作っている感じです。そのぶん、飽きているとかはなくて、集中して取り組んでいるようではあります。次回で、ハラハラピンボールは完成になると思います。', null, '時間帯: その他'),
  ('65ad345e-e3f1-5445-a6b3-4d0dccc3141d', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-11-22', null, null, '通常 / ロブロックスの続き', 'スクリプトを使って、物体の座標を変数を使って動かす処理が、この章のキモとなると思うのだけど、その部分は、問題なくきちんと理解できて、終わらせることができました。確認テストも１００％で終わらせることができました。ただ、だんだん難しくなってきた？とチラッと聞いてみたら、「うん、ちょっとそうかも」みたいに返事が返ってきたので、そろそろしっかりと理解度確認をしながら進めていきたいと思います（モヤモヤしてるのにわかったという事もたまにあるので、聞き方を考えて対応します）', null, '時間帯: その他'),
  ('86c2c57a-6027-52df-8858-5c901cb15567', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-11-22', null, null, '通常 / エクセル模擬問題', '前回に続き模擬問題を実施。４３％という結果でした。印刷のところで、問題が固まってしまったとかで、時間が無駄に経過してしまい、その部分、もし普通に回答できれば、正解できていたかもしれないとのこと。次回は、模擬問題４で解けなかったグラフ部分のところ（３０時間６章のどこか）と、RANK.EQ(8章)のとこを復習した上で、別の模擬問題に挑戦してもらえたらと思います。', null, '時間帯: その他'),
  ('b1c37975-8f81-523a-b750-d3e8d816b179', '2758b49a-c2b1-5cd0-9b37-3b988f2a5a09', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-22', null, null, '通常 / メッセージとセリフの使い方を覚えよう', '最初に、前回の名前を動かすの復習から行いました。動かすとかxy座標のの確認、色や大きさのコードの確認を行いましたが、悩む時間もなく覚えていて教えてくれました。 今回の作品では海を舞台に選んでくれました。セリフのブロックとメッセージの機能を教えてあげると、セリフは場所を覚えてすぐに使いこなせれるようになりました。「メッセージ」については、最初は「受け取る」と「送る」の混同はありました。そして、メッセージの名前を変更し間違えることもあり、フォローをしてあげました。それに伴って、物語のセリフの展開などのアイデア出しに少し苦労している点がありましたが、コードの使い方が身に染みてくると、アイデアの方も自分から出てくるようになり、楽しんで作っていました。海の中で、出会って遊ぶ作品が完成しました。最後に、アレンジとして、泳ぎまわる動きのアレンジを加えて、前回使用した「何歩動かす」や「ずっと」で表現できていました。「動いているときもセリフを言いたい」と要望があったので、その付け方を教えて、完成できました。', null, '時間帯: その他
タイピング: キーボードを見ながらも素早くできていました。一文字だけでなく単語の時もよくできていたので、タイピング能力がありそうです。
盛り上がり: 今度誕生日プレゼントでPCを買ってもらうそうです'),
  ('97d44fd7-c19a-524d-bf39-538ffa1a2024', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-11-22', '16:30:00', null, '通常 / ロブロックス', '一時間早く来たが、結局1時間半も遊んでいしまいました。こうしろうくんが横から見ていることもあって、それで調子乗ってだらだらと続いてしまう様子が見られます。そこから始めると、前回紙で見た方が進めやすいと本人から要望があったので、プリントして進めました。けど、動画のチャプター的には1つ程度しか進まず、火でダメージが与えられるようになったくらいです。ontouchからhumanoidの機能がたくさん出てくるので、情報量が多いでしょう。い時間遊んで1時間やると最初に意気込んでいたのは何だったのでしょうか??', 'つづき', null),
  ('ae83306d-842a-5077-992b-4865eb29d334', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, 'f7b1b888-88b7-5b1d-9bee-05201726d587', '2025-11-22', null, null, '通常 / 検定練習', '前回に引き続き2級の応用課題の5をして最後まで終わらせた 前回直せていなかったバグを修正した ・セリフの入力ミス「成功だ！」を「正解」にしていた ・変数名の指定ミス「番号3」を「たおした順」にしていた ・条件の確認不足(((番号3=番号1) ではない) かつ ((番号3=番号2) ではない))という答えの場所を(((番号3=番号1) かつ (番号3=番号2)) ではない)にしてしまっていた バグの原因は全てのバグに共通して問題文を読み足りていないこと アレンジにも集中して取り組んでいた。 アレンジ内容：制限時間、爆弾を追加することで失敗する要素を増やし、さらに難しさを上げていた。2級の応用課題5が終わったので2級は全て終了。', null, '時間帯: その他'),
  ('58e119de-6600-5f05-a22d-18fe9aa25df5', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2025-11-22', null, null, '通常 / 定4級①', '検定4級は全て取り組み済みだったため、復習として4級①に取り組んだ。 問題文の中で理解できない部分が多くあったようで、「a,bの順に動作する」や「〇〇のあとに」などの条件をほとんど見落としてしまっていた。 繰り返しブロックのミスについてはヒントを出したところ、自分で間違いに気づき解決することができたものの、「〇〇のあとに」という条件についてはかなり誘導したが、なぜそうなるのかあまり理解している様子では無かった。 アレンジにも挑戦したが、アイデアを書き出すことはできたものの、実際に作成することはできなかった。 検定4級①は一度取り組んだことのある問題であったが、定着が十分でないと感じることから、新しい事をするよりも基礎を固める時間があると良いと考える。', null, '時間帯: その他'),
  ('b08456d4-22f1-579b-804f-2b8de5c2926b', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2025-11-22', null, null, '通常 / 検定対策', '２級問題は全て終わっていたため、これまでの復習と1級①のどちらをやりたいか聞いたところ、1級①に自信をもって挑戦していた。途中、泰徳君のゲームに気を惹かれていた部分もあったが、一通り時間内で終わらせることができていた。バグの修正までは行うことができなかったが、全体的に動作する段階まではできていたことと、1級という問題のレベルを考えると十分だと感じた。途中脱線することはあったが、自分から検定問題に戻る事が出来ていたのは良かった。', null, '時間帯: その他'),
  ('d24cf2e7-6c7a-5e6d-8dd7-6e9b23480f8a', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2025-11-22', null, null, '通常 / 検定対策', '検定課題をやりながら、途中途中でゲームをしていた。あと少しで検定問題が終わると言っていたので、課題を動かして見せてもらった。魚釣りのゲームだが、魚の動きが課題どおりでなかった。全体的にはできていたが、魚の動きの修正が終わらなかった。 課題がうまくできていなかったので、途中にゲームをしていたのかもしれません。 もう少し注意して見ていれば早くに気が付けたと思います。', null, '時間帯: その他'),
  ('0e88e3ab-148b-582c-83dd-17732fa4de31', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-12-01', '16:30:00', null, '通常 / 【小技】体力ゲージをつくる', '前回までは検定の練習だったため，今回からは小技の作成をして新たなブロックの使い方について学んでいきました．今回行った体力ゲージを作る小技は今までに作成していたバトルが入るゲームとも親和性が高く，さらにペンツールというほとんど使ったことのなかったものも入ってきたため，興味深く作成していました．キャラクターを変えたい欲が高く，デザイン面に関しても積極的に取り組んでいました．', null, null),
  ('ea03231a-c32d-5250-964f-519ac372bf96', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-12-01', '16:30:00', null, '通常 / 【小技】体力ゲージをつくる', '今回の小技作成では勇作くんと一緒に体力ゲージについて作っていきました．二人ともゲームとして体力は重要な項目であると同時に，アクションやバトルの作品を作ってきたからこそ必要性を理解して集中して取り組んでいました．今までに使用したことのあるブロックや使い方についてはすぐに思いつくことができており，成長を感じられた回にもなったと思います．', null, null),
  ('e5315edb-8b93-5747-9513-a6b3f65f9091', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-12-01', '17:30:00', null, '通常 / ロブロックス', '前回レッツ・ショッピング！（後編）を1か月かけて行うと決めたので、今回はpart1を進めました。まともに進めたのが、かなり前なのでしらばっくれないように、こちら側から質問をしていきました。ここの辺の内容はデジタネの進め方は1回で覚えろよりかは何回か使って覚えていくという感じです。ontouchなどの構文は覚えていましたが、humanoidの機能を忘れ飛んでいました。今回、初出として、[destroy」や「：」の意味などを最後に遊びに逃げる前に再度確認して終えました。 robloxstudioのUIも変わってやる気を落としそうになっていましたが、そこは手厚くフォローしてとりあえずは1つは進められました。', null, null),
  ('f8fd8fc4-e61f-5bd9-9aca-bb923b263619', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, 'f7b1b888-88b7-5b1d-9bee-05201726d587', '2025-11-22', null, null, '通常 / 検定練習', '1級の応用課題の2をした。 質問なども特になくスムーズに終了していた。 答え合わせのときに、見本と見比べてもコードはあっているのにジャンプがうまくできないという問題に手こずっていたが、コスチュームが1pxずれていることが原因なことを特定して修正していた。 隆翔くんは問題をスムーズに解けていたので検定は合格できると思います。', null, '時間帯: その他
盛り上がり: バグを修正できるまで諦めずに原因究明するときや原因を特定して修正できたときは楽しそうだった'),
  ('e967da30-62f5-5fbf-9b79-15083a7645a8', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2025-11-22', null, null, '通常 / 3級の検定対策(3級応用問題3)を進める予定、ただし本人のやる気次第でイラストへの変更可能。', 'アルスタジオ：検定3級対策については、やる気はなかった。 →検定問題に対しては、最初から今日はやらない宣言を受けましたので、ゲームの切りがいい時に、何をしたいか確認をしました。 もう少しゲームをしてから、アイビスペイントをしたいと言っていたので、後半からアイビスペイントをしました。 アイビスペイントは、背景への星を追加したときに反応が少し遅いと言っていたが、ツリーの飾りの明暗をつけるのが上手くでき、さらにベース色(ツリー自体)の調整をしていた。 また、PC画面のチラつきについて、少し気にしていた。 →次回、Chromebookで再度確認をするようにします。', null, '時間帯: その他
盛り上がり: 横スクロールゲームに関しては、ハイスコア狙いで集中していた。 →アイビスペイントについては、【レッスン様子】に移動しました。 追加：アイビスペイントで光の明暗がとてもきれいだと言うと、実際に設定方法を教えてくれ、さらにもう少し明暗をはっきりさせたいと試行錯誤をしていた。'),
  ('01a84283-1dba-5f44-98f0-01a8f7ef20c1', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2025-11-22', '16:30:00', null, '通常 / 検定練習', '前回の3級応用課題1で発生していたバグ修正を行った。勘太郎君は特に繰り返しブロックの間違えが多く、複数の繰り返しが絡むと理解に苦戦している様子だった。 目標である3級応用課題4の時間を確保するため、こちらから「この処理が終わったらもう1回繰り返してほしいから、このタイミングで繰り返してほしいね」といった分解のヒントを一緒に考えた。 正後にどのような変更をしたのか尋ねたところ、曖昧な部分はあったものの、ある程度理解できている様子だった。 3級応用課題4は、途中で手が止まることなく一人で淡々と進めていた。25分程度で解き終わったが、「複数の文字と変数の値を組み合わせる」方法を知らなく、苦戦している部分があった。それ以外にも不等号の向きを逆にしてしまう事が多く、検定が近いことから、どちらも知識として教えた。 勘太郎君は「アレンジの時間まで取るのは難しいが、時間内に解ききることはできそう」と言っていたので検定に向けての不安は少ないのではないかと感じます。', null, null),
  ('11d496f5-7a44-5161-b502-6532797eac94', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '39c367bc-400f-521c-85a3-5b6d9099f4a3', '2025-12-01', '16:30:00', null, '通常 / 小技', '【レッスン様子】 正規の方法とは違うやり方で再現しようとしたり、こちらの説明を聞いてすぐに理解して組み上げられたりと特に問題なく進めることができていました。 タイピングに関してはまだ慣れておらずかなりもたつきが見られました。 完成後のアレンジに関しては既にやりたいものがあったのかかなり意欲的に取り組んでいました。', null, null),
  ('cacdccc2-ec07-5073-b795-6fdd7f4669a7', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-13', '17:30:00', null, '通常 / Excel検定の対策', '特に問題なくできています。', null, null),
  ('353b4f1d-f290-51d3-a618-04964f6d3d74', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-12-02', '16:30:00', null, '通常 / 小技を使って作成する', '検定の結果については嬉しそうでした。それなりに自信もあったそうで、自分の解いたファイルを開いて「ここをがんばった」などと教えてくれました。 小技は一通り見てくれましたが、あまりピンとこなかったようで、体力ゲージを使った自分の過去の作品を少しいじったりしていました。クマ退治ゲーム自体はよく作れていたので、自分のHPにもゲージを作ることを勧めたのですが、それは面倒だとのこと💦 とりあえずスクラッチの1級がとれたので、今後何を勉強していきたいか、家でも少し話し合ってきてと伝え、了承してくれました。 後半は棒人間アスレチックを遊んで少しアレンジを試したり、ほかのゲームをちらほらいじったりしていました。', null, '盛り上がり: 検定は自分でも頑張ったと思ったのか、満足そうにしていました。
備考: 久しぶりにお父さんがお迎えだったので、少し話ができました。1級合格についてはとても喜ばれていました。ここまでスキルが身についたのか、と感慨深そうでした。 今後ロブロックスに進むのか、このままスクラッチをやっていくのか、家でも相談してほしい旨をお伝えしました。 本人は、イラストは以前は興味があったけれど、最近はプログラミングの方が良いそうです。'),
  ('3a5b9b33-8cde-5bcb-8f9a-fea2e8fd914c', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-12-02', '17:30:00', null, '通常 / 小技を使った作成をする', '定期テストが無事に終わったこと、数学と理科の点数が良かったことを嬉しそうに話してくれました。 小技については、素直に一通り確認して、ビームの巨大化を選んでいました。 アルくんとビームのコードで注意する箇所を一緒に確認し、そこだけ削除して自分で作成させましたが、いずれも問題なくできていました。 コードの確認ができたあとは、自分でスプライトを増やし、スマブラのようなゲームにアレンジしていました。', null, '盛り上がり: コードを理解してアレンジに進めたので、集中して楽しそうに取り組めていました。'),
  ('9a133f69-9832-54d1-8db4-19bb2cf4f653', '57f45872-1f3e-5540-b676-bf9023444e39', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2025-12-04', '16:30:00', null, '通常 / 小技を使用してなにかを作成', 'HPバーをペンを使用して作成する小技のアレンジを行なっていました。 外部の画像をネットから拾って追加したりキャラクターの数を増やしたりのアレンジをしていました。', null, '盛り上がり: アレンジ中に、タイピング大会で三位になったと話していました。'),
  ('4e91c2f7-941f-5990-b297-ea118613e50e', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-12-04', '16:30:00', null, '通常 / 小技習得', '残像のモノに気に入ったらしく、以前作っていたドラゴンを倒すものにドラゴンの効果として、追加していきました。最初は、ただコードを映してうまくいかなかったが、ドラゴンの動く速さに合わせて、自ら数字を調整したところ、きれいに出来上がっていました。その流れで、ほかのドラゴンも画像効果を追加して、各色のドラゴンの動きにふさわしいものになりました。', null, null),
  ('de1f6ebf-7986-5e62-bffd-54f49199537c', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2025-12-04', '16:30:00', null, '通常 / 小技を使用してアレンジ', 'HPバーをペンを使用して作成する小技のアレンジを行なっていました。 操作キャラクターが攻撃時に敵の攻撃を受けやすくなるよう変更したり、敵の数を増やしたりしていました。', null, '盛り上がり: 検定に合格したと、喜んでいました。 アレンジ後はこたろう君達とアクションゲームで遊んでいました。'),
  ('e9780979-fb85-53fa-affe-ed0da98033fd', 'f3102a36-fdd8-574f-bf3c-85723faf424f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-12-04', '16:30:00', null, '通常 / 小技習得', '小技習得のために、いろいろとみてくれていたのはいいですが、最終的には耐力ゲージのモノを選びました。ペンの存在を知らなかったので、その認知としてはよかったです。アル君に動きを増やして、早々とアレンジを終えようとしていました。時間的にもかなり早かったので、やられたリアクションも追加して残り30分はずっと遊んでいました。', null, null),
  ('52f78499-22d3-5934-b36b-8cb43b0ca39c', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-12-04', '17:30:00', null, '通常 / U16大会の本線の準備', 'U16大会本線に選ばれたものの、ほかの比べて、作品が全然完成していないので、至急取り組んでもらいました。特にゲーム性の高い「戦い」の部分を制作していきました。一度にいろんなことをやると、整理がつかなくなっていたので、先生と相談しながら作っていきました。味方の動きとして「動かすものをクリック→2度目のクリックした場所に移動する」を再現しようしたが、「もし」を使ったクリック判定だとうまくいきませんでした。そこで、「まで待つ」追加して、クリックに順序をつけたら動作できました。そこで、ほかのスプライトにもコピーできるように、ローカル変数で対応しました。敵の動きに関しては、乱数で自分で作れていました。 今日はここで終わったが、HP管理として、触れあうと、HPとともに大きさが減少していくkとは想定できています。それ以降の、勝利条件や、ほかの部分の作成など、やることはかなり多いいです。本人的には、1回で終わると言っているが、全然終わらなそう気がするので、追加で授業を増やした方がよさそうです。 5分間のプレゼンのことも本人はどれほど大変かわかっていなそうなので、', null, '盛り上がり: そうたくんの作ったゲームをさらに改良させる案を提示して盛り上がっていました。'),
  ('6437a3f3-07f7-5c5a-90c1-61843c2de411', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-12-04', '17:30:00', null, '通常 / 小技習得', '小技選びでなかなか悩んでいたが、最後のガーンでいいアレンジのアイデアが思い浮かんだらしく、そこからは切り替えてスムーズに作りあがっていきました。物語を作り、「ケーキが目の前で売り切れになってしまう」少し笑える話になっていて。うまく活用できていました。', null, '盛り上がり: そうたくんのGゲームがみんなでお気に入りでした。'),
  ('3618da0c-ac15-558a-b842-7a8e88179f4b', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-12-04', '16:30:00', null, '振替 / U16大会本選の準備', '作品自体を、初見の先生二人に説明してもらい、アピールするべき点をすり合わせていきました。先生たちの意見と本人の意見もほぼ一致したようで、そのあとはアピールする箇所の細かい修正や作りこみをしていました。 本番は、提出したスライドは使わずプログラム自体を見せながら説明していくとのことなので、タイトルスライドと原稿の準備をするということで納得していました。 実際に投影しながら発表する練習もしてみたいとのことなので、明日までに一部分でも原稿を準備してくるとのことでした。', '発表の練習をする予定です。', '盛り上がり: 小学生に作品の簡単な紹介をしたり、先生たちに説明したりと、わりと楽しそうによくしゃべっていました。
備考: 八王子東高校が第一志望だと話していました。 今回の大会の結果も三者面談で先生に話していて、内申に書いてもらうそうです。'),
  ('09c72f45-0b8d-517f-b68c-bb74ad48cd04', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-12-04', '17:30:00', null, '通常 / 小技習得', 'いつものやつねとおおむね理解できていながら、新しい小技に挑んでくれました。ガーンは物語の転換に使いやすく感じてくれたため、ショートストーリーでいくつも作ってくれまhした。作って楽しいのか、来週まで引き続きやりたいそうです', null, null),
  ('24533852-19f0-5ed7-8ea9-dab4d2f599fb', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2025-12-05', '18:40:00', null, '通常 / 小技を利用した作品作成', 'タイマーの扱いの小技を授業時間半分ほどで完成させました、その後別の小技の作成も勧めましたがアレンジに夢中な様で、そのままアレンジを行いました。', null, '盛り上がり: アレンジ内容として、学校の先生のオリジナルキャラクターらしい"クーマ"をコスチュームとして追加していました。 肉球や光の反射も描き込んでいて、とてもこだわって作成していました。'),
  ('6125a0aa-c891-56bd-9a1a-d83b45e0a0a5', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-05', '16:30:00', null, '通常 / 小技', 'ビームの小技のお手本を見せたところ、食いついてくれました。お手本をリミックスして開始したので小技を自力で作成するところはできませんでしたが、ポイントとなる「タイマー」や「うずまき」については話しました。シューティングゲーム風のアレンジをしたいと言って、敵を作っていました。その際クローンを使おうとしてバグっていたので、本体とクローンの動きを分けて考えるように促すとうまくいきました。また、「うずまきの効果」のブロックをいじり、一気にうずまきにしたり違う効果を試したりしていました。', null, null),
  ('240b6129-4be1-5971-a1a9-b8a1fda4c902', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-05', '17:30:00', null, '通常 / Roblox', '検定が終わってRobloxに復帰しました。やはりデジタネをやる気にはならないようで、自分でrobloxのステージを作っていました。広い草原のステージに山や湖などの地形を複雑に設置して、本格的なゲームっぽくなっていました。レッスン終盤、 ・SpawnLocationをランダムな位置にする ・歩く速度を変える（→humanoidオブジェクトのwalkspeadでできる） をやりたいと言ってくれたのですが、時間が足りず次回に持ち越しになりました。', null, null),
  ('23c2327b-7003-565d-8740-182daeda4aa5', '10db50c3-a153-502a-b455-c67362b9871c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-05', '17:30:00', null, '通常 / 小技', '好きな小技を選んでもらったところ、一番役立ちそうだということで体力ゲージを選んでいました。ポイントだけ示した手順書を見せると、それ以外は見ずに一から作成していました。そこで使うペンや定義の仕組みはしっかり理解していました。HPが0になったときに少しゲージが残ってしまう(お手本でも自分のでもそうだった)のが気になって、ゲージ枠の位置や形状を工夫していました。', null, null),
  ('ef23c622-1595-57ec-8c4a-d6650a8ec71b', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-05', '18:40:00', null, '通常 / Roblox', '前回バグだった所を直し、その後アレンジをしました。UIが変わったことでToolboxの場所がなかなか見つからなかったようですが、見つけた後はいろいろなものを追加していました。敵やライフルなどを入れていました。動画はコンプリートしたので、次回チェックテストから入るとよいと思います。', null, null),
  ('48d001bd-b037-52c8-acaa-bee3b49de070', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2025-12-05', '16:30:00', null, '振替 / 小技', '体力ゲージのUIのズレを修正するところから始まった。教えている時はしっかり聞いてくれていた。ビームの課題は論理式の「スペースキーが押された」でない まで繰り返す。を重点的に教えた。', null, '盛り上がり: 楽しそうにアレンジしていた。'),
  ('5647853b-1e4f-52b4-b9a8-13b2b796ace2', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2025-12-05', '17:30:00', null, '通常 / 小技', 'ビームのuiの不具合で躓いたが、しばらくすると修正できた。少し教えると自分でコードを組み立てていい感じに進めれていた。', null, '盛り上がり: アレンジを楽しんでた'),
  ('0f774a74-edbf-5837-b104-6a96220af2fd', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2025-12-05', '18:40:00', null, '通常 / 小技', '回答を見ながら解こうとしていたが、自力で考えさせるように導いた。 論理式のところで詰まっていたので、回答を参照しながら教えた', null, '盛り上がり: アレンジを楽しそうにしていた。'),
  ('79a1e3bb-89fb-5d7a-96fd-3688c028c0ed', '5fc65a36-fdbb-5af5-a6f4-16080e4e37ef', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-07', null, null, '通常 / 【体験】', '橋本の小2。マイクラや、YouTubeでプログラミングをしている動画を見るのが好き。マウスは初めてだが、一生懸命に使おうとしていて、「だいぶできるようになった」とのこと。話すのが好きで、説明も好き。10歩では早すぎて5歩では遅すぎ、というときに、どちらからも2違う7と8が候補、みたいな話し方をする。基本操作のブロックや背景などを紹介するたびに、YouTubeで見たことある、と喜んでいた。洞窟ダイヤのアレンジをかなり楽しんでいた。スプライトやコードの複製を学習済み。', null, '時間帯: その他'),
  ('8f97beb7-aba3-5f21-9a03-827633727d30', 'dbe3dbc6-eb44-5cf8-b4f8-2bf2348e73cf', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-08', null, null, '【体験】', '七国在住で、学校は私立（桐朋？）自分でポケモンゲームのオープニングを作っていて、USBを持参して見せてくれた。Scratchは、今年買ったラズパイに入っていたので興味をもってやり始めたそうだが、何か作るのが楽しい、といった感じ。自作ゲームに合わせて、背景スクロールをおしえた。マイクラもやっているそう。', null, '時間帯: その他'),
  ('8cc4acea-4ad2-5b7f-9e5c-4c0f981d67f3', '1da24088-9441-50c6-ac58-79e18ef5cc01', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-09-30', '17:30:00', null, '【体験】', '自分で考えてゲームを作ったことがある、とのことでしたが、おそらくほぼ独学のようでした。ジャンプのときに条件分岐を使う、というのはわかっていましたが、ずっとと併用するのを指摘するまで気づかなかったり、向きを変えるのと回すのブロックの混同が見られたりと、スキルの整理が必要なところも多くみられました。自分でジャンプを作るとおりられないんだよ、と言っていましたが、向きを0度にして10歩動かす、というのが作れても、-10歩が作れていなかったため、そこの説明と、10歩動かすを〇回繰り返したほうがよりジャンプらしく見えることを提案すると、「こんなことができるんだ」と感動してくれました。ライフル弾のクローンを使った連射なども、とても面白がっていました。すらぼーが端についたら次のステージにいく、というところで座標を使った画面の切り替えを学習しました。座標は苦手だと思っていたけれど、スプライトの下に座標が出ることがわかってからは、なんとなく使えるような気がしてきた、とのこと。 作りたいゲームがはっきりしていて、1時間以上集中してオリジナル作品を作っていました。また来週続きを作りに来たい、とも。ロブロックスのアカウントを友達から聞いたとかで、ロブロックスをやりたいそう。目安として検定1級②と、検定2級②の完成例を見せました。2級のスロットマシーンがおもしろかったようで、コインが出てくる枚数を増やして喜んでいました。', null, null),
  ('4e808b2d-7dae-5d6a-a004-ff4b332e9c59', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2025-12-06', null, null, '通常 / 小技使用作成', '最初タイマーの小技を作成後、完成品を見ながらでしたが、残像、鏡の小技を組み合わせて作成していました。', null, '時間帯: その他
盛り上がり: 小技全てを使ってみたいとやる気が高かったです。'),
  ('b9821acb-1bfb-5127-97e7-eebae4c9f579', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2025-12-06', null, null, '通常 / 小技使用作品', '最初にチャージして攻撃する小技を作成し、その後残像の小技に取り組んでいました、 画像効果の大きさに少しつまった程度で基本すらすらと作成できていました。', null, '時間帯: その他'),
  ('26269c23-8607-5dc4-802f-bbe71744808b', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-12-06', null, null, '通常 / ロブロックス', '自分のアカウントのパスワードを忘れてしまったようで、Roblox Studioにログインができないとのことで、It自由研究室のアカウントで入って、未来へジャンプの最初から始めました。実際にはあおし君のアカウントでは、ハラハラピンボールの途中まで進んでいるので、次回はこちらの途中から進めるようにして下さい。今日やった未来のジャンプは、途中まではX ,Y,Z座標の扱いについての座学のようなもので占められていて、不明点を何回か尋ねても問題なしとのことで、問題なく進められていました。次回以降、IT自由研究室の、2025/12/06のデータをダウンロードして、あおし君のアカウントで、今日の続きができるようにしておく必要があります。来週可能であれば、私が対応します。', null, '時間帯: その他'),
  ('e325b74d-4d8f-5ac6-b647-cb147896d56f', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2025-12-06', '16:30:00', null, '振替 / 小技使用作品', '体力ゲージの小技作成に取り組み始めましたが、難しいとのことで完成の物を見ながら作成しました。 その後は特につまづかず完成までできました。', null, '盛り上がり: 基本の完成後、アレンジとして操作キャラクタを自身で作成した電車コスチュームに変更していました。 5種類くらい作成していて、とてもこだわって作成していました。'),
  ('56cf712e-3329-5cd9-938c-f04f1121f98f', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-12-06', null, null, '通常 / 小技デイ', '一つ一つ小技で遊んでもらって、その中でも気に入ったビーム巨大化の小技を選んで、自力でプログラムを組んでいきました。「スペースを押した」ではないまで待つのようなトリッキーな部分とか、スペースキーを押した時間分だけ変数が大きくなって、その変数の値がビームの大きさ計算に使用するところとか、いきなり理解するのは難しそうですが、最終的にはきちんと理解して自分のものにしていました。最後に、時間があまりなかったので、この小技で色々アレンジして遊んでいました。体力ゲージの小技も気になったようで、挑戦したかったようですが、時間がなかったので、また別の機会に何かできたら良いですね', null, '時間帯: その他'),
  ('32e7b9db-e7dc-55a4-ac78-bd0d8bb0a23c', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2025-12-06', '17:30:00', null, '通常 / 小技使用作品', '一から体力ゲージの小技作成を行なっていました。 一からということでコスチュームの作画に手間取っていました、また、ペンの扱いも教えながらの作業になりました。 バーの動作とキャラクタの攻撃まで作成できました。 今回の授業時間内には完成しなかったので、家で完成させる様です。', null, '盛り上がり: キャラクタを2Dアクションのように操作できる様、また、二人で対戦できる様にアレンジを行なっていました。'),
  ('5a9449c0-3b07-599b-bb3e-88a232ce1060', '2758b49a-c2b1-5cd0-9b37-3b988f2a5a09', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-06', null, null, '通常 / 基本操作コース(変数や座標)', '完成版を遊んでイメージをつかんでもらったあと、一つずつステップを進めていきました。x座標とy座標の区別は前回まででよく覚えていました。「1秒でどこかへ行く」や「背景を～にする」、変数など新しいブロックも出てきましたがすぐに使いこなせました。「スコアを増やすのはいつ？」「レベルアップと表示するのはいつ？」など、処理のタイミングについて何回か問いかけしたところ、的確に理解していてブロックを正しい場所に挟むこともできました。', null, '時間帯: その他
盛り上がり: 適当ではなくきちんと考えながら、かつ楽しみながら進められました。'),
  ('f2fdc362-e6c4-550a-990d-fb8f57b0ba9b', '31feac25-f850-5d21-8e43-ed4d7badb6a0', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-06', null, null, '通常 / 小技day', '小技として何をやりたいか聞いたところ横スクロールを選んでいました。今回想定していた教材の中にはなく、ややレベルの高い内容でしたが、「一度中途半端にやって諦めた分をリベンジしたい」とのことでやってみました。クローンの概念は分かっていたので、座標の動きとクローンの生成タイミングを中心に説明しました。「x座標がどう変化するか？」「どこまで来たら新しいクローンを作るか？」を問いかけながら紙にまとめていきました。そうしてコードを作り、きちんと動いたときはとても喜んでいました。アレンジとして、日本刀も同時にスクロールさせてそれをよけるゲームを作っていました。', null, '時間帯: その他'),
  ('4ade9a50-2f30-5e0e-abf9-ce9bb884f71a', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-06', null, null, '通常 / Roblox', 'レッスン前半は遊んでばかりでしたが、後半はなんとか紙テキストで一緒に進めました。トラップについて、キャラクターが触れたらそのキャラクターのHPを0にするというscriptを書きました。学校での勉強を含め英語に苦手意識があり、単語をすぐ忘れてしまうとのことだったので、一語ずつ意味を確認しながら書き進めると意味が理解できたようでした。コード内で「兄弟」を表現するのに「自分の親の子供」としなければいけないなど困惑した点もありましたが、流れは把握できたようでした。', null, '時間帯: その他'),
  ('adb3ae7c-0587-5e05-b1fb-1492c5644599', '40a476bc-72a5-5bdc-ab75-e89d5310b442', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-12-06', null, null, '通常 / 小技デイ', '気になる小技を色々見てもらった中で、残像なら興味あるしできそうということで、１から作ってもらいました。まず、残像を表現するためにどうすべきかを、サンプルを見ながら言語化してもらい。クローンを使う、クローンを半透明にする（幽霊の効果）、クローンを小さくする。みたいな言語化はできたのですが、それを具体的に、ジャンプの時にどう組み込むのかのイメージが湧かないようだったので、少しずつヒントを与えて、自力で作成してもらいました。が、ジャンプの時に無理やり（使う必要のない）変数を使おうとしたりとか、簡単なジャンプの処理自体もささっと作ることはできなかったです。少し進んだ知識を知っていて、ささっと作れるようなこともあれば、基本でもできないことがちらほらあるというチグハグな状態かもしれません。その辺注意をしながら見ていけたらと思いました。', null, '時間帯: その他'),
  ('27a984d0-3d6c-58cf-8ffc-fd4e1bdf572a', 'dbe3dbc6-eb44-5cf8-b4f8-2bf2348e73cf', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-12-06', null, null, '通常 / 初回レッスン', '最初に、どれくらいスクラッチ歴があるか聞いたら、今年の3月くらいからとのこと、ポケモンみたいなゲームをスクラッチで作っているとのこと。PRGのゲームを実際に触らせて、この動きはどうやれば作れると思う？との問いに、きちんとうまく言語化もできていたし、その内容も、変数やメッセージ使用、〜ではないまで待つ、とかの理解もバッチリだったので、この時点で、結構できるかなと判断。今日は他の子たちと同じく、実際に小技を作ってもらいました。「残像」と「スペースでビーム大きくなる（実際には、拳銃から日本刀が飛び出るようにしていましたが）」の２つの小技を仕上げていました。最初の時点で言語化が上手だったので、理解力もあるんだろうなと思っていましたが、この二つの小技に対する、重要ポイントの私の説明もしっかり即座に理解してくれていました。だいぶできる子だと思います。', null, '時間帯: その他'),
  ('2c68cbc9-1786-5916-9d26-4c87cd5eeb6f', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-12-08', '17:30:00', null, '通常 / ロブロックス', '今日は早めに来て、デジタネ教材は早々とやっていました。やらずにだらだら授業時間をずっと過ごすよりかは授業時間前にやるのはいいですが、ちゃんと見ているか不安です。でも、途中UIの変更されたことで、捜査のボタンがわからず質問を聞きに来てくれたので、進めている気がします。5時半になって、やったことを確認すると、コインクローンとカウントでなじみが深い内容だったので、学んでいるのは分かりました。', null, null),
  ('6c4a4e4a-ab36-57dd-a1ff-ad01d63626c1', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-12-08', '16:30:00', null, '通常 / 3D ボールコロコロ', '今日からコンテスト作品の3D ボールコロコロに取り組んで行きました．はじめにゲームを実際に遊んでもらった際には，操作性の難しさや難易度に苦戦していたようですが，次第にはまっていき楽しめていました．作成では初級に挑戦していき，ボールの判定をどのようにして作っているのか理解していきました．今までに使ったことのあるものもいくつかあったため，スラスラと作っていくことができていました．色での判定についてもすぐに理解することができていました．次回で初級の残り部分を作って中級へと入っていきたいです．', null, null),
  ('4e8d8f9f-c501-55a6-947b-10d55687e820', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-12-08', '16:30:00', null, '通常 / ゲームコンテストの内容の理解', 'ゲームで最初に遊んだときは、これ学校でもやったことあるよ、けど苦手なんだよねと少しやる気が下がっていたが、いざやると岳君ともにランキングの上位を狙いたい気持ちで遊びのめりこんでいました。その最中、2人でスコアが途中でリセットされる違和感に気づてもらい、バグ修正に貢献してくれました。そのバグに乗じてスコアを良いものに不正使用としているときもありました。コード理解のために、影武者のところを触れようとしましたが、遊びが長引いてしまい、表面の黄色ボールしか手を付けられませんでした。 次回からは水ボールをコード見せながらなぜこの構造にしているか触れていきたいです。', null, null),
  ('b312758a-4bbd-5c15-a6e0-cc9c1592349e', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-12-08', '17:30:00', null, '通常 / 3D ボールコロコロ', 'コンテスト作品の3D ボールコロコロに挑戦していきました．遊んでいた際には黙々とプレイしており，記録をどう伸ばすのか考えながら遊んでいました．初級の作成を行なっていた際には，自分で考えて作るのがあまり好きではないようでとにかく早く答えが知りたいと言った雰囲気でした．オリジナル作品ではそんなことはなかったため，答えがあるものや好きではないものに関してはすぐに知りたいという気持ちが強いのではないかと感じました．今回で初級は終えられたため，次回からは中級に入っていきたいです．', null, null),
  ('25963c86-273a-59a3-a9ac-e44bba8fb248', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-12-08', '16:30:00', null, '通常 / ゲームコンテスト作成', '前回、振替でやった小技の作品をまずは見せてくれました。今回も小技が隠れているゲームを遊んでいくからと伝えてたら、喜んでいました。実際に遊び始めると、コツをすぐにつかんで、ハイ記録を題してくれました。ただ、途中でスコアの違和感に気づいてくれて勇作ンとバグ探しに貢献しtくれました。そこで、バグで不正にスコアを稼ごうとあがいていました。（笑）コード政策に移ると、影武者の概念が説明してもピンとこなかったので、次回はもうちょいわかりやすいもので答えたいです。遊びがかなりメインとなっていたので、、初級の裏側のこーーどはまた次回です。', null, null),
  ('123d1b5f-2963-55b8-a25b-27ac267c237f', '1c7005cc-2815-558f-993a-9c7617d34c44', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2025-12-09', '16:30:00', null, '通常 / ゲームコンテスト', '終始コロコロのゲームに夢中だった。コードのブロックの説明を試みたが、ゲームに没頭し、あまり聞き入れてくれなかった。ゲームはトライするたびにみるみる上達していた。自己ベストを更新するたびに、嬉しそうに報告していた。', 'コロコロゲームのコードの説明をしたい。', null),
  ('30cb757c-d1f0-5b25-af83-b42aa03045fa', '1da24088-9441-50c6-ac58-79e18ef5cc01', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2025-12-09', '17:30:00', null, '通常', 'ゲームも楽しんでプレイしていた。最初はマウスの操作に慣れていない様子だったが、回数を重ねるごとに上達していた。初めて会った子たちとも会話をし、馴染めている様子だった。後半は「自分でゲームを作ってみたい！」といい、カービィのようなホバリングの動作の作成に取り掛かってた。ジャンプしたあとに落下速度を遅くしたがっていたので、僕がお手本を作成するととても喜んでいた。自分でいろんなものを作りたい！という好奇心があるので多少遠回りでも本人がやりたいことをやらせた。', null, '盛り上がり: 帰り際にもう終わり？と言うほど最後まで没頭していた。'),
  ('f430a1fe-c05a-5bf6-bc97-26256b77217a', '512b2f12-24bc-5afa-913a-d68b4a9f9e14', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-12-04', '16:30:00', null, '通常 / ExcelとPowerPointの使い方を学ぶ', 'キャラクターカードの作成をメインにしました。吹き出し、スライドとプレゼンテーションの違い、テキストボックスの調整の仕方などをPowerPointで学習しました。 Excelで順位グラフを作成する復習をしましたが、表に何位と入れるとグラフにならないと困惑していたので、数値データとテキストデータの違いを説明し、ユーザー定義の表示形式を紹介しました。難しそうというので、できるかできないかだけでも覚えておくことが大事と説明しました。', '次回、グラフをパワポにはりつけ', '盛り上がり: 好きなキャラクターの作品作成なので、色使いなどにもこだわって楽しそうに作成していました。'),
  ('f71a861f-ad06-5e87-bdc5-36348ef82005', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-11', '16:30:00', null, '通常 / ゲーム大会と関連スキル', '前半はボールコロコロで遊びました。マウス操作が難しいと言いつつも自分なりにハイスコアを狙っていました。後半は影武者のスキルを扱いました。小技の方で進めようとしましたが、影武者の内容を把握すると「自分のゲームでこれをやりたい」と申し出ていました。魔法使いがドラゴンを撃つゲームで、魔法使いの判定を影武者にしていました。そのゲーム自体にも思い入れがあるようで、細かいコスチューム編集などもやっていました。', null, null),
  ('44c97169-9b85-5750-ab0b-918affcfd51f', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-11', '16:30:00', null, '通常 / ゲーム大会と関連スキル', '前半はボールコロコロで遊びました。しばらく頑張ってハイスコアを目指していましたが、「似たゲームがscratchにあってそっちのほうがいい」と言ってそちらで遊び始めてしまったので止めました。後半は影武者のスキルを扱いました。一から作るのは大変だというので、幽霊効果のところだけ作ってもらいました。幽霊と「隠す」の違いを質問すると、当たり判定があるかどうかだということは理解していました。', null, null),
  ('05e7b769-9322-5eb7-93f9-0aecb30f75a7', '57f45872-1f3e-5540-b676-bf9023444e39', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-11', '16:30:00', null, '通常 / ゲーム大会と関連スキル', '前半はボールコロコロで遊びました。「むずすぎ」と言いつつもしばらくやっていました。後半は影武者のスキルを扱いました。一から作るのは大変だというので、幽霊効果のところだけ作ってもらいました。幽霊は初めて使うそうだったので、透明だけど当たり判定はあることだけは覚えて帰ってもらいました。', null, null),
  ('3a25b097-3899-5019-9a58-ad9494acc833', 'f3102a36-fdd8-574f-bf3c-85723faf424f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-11', '16:30:00', null, '通常 / ゲーム大会と関連スキル', '前半はボールコロコロで遊びました。るいくんたちと競うようにやりこんでいました。後半は影武者のスキルを扱いました。内容はよく分かっていて、影武者を一から作ってほしいというとスムーズにできていました。少し時間が余り、中級の「3Dの基礎・応用」を勧めました。それを実際に作りはしませんでしたが、「大きさを変える」「最前面/最背面」「だんだんy座標を変える」というエッセンスは中のコードを見ずとも抑えられていました。', null, null),
  ('2ecc0f7e-36b6-5ced-a5bf-ea8c2fe942f2', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-12-04', '17:30:00', null, '通常 / Excel検定の準備', '授業前にU16大会の結果説明をしました。今回は応募が1000を超えたこともあり、オリジナリティのあるプレゼンが大事ということ、来年もチャレンジするのであれば、コンテストの趣旨にあわせた作品を作るか、ほかのコンテストをさがすか検討してほしい旨を話しました。だめだったか～と残念そうにしていましたが、来年のことも考えると前向きにとらえてくれて、とりあえずエクセル検定を受けてみるということになりました。 ROUNDDOWNについては、桁数をとりあえず入れてみればサンプルがでるのでそこで判断すればよいことを説明しました。 RANK.EQで、数値に範囲全体をいれていたので数値と参照の違いを説明し、そういうことか！との反応でした。また、絶対参照のマークは覚えていましたが、参照で範囲選択のあとF4ですぐに入れられることに驚いていました。 「値」での貼り付けは初めてだったようで困っていたので、普通のコピー&ペーストとの違いを実際に操作して納得してもらいました。模擬問題4の問題3まで完成。', '続きをするか、時間をはかって次の模擬問題。', '盛り上がり: 大会結果は残念がっていましたが、しっかりとExcel検定に頭を切り替えて一生懸命取り組めていました。'),
  ('1c52bdf7-6cab-5eb0-86c9-6915555f44f6', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-11', '16:30:00', null, '通常 / ゲーム大会と関連スキル', '前半はボールコロコロで遊びました。小さい判定ボールの存在に気づき、その小ささを意識しながら動かすとうまくいくというコツを編み出していました。その流れで、後半は影武者のスキルを扱いました。影武者の概念はすぐに理解し、幽霊化してキャラについていかせるのをほぼ自力で再現できていました。残りの時間は、前回やった小技「ガーン」の製作を続けたいらしくそれをやっていました。「日常でガーンとなる瞬間○選」を、楽しそうに作っていました。', null, null),
  ('a326b01f-5a54-556c-88f9-f641c9472639', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-11', '17:30:00', null, '通常 / ゲーム大会と関連スキル', '前半はボールコロコロで遊びました。高得点を取っている周りに負けじと頑張っていました。後半は影武者のスキルを扱いました。横で同じ内容をやっていたそうたろうくんから少し聞いて内容を理解していました。影武者をキャラに追従させる→幽霊化する→影武者が星に触れたら得点 という流れを、一つずつコツコツ作っていきました。', null, null),
  ('7edc3be7-acf0-52e4-a0e1-8d0d3686572d', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-13', '17:30:00', null, '通常 / 検定対策', '長文を読むのがとにかく面倒そうでした。 変数●●を答えにする、で、等式の演算式をもってきていました。変数●●の値を1にする、で考えさせると理解していたが、問題文をパッと見てそれっぽいブロックを持ってきてしまうので、落ち着いて、問題文を細分化して考えるよう伝えました。 簡単だ、と言いつつも、とにかく文章を読むのが面倒なようで、修正問題が嫌いなようでした。', null, null),
  ('f33ae445-e272-597d-af3a-61fd040cb081', '05439956-11b9-5ac7-a44a-3e6f5a6831d8', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-13', '16:30:00', null, '通常 / 検定対策', 'まったく問題なく、30分もかからないで解き終えていました。アレンジをどこまでしていいのか聞いてきたので（スクリプトの削除はありか？など）、できているコードは残しておいて、自分が説明できる範囲でアレンジをするよう伝えました。余裕があるので100点合格を目指すそうです。問題を1題持ち帰りました。', null, null),
  ('549e976b-aa56-543f-ac98-587b2a845d0e', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-11-18', '17:30:00', null, '通常 / Excel検定本番', '無事に受験できました。手ごたえもしっかりあったようでした。 最後にきちんと挨拶をして、お菓子を渡して帰っていきました。', null, null),
  ('c4462762-e414-5851-9206-9fa864b2a643', '512b2f12-24bc-5afa-913a-d68b4a9f9e14', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-12-11', '16:30:00', null, '通常 / ExcelとPowerPointの学習', 'グラフ作成の復習として、2つほどお題を出してグラフを作成してもらいました。表を作成してからグラフを作る手順はしっかり覚えていて、自分で色遣いなども工夫して見やすいグラフを作成できました。 グラフをコピーしてPowerPointに貼り付けるのもすぐにマスターしました。 グラフに見合ったキャッチコピーを考えてもらい、キティちゃんの紹介ページを3ページほど作成することができました。デザインもなかなか上手で、雰囲気にあったスライド作りができていました。 次の課題として、似たようなスライドを作る際にはコピーをうまく利用することを教え、キティちゃんのスライドをもとに、シナモンのページの作成に入りました。', 'シナモンの紹介ページを作りながら、グラフとPowerPointでの作成手順の定着をはかる', '盛り上がり: 授業で作成するのがとても楽しい、と言ってくれました！'),
  ('fcd961eb-d2d1-52aa-a5b0-e0682b23730a', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-12-11', '17:30:00', null, '通常 / コンテストを楽しむ、Excel検定の準備', 'Excel検定を受験はするものの、今日はちょっと疲れていたのか、「今日もずっとExcelですか？」と聞いてきたので、気分転換に前半はコンテストのゲームを勧めました。嬉しそうにしばらくプレイしていて、4位の記録が出たら自分から「そろそろExcelやらないとまずいですよね」と切り替えてきました。 前回できなかったグラフとページレイアウトの問題をメインに取り組みました。作業時間もだいぶ速くなり、グラフエリアの塗りつぶし以外は質問もなくできました。', null, '盛り上がり: 相変わらずゲームのコンテストは得意なようで、難しいと言いつつも好記録を出し、楽しそうでした。
備考: Excelの受験日について、試験もあるので木曜日にするか検討してくるとのこと。'),
  ('d145220f-4348-5038-96b8-72d678c208ee', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-12-11', '17:30:00', null, '通常 / U16大会本選準備', '本選のため、16:30から19:30くらいまで発表準備をしました。 今日は事前に保護者の方にも伝えてもらったせいか、ほかの子と遊ぶのも我慢して、一人の机で頑張っていました。 ゲームの完成は完全に間に合わないので💦発表原稿に合わせて必要な部分だけを作成していきました。いいこと思いついた！と嬉しそうに作成に没頭したり、急に「もう間に合わない！つかれた！」とぼやいてみたりを繰り返しつつも、なんとかやりたかったことを説明できる内容にはなったかと…。 実際にお母さんの前で発表練習もしました。5分を15秒ほど超過しましたが、途中で操作にとまどわなければ大丈夫かと思われます。 家で作成して2分ほどで済んでしまった原稿をふくらませることができて、親子ともどもホッとしたようでした。 長時間だったため、途中何度か気が散るところもありましたが、文章なども積極的に考えて発表練習もしっかりできていました。', null, '盛り上がり: いつもよりもかなり集中してがんばっていました'),
  ('6fbddf7d-b0d9-58fc-9980-3b102961c210', '5fc65a36-fdbb-5af5-a6f4-16080e4e37ef', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-12-05', '17:30:00', null, '通常 / 教室に慣れる', 'プログラミングを勉強にきているという意識がきちんとあります。基本操作コースの学習表を見せると、これを全部うめたらすごくできるようになる！と盛り上がって、課題も意欲的にとりくめていました。やりながら、ひたすらひとりで解説をしたりしていますが、話を聞きながらも次にやることなどを発問していくと、きちんとのってきて取り組むことができます。お手本を見せてから、どういう動きだったかという発問で課題を進められるので、カードは使用しませんでした。 算数は得意なようで、角度が一周360度ということや、何度の回転を何回繰り返すとどのくらいまわる、などということも計算してわかっていました。座標が縦横でxyを使うこと、反対向きの時はマイナスを使うことなども理解できていました。xyの使い分けについては、スプライトの上に書いてあることを教えると「これなら迷わないかも！」と感動していました。また、コードの複製も教えるとよろこんでやっていました。 学年のわりに、漢字もよく読めます。マウスはまだなれていなくて、力が入ってどんどんずれていってしまう傾向がありました。右と左クリックも、もう少し慣れるとよいかなあと。', null, 'タイピング: ひたすらしゃべりながらやっていました。学校ではもっとできたとのこと。 時間がかかっても、きちんとした指でうとうとするところがよい傾向です。
盛り上がり: とにかく楽しそうに、一生懸命取り組んでいました。'),
  ('b439ddae-42b5-5618-aeb1-b366e0e28763', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-12-05', null, null, '通常 / Excel検定対策', '検定本番まで、知らないスキルをなくしていくことを目標に、わからないことがあったら聞いて覚えてほしいと最初に説明しました。そのせいか、行き詰るときちんと質問してきてくれました。 セルの書式設定の配置の横位置の繰り返しという問題の意味がわからなかったようで質問してきたので、言葉のまま、メニューを探して進めていくことを教えると、自分で操作して納得していました。 ROUNDDOWNの中の引数で、割る数値を絶対参照にすることを、オートフィルをした数式の中身を見せて説明しました。 軸の書式設定の単位の場所についても、問題文のまま、メニューを探すよう促しました。 印刷の垂直と、ヘッダーフッターの編集については初めてだったようで、これも説明して理解できていました。', null, '時間帯: その他
盛り上がり: 知識の抜けを埋めて完成させることができて、満足そうに見えました。'),
  ('54c50678-9bfd-52bb-8693-2d0321d363ba', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-12-05', null, null, '通常 / Excel検定対策', '検定本番まで、知らないスキルをなくしていくことを目標に、わからないことがあったら聞いて覚えてほしいと最初に説明しました。 とらくんはほぼ行き詰ることもなく、順調に解き進めていて、時間内に終了していました。 テーブルの書式設定の前にセルの塗りつぶしをしていて色がおかしかったので指摘したところ、どうりで変な色だと思ったといってウケていました。', null, '時間帯: その他
盛り上がり: Excelは得意なのか、問題なくすらすらとできていて少し得意げでした。'),
  ('60346dcf-69d4-5397-be7d-f83529bcf0d4', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-12-05', null, null, '通常 / Excel検定対策', '検定本番まで、知らないスキルをなくしていくことを目標に、わからないことがあったら聞いて覚えてほしいと最初に説明しました。 セルの書式設定の配置の横位置の繰り返しの意味がわからなかったようなので、言葉のまま、メニューを探して進めていくことを説明し、納得していました。 ROUNDDOWNの中の引数で、割る数値を絶対参照にすることを、オートフィルをした数式の中身を見せて説明することで理解できたようでした。 問題自体は上記以外は解けているのですが、まだ操作に慣れきっていないのか、少し時間がかかる傾向がありました。', '次回、問題4から', '時間帯: その他
盛り上がり: 淡々と作業していましたが、わからないところが解決すると少し嬉しそうでした。'),
  ('5a083a6f-dc53-5ce3-8922-9fce098bdede', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2025-12-12', '16:30:00', null, '通常', '記録更新に熱心だった。コード分解も少し触れて、当たり判定の透明部分を一緒に改造した。ゆうれいの機能を他のものに変えたりした。基本的にはコンテストの記録更新に夢中だった。', null, null),
  ('225101be-a73a-5a59-8808-d40e129023cd', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2025-12-12', '17:30:00', null, '通常', 'ゲームの記録更新にも熱心だったが、他の子よりはコードの分解に興味を示していてた。初級の部分のコードの再組み立てをしていた。ゆうれいの効果や、当たり判定の改造を行った。', null, null),
  ('4616327c-7f54-576f-93dd-916b923d3937', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2025-12-12', '17:30:00', null, '通常', '終始記録更新に熱心だった。マウス操作があまり得意そうではなかったが、落ち着いて取り組んでいた。コードの内容を教えたかったが記録更新に夢中だった。', 'コロコロボールの初級の内容を教えたい。', '盛り上がり: 楽しそうにプレイしてた'),
  ('ed4c17df-b3bf-5857-bb18-8d3b6f5502ef', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-12', '16:30:00', null, '通常 / ゲーム大会と関連スキル', '前半はコンテストゲームで遊びました。今週火曜日も振替で同じことをやっていたため慣れており、(生徒内)1位に躍り出て得意げでした。後半は関連スキルを扱いました。3Dの仕組みに興味をもったので基礎の教材を見てもらうと、スプライトの大きさと最前面/最背面がポイントだとつかめたようでした。', null, null),
  ('def494d3-2ed7-56f9-95dd-3593712cb46b', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-12', '16:30:00', null, '通常 / ゲーム大会と関連スキル', '前半はコンテストゲームで遊びました。当たり判定に文句を言いつつもスコアアップを狙って粘っていました。後半は関連スキルを扱いました。影武者を作るように促すと、幽霊効果については分かっていたため、自力でさくっとやってしまいました。矢印キーの移動も、滑らかな方法(もし「～」キーが押されたなら)で作り変えていました。残りの少しの時間は、棒人間アスレチックでも遊んでいました。', null, null),
  ('6a4cc658-b085-5434-84c3-41c9fb9beeeb', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-12', '17:30:00', null, '通常 / ゲーム大会と関連スキル', '前半はコンテストゲームで遊びました。はじめは操作感に慣れないながらもだんだん安定して走れるようになっていました。後半は、Robloxは乗り気ではなさそうだったので、3Dボールコロコロの関連スキルを扱いました。あまり勉強チックなことは嫌そうだったので、3Dの仕組みについて、お手本だけ見せて考えてもらいました。そして、近いものを自分オリジナルで作ってもらいました。スプライトの大きさを変えながら、キャラを手前に来るように見せていました。', null, null),
  ('bf736581-2e86-5431-9325-2b01eed9d4d3', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-12', '17:30:00', null, '通常 / Excel検定受検について検討', '検定の模擬問題を解いてみて、受けるのかどうか・何級を受けるのかを決めました。2級は実技問題はまだいいものの知識問題が厳しいらしく、3級はいけそうという様子でした。そのため「3級を受検する」と言っていました。', null, null),
  ('fe53cf8e-05e5-5e67-8476-c2703da3e592', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-12', '18:40:00', null, '通常 / ゲーム大会とRoblox', '前半はコンテストゲームで遊びました。なかなか苦戦していましたが、目標として決めた100点を達成するまであきらめずにやっていました。後半はRobloxに移りました。マイハウスを軽く修正した後、チェックテストをやりました。問題に出てくるだいたいのコードは読めていましたが、"+="が何だったかだけ忘れていたのでおさらいして解きなおしました。結果、無事満点になりました。', null, null),
  ('b52fa606-e0bf-5034-b114-8c049ff3dade', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '7c6bdbc6-3838-5e84-bf07-a26ee6bfe976', '2025-12-12', '17:30:00', null, '通常 / ゲーム大会と関連スキル', '今日はゲームコンテストに熱心に取り組んでいた。途中、十海君と柚月君が攻略法をアドバイスし合う様子が見られた。記録更新のために夢中にしており、手順書の初級を終わらせることはできなかったが、最終的に451mという最高記録を出すことができていた。', null, '盛り上がり: 最後まで粘り強く取り組んでいる様子が印象的であった。何度も大きな声で悔しさを口にしていた。'),
  ('15330152-12ef-57f8-be49-a5893691eba3', '10db50c3-a153-502a-b455-c67362b9871c', null, '7c6bdbc6-3838-5e84-bf07-a26ee6bfe976', '2025-12-12', '17:30:00', null, '通常 / ゲーム大会と関連スキル', '3Dボールコロコロの手順書にある超上級の課題に取り組んでいた。 Scratchのリスト機能を使用したコース設計をさらに発展させ、新たにタイル4を「スーパージャンプ」にするなど、自身で工夫を加えていた。途中、予想通りに動かないこともあったが、自力で解決することが多かった。', null, '盛り上がり: スピードを上げたり、高くジャンプさせるなど、躍動感のあるゲーム作りを楽しんでいる様子だった。'),
  ('1a8fefbe-1744-5491-a76f-e451ccf92adb', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '7c6bdbc6-3838-5e84-bf07-a26ee6bfe976', '2025-12-12', '18:40:00', null, '通常 / ゲーム大会と関連スキル', 'レッスン当初は3Dボールコロコロで高いスコアを目指し熱心に取り組んでいたが、なかなかスコアが伸びず、最終的には意欲を無くしていた。その後、手順書の初級編に取り組んだが、あまり理解する姿勢が見られなかったので「この変数は何を指しているか」など基本的なな質問を多くすることで解決した。今回はゲーム自体の難易度が高く、それが本人にとっては負担となってしまったのではないかと考える。', null, null),
  ('70854444-40b7-5fa5-99da-a3e5e974d1b4', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2025-12-13', null, null, '通常 / ゲームコンテスト', '一通りプレイした後、リストを使用してのコースの変更を行ないました。', null, '時間帯: その他
盛り上がり: ジャンプタイルを多く設置することで、リズムよくプレイできるようにしていました。'),
  ('48329fbc-99f0-5b7a-bf7e-0e604fe66f04', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2025-12-13', null, null, '通常 / ゲームコンテスト', '30分ほどボールコロコロと格闘していましたが、なかなか進めず集中できなくなってきたので、まだプレイしていなかった棒人間アスレチックをプレイしました。', '次回はボールコロコロの小技/アレンジを勧めれれば。', '時間帯: その他
盛り上がり: 棒人間アスレチックはボールコロコロよりは楽しんで取り組めていたようです。'),
  ('a0c2f3c5-ee9d-5869-b097-437428538c7b', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2025-12-13', null, null, '通常 / ゲームコンテスト', 'なかなか操作が難しいゲームでしたが、マウスとタッチパネルを両方使うスタイルで楽しんで取り組んでいました。', null, '時間帯: その他
盛り上がり: 集中して取り組んだ結果、記録として四位にはいることができていました。'),
  ('eb7b238a-8d1e-5f2b-9f83-3f1ffaaca820', '2758b49a-c2b1-5cd0-9b37-3b988f2a5a09', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-12-13', null, null, '通常 / 習ったコードを使えるようにしよう', '今回は、今まで学んできたコードなどを使えるようになるために、サメから逃げろを作成していきました。まずは、ゲームを観察して、どのような動きを読み取ることはできていました。コード作成では、「上下左右にうごく」 ことは、xy座標の移動のコードは理解できていましたが、「キーを押す」については、そのブロックは使いたいが、どこにあるかわからない状態でした。機能はしっかり理解できているので、回を重ねればできてくると思います。「もし」の条件を使った際に、「ずっと」を入れ忘れることがあります。そのことについて指摘すると、「あ、そうだ」的な反応があるので、その認識を高めていきたいです。「触れたら消える」のコードは自力で組み立てられていましたが、また始めると、「隠れた」ままなので、初期条件について「表示する」ことも教えました。 残りの時間は、３ｄコロコロをやりましたが、少し難しかったみたいです。', null, '時間帯: その他
タイピング: 速くできていました'),
  ('93321d6f-93e2-58c0-b192-c22578d42c34', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-12-13', null, null, '通常 / ３Dコロコロボール', 'ロブロックスをやるのかなと思いましたが、３Dコロコロボールが気になったらしく、かなり集中して取り組んでいました。いつものあおし君らしく、一人の世界に入って静かに集中していました。結果は、現時点で7位（２５８）というそこそこ良い成績でした。アレンジ等をすすめてみましたが、 今日は記録に挑戦したいということでしたので、来週は何かしらのアレンジ等できたらと思います。', null, '時間帯: その他'),
  ('a19a8f97-4810-574a-ac57-941360e02df5', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-12-13', null, null, '通常 / ゲーム大会', '今日はコンテストの3dコロコロを遊んで競いあっていました。最初は苦戦してほかのことに気が移りそうでしたが、はるたくんが目の前でハイスコアを出されると、それに追いつこうと、必死に取り組んでくれました。マウスで操作もなれてきて睦月くん自身もよい記録を出せるようになりました。', null, '時間帯: その他'),
  ('90645fdc-27b3-5ac7-8be3-895a485cd04d', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-12-13', null, null, '通常 / ゲームコンテスト', '最初は、コンテストのゲームを遊んでいましたが、難しく気がそれてほかのゲームに移っていました。そこまではまらなかったみたいです。そこから自分の作品を遊んで、時間が過ぎていきました。小技のことに触れようにとしても、今日はうまくいかな型tので、時間はアプローチを変えて取り組みたいと思います。', null, '時間帯: その他'),
  ('39134acd-187a-59e7-9697-e71fb1e1ce7d', '40a476bc-72a5-5bdc-ab75-e89d5310b442', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2025-12-13', '17:30:00', null, '通常 / コンテスト3D ボールコロコロをプレイする', '3Dボールコロコロをプレイしていたが、ジャンプ分岐の箇所が苦手のようだった。 合間にスプライトを自作していた。エビフライ成人、ミドリムシを作成。 スプライト作成時に、ドットでのキャラの作り方を楽しそうに話してくれた。', null, null),
  ('1b8ca03e-7b3f-541e-a7a8-fdaa75948b96', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-12-13', null, null, '通常', '今日は遊びデーでした。 コンテストのゲームもやってみたが、飽きられ、以前のジオメトリーダッシュを遊んでいました。それ以降、ロブロックスとジオメトリーダッシュで繰り返しで遊んでいました。 次回は、必ず教材を進めるようです。', null, '時間帯: その他'),
  ('5a5eae3a-b497-576b-9642-4b00a5c35fa1', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-12-13', null, null, '通常 / ロブロックス', '今日は、コロコロボーリングの途中からで確認問題を残してほぼ終わっていた状態でした。ただ、Robloxやるのはかなり久々っぽかったので、この章で覚えるべきことを説明して理解してもらった上で、確認テストに挑戦してもらい、次のハラハラピンボールに進んでもらいました。ハラハラピンボールに入ってからはわからないところはなく、スムーズにすすめていました。まだ、そんなに難しいところではないので、きちんと理解できているとは思います。', null, '時間帯: その他'),
  ('f0750c8a-ed01-5585-b2ee-8d1ade71a01e', '31feac25-f850-5d21-8e43-ed4d7badb6a0', null, '9975e2b1-2972-5720-830a-6de5deffeb24', '2025-12-13', null, null, '通常 / 小技day', '今回はコンテストの3D ボールコロコロをプレイしていました。マウス操作で遊ぶことに慣れていないそうで十字キー操作に改造して遊んでいました。タイルの色を変えて遊ぼうとしていましたが、うまく動かすことができず残念そうにしていました。全く同じ変更を自分の方でやってみたら普通に動いたのでなぜ動かなかったのかは謎です。最近はまっているらしく最後の5分くらいの時間はジオメトリーダッシュで遊んでいました。', null, '時間帯: その他
盛り上がり: 最後まで楽しそうにしていて、プログラムに軽い改変を加えたときにも楽しそうにしていました。'),
  ('a31dd885-b177-5a39-af92-70ef238cdfd7', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-12-13', null, null, '通常 / ロブロックス', '今日は憧れのマイハウスをほぼほぼ最初からスタートとなりました。スクリプトから色や座標といったプロパティをいじるようなプログラムを書くことがだいぶ多くなってきているので、そのくらいのスクリプト作成ならだいぶ慣れてきたと感じます。特に質問等なく、スムーズにすすめていました。もう少ししたら、難しくなってくるので注意して見るようにしないといけないかなと思います。', null, '時間帯: その他'),
  ('468017ba-408e-533f-bf86-e153de9894eb', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2025-12-13', '18:40:00', null, '通常 / コンテスト3Dボールコロコロをプレイ', 'コンテストの「3Dボールコロコロ」と「シップのジオメトリーダッシュ」をほぼ交互にプレイしていた。 3Dボールコロコロは終盤にスコアがあがってきて、ランクイン目前だったので集中してゲームをプレイしていた。 来週にはランクインできると思う。', null, '備考: 次週も3Dボールコロコロを集中してできれば、ランクインも可能と思う。 また、ゲームの構成、内容も説明もできるように準備をしたい。'),
  ('7d725d61-df0c-5909-b855-e8715b09716b', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-12-13', null, null, '通常 / ゲームコンテスト→イラスト', '最初にゲームコンテストとイラストどちらがやりたいか尋ねたところ、イラストがやりたいということで、iPadを渡してイラストに集中して取り組んでいました。イラストに関しては、本当にすごいアイデアが次から次へと出て、ものすごい楽しんで、かつ、集中して取り組めるようなので、本人的にとても合っているんだと思います。', null, '時間帯: その他'),
  ('629dd7d8-86f8-54f7-af7d-f29712f9dfea', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-12-13', null, null, '通常 / U16本戦プレゼン練習', '明日U16本戦なので、プレゼンの最終調整のようなことをやりました。いろんな内容を詰め込みすぎて、プレゼンの中で言いたいこと、重要な部分が、わかりにくかった印象がありました。なので、その辺を明確に伝えるように、プレゼン冒頭部分、最後の部分で、このゲームの目的、どんな人のために作ったのか？等、わかりやすく伝えられるような文言修正・追加を行いました。また情報を詰め込み過ぎなので、一部情報を削除するようにしました。最後に、皆の前でプレゼンをして微調整しました。うまくいくことを祈っています。', null, '時間帯: その他'),
  ('b0bcad1f-06e0-5d10-a490-4c467e8521b0', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-12-15', '16:30:00', null, '通常 / コロコロボールに使われる小技を確認しよう', '前回同様、最初はコロコロボールで遊んでいきました。1週間で、400点以上ととんでもないスコアを出されて、がぜんやる気になっていました。それで初めて2週目に入り、その勢いで、212点を出して大満足な様子でした。 ハイスコアが出たので、気分良くコード作成に切り替えができました。影武者で、幽霊や位置取りについてはゲームの内容と対応がよく取れていてスムーズ作成ができていました。そして、落下条件やゲームスタートのスコアの始まりの色判定も気づいていて勇作君をおいて供養に完成はできました。', null, '盛り上がり: やりこんでいき、2週目から本番顔で楽しくやっていまっした。'),
  ('9553f2fc-a44f-5a03-b4a7-b4a8f7972135', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-12-15', '16:30:00', null, '通常 / コロコロボールに使われる小技を確認しよう', '前回同様、最初はコロコロボールで遊んでいきました。今日ランキングを確認したら、自分の名前がなくて、入り込むようやる気を出していました。岳君がランクインすると、羨ましがるようにちょっかいをかけるようになりました。2週目もたどり着くようになったが、ランクインするには、まだ遠かったです。 コード作成に移ると、基本コードの見本を見せがら、なぜこのコードを使ったのか考えていきました。かけ武者の理解はぐできましたが、コースの始まりの色判定や落下判定はあまりピンとこなかったです。コードの流れをゲームと一つ一つ確認していけば、何とかなりましたが、順序の感覚が少し鈍かったです。 今まで見てきた感じ、 勇作君は自分で考えて一から作る方が好きで理解が入りやすいです、一方、岳君は見本から理解を深めるタイプな感じです。', null, null),
  ('5158aa18-cb1e-5867-be08-328eec8043dd', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '9975e2b1-2972-5720-830a-6de5deffeb24', '2025-12-15', '16:30:00', null, '通常 / 3Dボールコロコロ', '今回は3D ボールコロコロの初級のボールが落ちる判定の後半部分と中級の3D風に見せる方法の【小技】3Dの基礎 部分までを学習しました。前回作っていた色の判定がうまく動いていなかったのでなおそうとしたところ「かつ」「または」「ではない」の組み合わせの仕方に戸惑っていたようで、うまく動かせるようなるまでに苦労していました。', null, '盛り上がり: 一緒に3D ボールコロコロをプレイしていたところ自分が何点取れたかなどを話してくれました。'),
  ('3a865ac9-163b-59d3-a57b-7afb192e2619', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '9975e2b1-2972-5720-830a-6de5deffeb24', '2025-12-15', '17:30:00', null, '通常 / 3D ボールコロコロ', '今回は3D ボールコロコロの中級の3D風に見せる方法について学習しました。最初から最後まで黙々と遊んだり作ったりしていました。大きさの変更が3Dのような奥行きを表現するために重要であることをすぐに見つけたりなど内容を理解するのが速かったです。最後はアレンジに挑戦しようとしていました。最終的に電車のゲームで遊んでいました。', null, '盛り上がり: プログラムをアレンジすることは難易度が高く、途中で諦めていましたがやる気はあったようにみえました。'),
  ('7136835d-d84f-5b16-88eb-5421832410bb', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-12-09', '16:30:00', null, '通常 / コンテストのゲームから学ぶ', '検定のプレッシャーから解放されたからなのか、ゲームがメインだったためか、今日は終始機嫌がよさそうでした。祥太くんが振替できていて、会話ができるのも楽しかったのかもしれません。 ゲーム自体は難しいとか、なんだこれ、とか言いつつも、しっかりと今日のベストスコアを出して嬉しそうでした。 コードについては、1級を取得したこともあるので上級の手順書をすすめたかったのですが、今日は息抜きしたい気分（いつもですが💦）ということで、影武者のコードを少し復習し、あとはひたすら記録にチャレンジしていました。', null, '盛り上がり: ゲームがメインだったためか、久しぶりに機嫌がよさそうで、穏やかでした。'),
  ('8f4cab6e-9593-5d18-869b-115d81986f6c', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-12-09', '16:30:00', null, '振替 / ゲームを通して学ぶ', 'とにかく熱心にチャレンジしていました。コースについてもしっかりと分析して、左ルートがいい、などと結論づけていました。 影法師についてはさすがにすぐ理解できたようで、少しだけいじってみましたが、やはりメインは記録に挑戦、という感じでした。', null, '盛り上がり: 久しぶりの火曜日クラスで、楽しそうにしていました。誰とでもしゃべってくれて、スキルや理解力もあるので、良いムードメーカーになってくれました。'),
  ('b86237a6-9c08-52e5-a24d-574a410a3d49', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, null, '2025-12-09', '17:30:00', null, '通常 / 大原', '検定が当日受けられなかったということで精神面を心配していましたが、わりと吹っ切れた顔で検定代をもってきて、「次はいつ受けられる？」と聞いてきました。親御さんに言われたのかもしれませんが、とうきくん自身が次に向けて前向きになれていることに安心しました。 今日はゲームコンテストということで、プレッシャーもなく楽しそうにチャレンジしていました。 コードを見る時間もわりと素直に見てくれて、影武者のところを少しチェックしました。', null, '盛り上がり: 試験のプレッシャーがなくなったからか、久々にリラックスした感じでした。'),
  ('d87a3523-92af-54dc-bc76-5018b095a2e8', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-12-09', '17:30:00', null, '通常 / ゲームを通して学ぶ', '検定の結果を伝えると嬉しそうにしていました。 ゲームについても、しっかりチャレンジし、学習の時間は切り替えることができていました。 リストでタイルを作っているところを説明するとすぐに納得して、自分でアレンジを加えて楽しめていました。', null, '盛り上がり: コースのアレンジを楽しそうにやれていました。'),
  ('45450f8e-60b9-5aaf-8c90-f00612ffbedc', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-12-16', '16:30:00', null, '通常 / 3Dの小技を学ぶ', '今日も先週に引き続き、穏やかな様子でした。最初はずっとコンテストのゲームをやっていましたが、授業に切り替えるように促すと、「あと1回だけ」と言ってゲームをしてからきちんと切り替えていました。同じ机に次の授業のやすなりくんがいたのですが、そちらと先生の話に入ってきたり、作った作品を見せたりもしていました。 3Dの基礎は予想以上に面白そうに見てくれて、そのあと40分くらい、1から熱心に作り上げて、一つのストーリーのあるアニメーションに仕上げてくれました。 お話や場面の作り方が、以前よりもかなり丁寧になり、スプライトの動きにも工夫が見られました。', null, '盛り上がり: 作品作りにしっかりと集中して、楽しそうに作成できていました。ゲームに比べて自分が思うままに作り上げていきやすいアニメーション作りは好きなのかもしれません。'),
  ('7a637b12-23f4-545e-8098-79729e2d8703', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-12-16', '17:30:00', null, '通常 / ゲーム作品から3Dを学ぶ', '何度も繰り返し、熱心にゲームをして記録にチャレンジしていました。最終的に3位の記録が出せて満足気でした。 小技については、基礎も応用もすぐに理解できて、自身での作成とアレンジを楽しめていました。', null, '盛り上がり: 記録が出せたことが嬉しそうで、ニコニコと帰っていきました。'),
  ('7cde457d-3764-5ff2-bd55-9183626b44cc', '1da24088-9441-50c6-ac58-79e18ef5cc01', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-12-16', '17:30:00', null, '通常 / ゲームから3Dの基礎を学ぶ', '時間集中して取り組んでいました。ブレインロットの画像を使って3D風に見せるを行いました。ブレインロットとロブロックスが好きなようで、早くロブロックスをやりたいと言っていたので二級取得を目指して頑張りたいです。プラットフォーマー型のゲームの作成の続きも行いました。空中のブロックに乗れるように色に触れたらなどを利用して作成を行いました。', null, null),
  ('7079845b-3e76-52f9-8d46-639640d0e556', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-12-16', '17:30:00', null, '通常 / ゲームから3Dの基礎を学ぶ', '3Dに見せるの作成は特に難しい様子も無く20分かからずに終わらせることができました。後半は自分の好きなゲームを色々触って楽しそうにしてました。', null, null),
  ('9f230a13-b83f-558b-bc72-68e563d03c4a', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '39c367bc-400f-521c-85a3-5b6d9099f4a3', '2025-12-18', '16:30:00', null, '通常 / 3D小技', '数値の変更等で移動方向を変更、スプライトの変更などを行っていました。 特に詰まっている様子はなく30分足らずで完了していたのもあり、理解度合いは少し不安なところは残ります。', null, null),
  ('3deb6a3c-dc00-5abb-9479-8c77c193a9cd', '57f45872-1f3e-5540-b676-bf9023444e39', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2025-12-18', '16:30:00', null, '通常 / 3D小技', 'コンテストのボール転がしをプレイした後、ダウンロードした画像を背景とスプライトに使用して3Dの基本を作成しました。', null, '盛り上がり: 終了後るい君と同じゲームで遊んでいました。'),
  ('e90dde9e-ab38-5370-85ea-c5e6ff6a2ff8', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-12-18', '16:30:00', null, '通常 / 3dの見方を学ぼう', 'コンテストの３ｄコロコロの小技として、３ｄの視野を学んでいきました。コンテストには、なかなかうまくいかなかったので、すぐに作成に移りました。大きさの大小で遠近を表現をしていることはすぐに理解できました。次々と追加していったドラゴンのゲームには、この小技は入れにくかったので、別にバスケのシュートを作ってくれました。ボールを投げる山なりの動きがピンと来ておらず、ジャンプのコードの復習にもなりました。そこに大きさのコードを入れっていきましたが、投げている間に何度も大きさが変更していて、コードを入れる場所に苦戦していました。最終的には、きれいにパラメータを調整して、作れていました。', null, null),
  ('e72f46fd-dc4a-59da-ab9f-4ffe5efe6e69', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2025-12-18', '17:30:00', null, '通常 / 3D小技', 'ボール転がしをしばらくプレイした後、3Dの応用に追加する形で木やビルが手前に近づいてくるようなプログラムを作成しました。 途中、クローンの扱いや大きさを逆にしてしまうなどはありましたが、安定して作成できていました。', null, null),
  ('ed0033d2-811a-5599-a97e-df0ba8e49232', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '39c367bc-400f-521c-85a3-5b6d9099f4a3', '2025-12-18', '17:30:00', null, '通常', 'コード自体に変更は特に加えず、「と言う」を使って機能追加していました。 応用でも特に悩んでいる様子はありませんでしたが、中身をしっかり理解しているのかは少し不安が残ります。（コード追加して終わってしまったかも...）', null, '盛り上がり: スプライトのドアップで楽しんでセリフ追加していました。 呪術廻戦をめっちゃ見てるとのこと'),
  ('5cf70028-0446-5e3b-a1f3-d2ef5011c2e3', 'f3102a36-fdd8-574f-bf3c-85723faf424f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-12-18', '16:30:00', null, '通常 / 3dの見方を学ぼう', '最初はスクラッチのゲームから授業の切り替えができていないことが増えてきました。作成するとなったら、作ってくれますが、、、3dの道筋を見てから、バイクの運転視線を作ってくれました。見本のような動きがなかったですが、ただの背景の切り替えでした。そこからは後半はずっとコンテスト以外のもので遊んでいました。', null, null),
  ('a27f0c53-8179-539e-8ea5-ec7e2936f67b', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '39c367bc-400f-521c-85a3-5b6d9099f4a3', '2025-12-18', '17:30:00', null, '通常', '3Dのように見せる説明は口頭でもしっかり理解できていたと思います。 しかし、3D風を活かして作品を作るのは案が浮かばずかなり悩んでいました。', null, '盛り上がり: ネットミームで少し盛り上がっていました。'),
  ('62f8fa38-feb5-524f-9474-85afa03cf765', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-12-18', '17:30:00', null, '通常', 'コンテストのゲームは2週目がいくほどに上達していました。3dの基礎に移ると、動きの詳細は動くほど小さくなる、ことは観察できていました。そこから、自由作成では、リンゴが飛ばされるくれることを作ってくれました。大きさが大小を繰り返すことなく、徐々に小さくなっているを作れていました。背景では２D画が多くて、いいものがないと言って3dの感覚も育っていました。', null, '盛り上がり: 小泉構文で盛り上がっていました。'),
  ('72878f6e-5319-51c8-9779-f9250ce8d835', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-12-18', '17:30:00', null, '通常 / Excel検定対策', '教室に来たときは「疲れてる」と言っていましたが、自分から「検定の準備しないと」と言ってやる気を見せてくれました。 初めての本番形式の模擬問題でしたが、特に抵抗もなく進めていて、残り時間を10分残して61%の出来でした。 ・試験のときはExcelの画面が小さくなるため、メニューの文字が全部表示されずにスパークラインのメニューが見つからないなど、少しとまどいが見られました。 ・関数はほぼできていましたが、IF関数の条件式を思い込みでアレンジしてしまっていました💦式自体はわかっているので、問題をきちんと読めば大丈夫かと思われます。 ・スパークラインの設定をどこから出すのかわからなかったようです。スパークラインを選択して上のメニューから進むというのを教えました。 ・グラフのデータラベルの書式設定を、セルの書式設定からやろうとして困っていました。基本はすべて、問題の表の左端の書式設定からいくこと、表示形式もこちらから、というのを一緒に確認しました。 ・印刷の設定はあまりやったことがないというので、ページレイアウトのメニューとページ設定のメニューを確認しました。', 'どこが間違っているのか納得がいっていない問題もあったので、次回は少し一緒に問題を確認しながらやってみることにしました。', '盛り上がり: 危惧していたよりも合格点に近かったことと、時間内に解き終えたことが自信になったようで、なんとかなるかもしれないと喜んでいました。'),
  ('423f50c4-0b34-5f29-994d-d9bdbfcf8858', '512b2f12-24bc-5afa-913a-d68b4a9f9e14', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-12-18', '16:30:00', null, '通常 / Excelのグラフ作成とPowerPointの書式設定', 'シナモロールの紹介ページを作成する中で、以下のことを学習しました。 ・PowerPointの図形と図の違いと、それぞれの書式設定 ・PowerPointの文字の塗りつぶしや輪郭などの設定の出し方（文字を選択して右クリック） ・グラフのメモリラベルの書式設定', null, '盛り上がり: わからないときや混乱したときは素直に言ってくれるので、なるべくシンプルに、操作方法は一つにしぼって教えました。その説明を素直に聞いて、楽しく作成してくれていました。'),
  ('ef0646ff-d263-5bbd-8fed-9da53b0e1536', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, null, '2025-12-19', '16:30:00', null, '休み（未対象）', null, null, null),
  ('c4005929-e258-5977-a296-fb5fff0fa6b6', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, null, '2025-12-19', '17:30:00', null, '休み（未対象）', null, null, null),
  ('0c1a8672-b669-5c06-af87-c04f8347d1fb', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, null, '2025-12-19', '17:30:00', null, '休み（振替対象）', null, null, null),
  ('f0ac5186-f6d2-5b5f-8862-d359ac9a8425', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, null, '2025-12-19', '17:30:00', null, '休み（振替対象）', null, null, null),
  ('810d6931-516e-5526-a8fc-746e3dd7a858', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2025-12-19', '17:30:00', null, '通常 / Excel', '途中うとうとしてしまう場面もありましたが特に躓くこともなく時間内に完了することができました。', null, null),
  ('9398a89c-7fc8-5173-9638-b7d46bcc38e8', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2025-12-19', '17:30:00', null, '通常 / Excel', '途中COUNTA関数、絶対参照、グラフのフォントサイズ変更でつまっていましたが、集中して取り組めており、時間内に完了できていました。', null, '盛り上がり: 終了後3Dボールコロコロを楽しんでいました。'),
  ('4ba2b23e-7419-5f29-9d69-23c9cea765cb', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2025-12-19', '17:30:00', null, '通常 / Excel', '途中手が止っている感じもあり、あまり集中できていなかったように見えます、 進行も問題2の途中までで終了しました。 問題の内容は特に躓いてはいなさそうでした。', '模擬問題続き', null),
  ('25f79f63-c631-579a-b910-38ef702f0afa', '10db50c3-a153-502a-b455-c67362b9871c', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2025-12-19', '16:30:00', null, '通常 / 3D小技', '3Dの小技を参考にオリジナルのゲームを作成していました(あまり3D要素が見えませんでしたが)、集中して取り組んでいました。', null, '盛り上がり: 授業時間終了後も自主的に続きの制作に取り組んでいました。'),
  ('1761f44e-9438-5faa-8f4b-84b970a9c1ed', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2025-12-19', '16:30:00', null, '通常 / 3D小技', '始めに当たり判定の小技を完成品を見ながら作成し、その後、小技を使用してオリジナルの2Dアクションゲームを作成していましたが、あまり小技の仕組みをわかっていないかもしれません。', null, null),
  ('4bc8bb80-8c64-5c80-b880-efbfe5b59d46', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-19', '16:30:00', null, '通常 / コンテストゲームの関連スキル', '先週は3Dの仕組みを見ただけだったので今週は実際に作ってみました。タイルを配置する応用のほうで、スラボーをそのタイルに沿って動いていくようにできました。大きさや最前面といった3D再現の基礎を理解したうえでのアレンジができました。最後の方は少し時間が余ったので、しょうたくんが公開しているゲームをりょうまくんに遊んでもらっていました。そこでゲームクリアできないバグが見つかったので直しました。「タイマー>60」とすべきところを「タイマー=60」となっているのが原因だと気づいていました。', null, null),
  ('75fc194d-6ed9-599f-b161-c1b873fa7cb5', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-19', '16:30:00', null, '通常 / コンテストゲームの関連スキル', '先週の初級・影武者に続き、中級・3Dをやりました。授業前に遊んでいたホラーゲームを再現したいと言って、ホラーのキャラクターが近づいてくる3D作品を作りました。叫び声も録音し、しょうたくんと一緒にとても楽しんでいました。気に入ったらしく、最後はそれをアルスタジオで公開していました。', null, null),
  ('30b1cb48-32b7-56e0-a406-ba014c99b12e', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-19', '17:30:00', null, '通常 / Roblox', '前回に引き続き、広いステージに地形を作っていきました。途中、前回言っていた「歩くスピードを上げたい」を実現するため、humanoidオブジェクトを扱い、walkspeedプロパティを変えてみました。他のプロパティについても紹介したところ、jumppowerも変えました。', null, null),
  ('9e066d6b-6a35-5728-a71c-9ac4bc5aac2e', '5fc65a36-fdbb-5af5-a6f4-16080e4e37ef', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-19', '17:30:00', null, '通常 / 基本操作コース', '・キーが押されたとき回転して色を変える ・あちこちに移動する をやりました。キーの名前をあまり聞いたことがなかったようなので、スペースキーを使って覚えてもらいました。「あちこちに移動する」では、前回までに習った座標の移動をきちんと覚えていて、それを使って解決しようとする姿勢が見られました。ただ、瞬間移動ではなく滑らかに動かすために新しいブロック「～秒で座標を～にする」が必要だったので習得しました。この単元の全てのスタンプを押し、達成感を感じながら終わることができたようでした。', null, null),
  ('8e459c13-78a7-5f3f-8931-b92ec9c36698', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-19', '18:40:00', null, '通常 / コンテストゲームの関連スキル', '初級から超上級まで全体的にやることができました。影武者や3Dの概念はスムーズに理解し、自分の手で再現できました。超上級では、リスト「タイル」の中身を変えるとコースが作れることを紹介すると、ジャンプ台をたくさん置くなどして自分の好きなコースを作っていました。', null, null),
  ('0dd06335-c612-58a8-a110-06838b591eef', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-12-20', null, null, '通常 / イラスト→ロブロックス', 'イラスト先生おやすみにより急遽ロブロックスへ変更。ハラハラピンボールを黙々と集中してすすめていきました。まだ難しくなる前のレッスンなので、質問も特になくスムーズにすすめていました。イラストのポストカードを渡しましたが、嬉しそうにしていました。ホワイトボードにも貼ってもらいました。', null, '時間帯: その他'),
  ('1d9b0bdc-1ce0-5b3e-bc1f-1914131e1ae2', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2025-12-20', null, null, '通常 / 3D小技', 'コンテストをプレイ後、3Dの基礎の小技を作成しましたが、あまり集中できていなかった感じがあります。 その後、試験の結果を聞いてやる気をだしてくれたようで、前回の小技作品の続きを作成していました。', null, '時間帯: その他
盛り上がり: 試験の合格を教えると、とても喜んでいました。 制作意欲が湧いたようです。'),
  ('a9219dda-fc2f-5db5-bbc4-3a0360cfc3af', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-12-20', '16:30:00', null, '通常 / ロブロックス', 'ロブロックスでのやれていなかったハラハラピンボールの確認テストをやっていきました。 まだ基本的な内容ですが、透明度や当たり判定のコードについて忘れる感じでした。2か月ぶりくらいに見るコードなので、ゆっくり学んでいきたいです。人手が増えた見る暇があるので、 未来へのジャンプは、座標のコードだったのですんなり進められました。', null, null),
  ('2c700438-9a4b-50e2-9c91-9422382954da', '40a476bc-72a5-5bdc-ab75-e89d5310b442', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2025-12-20', null, null, '通常 / ボールコロコロ小技', '影武者の小技を始めますが、他のものに目移りしてしまうことが多く、なかなか前に進みませんでした。 適度に起動修正してあげることで完成させることができました。', null, '時間帯: その他
盛り上がり: アレンジとして、逆に星に触れていないとスコアが下る、ゲームオーバーの文字を追加するなど追加していました。'),
  ('97054b39-3f15-5694-8674-279358542334', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-12-20', null, null, '通常 / イラスト→ロブロックス', '前回の続きで憧れのマイハウス、このレッスンでは、スクリプトで物体の位置を上下左右に動か自動ドア・エレベーターを作ったりしますが、座標移動の処理はきちんと理解しているようで問題なかったです。今日はその部分がわからなかったらフォローしてあげなくちゃと思っていましたが、全然フォローの必要がなくてスムーズにすすめられました。', null, '時間帯: その他'),
  ('80ca8373-2592-5da3-b917-c03b9ec4a952', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-12-20', '16:30:00', null, '通常 / 小技を習得しよう', '先週のコンテストのモチベの低さががあったので、いきなり小技を作っていきました。その前の、触れてスコアが増えるや上下っ左右の動きは問題なく作れていました。影武者の肝である「幽霊効果」は知らなかったみたいなので、学びになりました。その後、アレンジをしてよいよと、しましたが、音やスプライトどまりになることが多かったです。背景にUFOが飛び回っているとかのアイデアはよかったですが、「どこかへ行く」のコードに頼り切っているのが選択肢として乏しさが感じられます。 なので、もう1周基本操作コースからPRGのゲームのつながりを細分化をした方が、経験が詰めるかもしれない。案です', null, null),
  ('79e66002-12e0-50bb-860c-5ef815cb0879', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-12-20', null, null, '通常 / エクセル', '前回模擬問題でうまく解けなかった部分の復習ということで、３０時間６章のグラフ問題と、８章RANK.EQの問題を解きました。６章の部分に関しては、わかるんだけど、時間がかかってしまい、最後まで解けなかったというふうに言っていたので、今回は、スピード感を持って素速く回答する事を意識しつつ復習してもらいました。６章については特に質問等なかったですが、RANK.EQは問題の読み間違え（降順でランキングしなきゃいけないのに、昇順で答えを出して、答えが合わない）で、だいぶ悩んでいましたが、その点を指摘して納得してもらいました。', null, '時間帯: その他'),
  ('33e9d6fa-ed50-5b38-9f43-145797b975fd', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-12-20', null, null, '通常 / ロブロックス', '一人で黙々と進めていて、何か質問ないと聞くも「ない」との返事だったんだけど、具体的にこちらから乱数生成の方法わかる？と聞いたら「わからない」ということだったので、細かいところを質問するということを躊躇しているのか、そんなに大きな問題じゃないから、スルーして進めているのか。その辺はよくわからないですが、ひとまず、乱数生成の概要レベルの話を説明しました、細かいこと言ってもまずわからないので、 「そのまま覚えるしかないし、何回も乱数生成を使っていると慣れてきて、理解は後から追いついてくるもの」みたいなことを言っておきました。ただ、何かわからない、もやもやしているだけでもいいから、質問してほしいなということもあわせて伝えました。', null, '時間帯: その他'),
  ('2bc34c8a-b8e7-55a2-8bf4-b9af722e0b61', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-12-20', null, null, '通常 / ゲームコンテスト', 'レッスン開始前に、自分の自作ゲームをいじっているのでそれを聞いてみました。U16が終わったばかりだというのに、別のオリジナルゲームを作り始めているようでした。何かサボテン（？）とか植物かなんかの成長シミュレーションゲームっぽいのを作り始めたようでした。今日は、少し息抜きでゲームコンテんすとに参加を促してみたら、普通に参加してくれて、結構ハマっていました。だいたいランキング13位くらいまでになっていました。それと、３Dコロコロの超上級のところ、エクセルでコース作成、CSV保存でそれをスクラッチのリストに取り込む部分を説明したら、かなり興味深く聞いてくれていました。そして、検定１級も１００点だし、今後の話を雑談レベルでしてみたところ、ロブロックスよりは、幅広く色々できそうなJava Scriptがいいなという話でした。また、途中、どっちがpythonの学習に有利になるか？みたいなことも言っていたので、pythonにも興味津々なんだと思います。', null, '時間帯: その他'),
  ('93f7903c-38c8-596f-a55d-bec0f4450790', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2025-12-20', null, null, '通常 / 3D小技', '前回小技を作成していたため、バスケットボールをシュートするプログラムの作成を行ないました。 見本の曲線でシュートするプログラムは作成しませんでしたが、ジャンプの小技のプログラムを参考に、上にトスするプログラムを作成しました。', null, '時間帯: その他'),
  ('4a94c722-7866-5fa1-829f-c8db7370d8ac', 'dbe3dbc6-eb44-5cf8-b4f8-2bf2348e73cf', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-12-20', null, null, '通常 / 小技習得', '始めに、コンテストを遊び、マウス操作に苦戦していました。そこで使われている小技の影武者について、どんなコードで作られていそうか聞いたところ、できそうとのことだったので、ノーヒントで作ってみました。当たり判定の紫のロボットの背面にかぶせることで対処していました。幽霊効果については知らなかったそうで、よい学びの機会になりました。そのあと、家で作っている自分の作品について教えてくれました。マリオ形式のアクションゲームを作っており、壁にめり込んでしまうバグで困っていました。背景スクロールとプレイヤーが両方動きが作ってあり、歩数の違いからめり込んでいました。そこで、歩数を合わせてそこは対処しましたが、そのあとに、背景足場だけを動かして動いて見えるような仕組みを教えました。最初は何を言っているんだと理解がピンと来ていなかったが、実際のマリオのゲームと比較して観察してもらったら、理解してもらえました。 また、大富豪のゲームと作りたいのことだったので、リストの使い方なども整理した挙げると良さそうです。', null, '時間帯: その他'),
  ('3beb63f7-5fed-544a-b7ae-e96e458175f3', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-12-22', '16:30:00', null, '通常 / オリジナル作品制作', '今年最後の授業のため，本人が作りたいものを作っていきました．赤い線に当たらないようにキャラクターを端まで移動させていくゲームを作成しました．左右への移動やジャンプの方法，クリアやゲームオーバーへの条件など今までの復習も兼ねていきました．この時間だけで完成まで持っていくことができ，復習内容についてもしっかりと身についているようなので，この調子で来年も取り組んでもらいたいです．', null, null),
  ('2889c510-984a-5031-91ce-a73f492428ef', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-12-22', '16:30:00', null, '通常 / オリジナル作品制作', '岳くんと一緒にPKゲームを作っていきました．サッカーをやっていることもあり，自身の知識や経験から様々なアイデアを出して楽しそうに作っていくことができていました．キャラクターの向きやゴールへのシュート方法などについて話し合っており，コードについても試行錯誤しながら作成を行っていきました．今回だけでは完成させることができませんでしたが，機会があれば続きもやっていきたいとのことでした．', null, null),
  ('6c9a8b3b-57a2-5136-b063-9cd9192815b7', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-12-22', '16:30:00', null, '振替 / 自由制作', '今回は自由に制作予定でしたが、前回の様子からの予測通り、好きなキャラをネットサーフィンをして、持ってきたところでだいぶ時間がとられていました。そこから、何をコードで作りたいか？聞いてみてもバスケシュートと答えることはできるが、作成にはなかなかつながっていませんでした。コードを作っている様子はうかがえたが、授業終わりに作品を見ると、コードが残っていなく何をしていたか把握できてませんでした。', null, null),
  ('e6ca1f4d-7c16-5e1f-9785-33bd6384484b', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-12-22', '16:30:00', null, '通常 / オリジナル作品制作', '勇作くんと一緒にPKゲームを作っていきました．今年最後の授業なので，最近の検定や3Dボールで指示された内容を多く作っていたため，今回のオリジナル作品制作でリラックスすることができた様子でした．二人で作っていることもあり，様々な意見が出ていたのでこういった機会があると今までに学んだことをアウトプットしていく場面として友好的なのではないかと思いました．作品の完成までは行けませんでしたが，次にオリジナル作品制作の機会があれば続きから初めていきたいとのことでした，', null, null),
  ('8a1ea966-5eb2-5393-9f85-2b491ebcfaa6', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-12-22', '16:30:00', null, '振替 / コンテスト小技', 'コンテストの小技の超上級について考えてもらいました。リストに関しては、まだなじみがなく、ノーヒントでコンテストの作品を理解するのは、厳しかったです。そこで、部分的にコードの解釈(コードのコスは番号分けされている、真ん中の道は3番目の数字を読み取っている、なぜ最初は111111なのか)を伝えると、そこぞれのヒントを自分で結びつけて理解することができました。その後は、アレンジをゆだねて、コースについていじってくれました。', null, null),
  ('6e2681cc-f333-5f05-863c-79f6afe5255e', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-12-22', '17:30:00', null, '通常 / オリジナル作品制作', '以前に作成したPrg21 アイテムで脱出をしよう！を自分なりにアレンジしていきました．デザイン部分にこだわって作成していたようで，以前の大会で使用した電車のスプライトをさらにアレンジしていき，より高い精度のものにしていました．楽しみながら作成することができていたようで，作品の出来に満足していました．', null, null),
  ('a0ca712e-b480-58ec-a0be-e4ae4bc889c1', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2025-12-20', null, null, '通常 / ゲーム大会', '3Dコロコロに集中して遊んでいました。ランキング入りをして満足したようで、もう1件開催されていた「シップのジオメトリーダッシュ」も遊びました。こちらはまだ操作に慣れていないせいか難しかったようです。3Dコロコロの当たり判定についても【小技】影武者を少しいじって理解できたようです。', null, '時間帯: その他'),
  ('b59294f0-e05a-5ab1-8407-b39a3aa0ef41', '31feac25-f850-5d21-8e43-ed4d7badb6a0', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2025-12-23', null, null, '通常 / ゲーム大会', '3Dボールコロコロ、今回もマウス操作が苦手なので矢印キーに変えてゲームをしました。そのあとは、ゲームをリミックスして落下をなくす、スピードを速くするなどのチート化を進めてゲームの内容を確認していました。 【小技】影武者で当たり判定も理解ができたので、3Dボールコロコロの当たり判定を実際につくってもよさそうです。', null, '時間帯: その他'),
  ('a529c7ad-545f-54da-ae66-7de35e048829', '0047fb11-a84a-5592-8c39-5a16c20eb10e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-20', null, null, '振替 / コンテストゲームと関連スキル', 'イラストコースの休講でプログラミングに振り替えました。コンテストゲームをしばらく遊んだ後アレンジに入りました。スクラッチに触るのは久しぶりながら、超上級のリストを使ったコース設定に挑戦していました。そのリストはどういう意味なのか、リストを読み取るタイルのコードはどういう意味なのかを真剣に考えていました。最終的に、リストの内容をいじってコースを変えてみることで、気づきを得て仕組みを理解しました。ジャンプ台を表す"3"を増やして、ジャンプが多いコースにするなどして楽しんでいました。', null, '時間帯: その他'),
  ('00a7b408-adc7-59db-9322-d6a07d7eec42', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-20', null, null, '振替 / コンテストゲームと関連スキル', 'イラストコースの休講でプログラミングに振り替えました。最初は自己ベスト更新を目指して遊び、目標の100点に到達すると喜んでいました。そのあと、ボールが少しだけはみ出ても落ちない理由について問いかけると、「ボールの半分ぐらいだけ判定をつけている」という仮説を立てることができました。そこから、元のボールから大きさを変えた影武者の考え方にスムーズに移れました。実際に影武者を作成している途中、影武者が奥の層に置かれていたため当たり判定が機能しませんでした。そこで、イラストでも使うレイヤーの考え方から、最前面/最背面の設定を思い出してもらいました。最終的に完成させて終わることができました。', null, '時間帯: その他'),
  ('b99b2847-24a4-514c-90eb-e9dce2967723', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-12-20', null, null, '振替 / コンテストゲームと関連スキル', '前半はスコアアップを狙ってコンテストゲームを楽しんでいました。後半は影武者を扱いました。ゲームオーバーになったとき判定用ボールが少し見えるので、ボールを分けているのは把握しているようでした。そこで、なぜわざわざ分けるのか考えてもらいました。元のボールでそのまま判定もした場合を考えると、少しはみ出たときにすぐアウトになってしまうことに気付くことができました。影武者の作成自体は、幽霊効果を既に知っていたのもあり、かなり自力で進められました。', null, '時間帯: その他
盛り上がり: 検定4級の合格証を渡したとき、バッジや紙という形として残ったのもあったのか、とても喜んでテンションが上がっていました。'),
  ('42f25fbf-903c-5808-b1d4-1a89702d9cdd', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2025-12-20', null, null, '通常 / バスケットボールでシュートをする、3D小技を作成した。バスケットボールのスプライトを作成して満足しているようだったがゴール、落ちてくるバスケットボールの受け、音楽をつけて全体像を完成させた。 また、ロボロックスをやりたいと言っていたので今後の検討が必要と思います。', null, null, '時間帯: その他'),
  ('9bf24534-d36c-57c9-a1fd-656c3e9e1361', '2758b49a-c2b1-5cd0-9b37-3b988f2a5a09', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-01-12', '16:30:00', null, '振替 / くじ引き大会', '前回の授業から1か月も秋、歴も浅いので、最初からくじ引きをやるのではなく、復習をやりました。左右の動かし方、変数の使い方などを復習しました。そして、次につながる、変数のサイコロについても学びました。乱数という言葉は知らなかったが、さいころのランダム性について触れらたら、理解できたそうです。 後半に久慈のエラーについてやっていきました。レベル1の問題は、やりがちなケアレスミスな問題なので、歴が浅いいとちゃんは気づくか難しいラインでした。右キーを押しても動かないエラーでは、「すべて」が抜けていることに気づくことに時間がかかりました。特に1から5までをカウントする問題では、繰り返しの中の変数の増え方戸惑いました。コード上だけではわかりづらいだろうとモノで変数箱の考えを共有したが、まだ難しそうです。全体的にも本人は難しく感じていたので、まずは基礎形成が先にした方がいいです。', 'エラーorチーズを探せ！', null),
  ('7b758b14-74e7-5322-8bef-d45296e87a31', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-01-12', '17:30:00', null, '通常 / バグつぶしとくじ引き大会', 'ロブロックスの予定でしたが、他の人のようにくじ引きがしたいとのことでエラーで学ぶスクラッチをやりました。検定1級まで受かっているので、一番高いレベルをやってもらいました。久しぶりのスクラッチだったため、複雑な条件分岐のコードを読み書きするのには少し時間がかかっていました。ただ、「～ではないまで待つ」などの大事なポイントは記憶に残っていたようでした。くじで取った駄菓子を食べて楽しんでいました。', null, null),
  ('23071ed3-049e-565a-b0fa-8d9ba87e5151', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-01-12', '16:30:00', null, '通常 / バグつぶしとくじ引き', 'こうすけくんと同じ問題を解き、競うように進めていきました。ペンやスタンプなどは初めて使ったので基本は説明しましたが、「スタンプした後に動けばいい」と言ったアイデアは思いつけていました。「りんごとバナナ」ブロックも初めてでしたが、数字の足し算と文字の結合の違いはよく分かっていました。 当たりよりむしろハズレの駄菓子のほうがいいと言っていて、実際に駄菓子をゲットして喜んでいました。', null, null),
  ('7f9039cb-2eb6-50f9-8465-1634cae38923', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-01-12', '16:30:00', null, '通常 / バグつぶしとくじ引き', '変数がおかしくなるタイプのバグは、変数の中身を表示してもらうと何がおかしいのか気づくことができました。検定の時に勉強した、セリフを消す方法もきちんと覚えていました。全体的に、試行錯誤して答えにたどりついていました。ゆうさくくんと偶然同じ問題を解いていることが多く、それを面白がりながらやっていました。 くじはハズレでしたが、「小さい駄菓子2つ」の中で比較的大きいお菓子を見つけてお得な取り方をしていました。', null, null),
  ('d823acec-fbe8-52ca-992c-496f1fb26e33', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-01-13', '16:30:00', null, '通常 / バグ探しクイズにチャレンジしてくじ引きをする！', '読解力を要する問題は苦手なようで、レベル的にも経験的にもできるはずの変数の入れ替え問題で躓いていました。箱を使った実践で、意味は理解したようでしたが、それを「箱●を箱〇にする」という言葉に置き換えると混乱するようでした。モチベが一気に下がりそうだったので、この問題はほぼつきっきりでサポートしました。 不等号や条件式などの分野においては、さすがによく理解できていて、スラスラと解いていました。算数だけならそれほど苦手意識もないようです。 40分ほどでレベル②を解き終わって、くじ引きをしましたが、今日はここまででいいとのことで、残りはのんびりゲームをしていました。 駄菓子の大を1つ選んで持って帰っていきました。', null, '盛り上がり: 最初に躓いたときはちょっと怪しい雰囲気になりましたが、そのあとは比較的スラスラ解けて、自信を取り戻したようでした。卒業が近づいてきて、学校も忙しいと言っていました。'),
  ('1c841dcc-dfb4-5a10-b326-d19e64fca6a8', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-01-13', '17:30:00', null, '通常 / バグ探しクイズにチャレンジしてくじ引きをする！', 'レベル②の問題は、最初の変数の入れ替え以外はさすがに余裕があって、どれもほぼすぐにエラー箇所に気づき、直すことができていました。 変数の入れ替えについては、同時処理ができないことを箱を使って説明したら、すぐに理解して残りは自力でできていました。 「右に消える」問題では、「より大きい」を「以上」と勘違いしていて座標を設定していたので、そこを指摘しました。 条件分岐の問題では、判定する順序が重要なことを説明すると、理解できたようでした。 レベル③にも意欲的に取り組んでいました。座標の四捨五入とペンツールについては初見だったようなので説明を入れましたが、よく理解できていました。 残りあと2問！と嬉しそうに授業を終えていました。', null, '盛り上がり: 検定の合格証を嬉しそうに何度か取り出して見ていました。 これからロブロックスをやっていきたいそうです。'),
  ('e2bf7048-9018-58a5-bd1d-dc207c016228', '1c7005cc-2815-558f-993a-9c7617d34c44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-01-13', '16:30:00', null, '通常 / バグ探しクイズにチャレンジしてくじ引きをする！', '時間内に全て終わらせることができました。ブロックを入れる順番を意識して行うことができました。ペン機能が楽しかったようで何度も繰り返し実行して遊んでいました。 （大原補記） 全体的に、ゆうたろうくんの現在のレベルでは自力で解くのは難しかったので、どういうところがおかしいのか、どうすれば直せるのかを考えてもらい、そのコードを教えるといった感じで進めていきました。説明はよく聞いていて、一問解けるごとにスタンプを押して、最後まで集中して取り組むことができていました。', null, '盛り上がり: くじびきは外れでしたが、大きいお菓子を一生懸命選んでいました。お母さん曰く、とても嬉しい時の表情だったそうです。
備考: お母さんが、最近学校に行けていなくて気分も下降気味なのですが、教室では大丈夫でしたかと心配されていました。教室ではとても意欲的に取り組めていて、今日もきちんと課題を終わらせるまでたち歩きもなく、集中できていたことをお伝えすると、少し驚いて、ほっとされたようでした。'),
  ('2f98d02b-2705-56c1-a062-b444b60eaada', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'd45d6c5d-18cd-5aa2-99ea-932c81442c55', '2026-01-13', '17:30:00', null, '通常 / バグ探しクイズにチャレンジしてくじ引きをする！', '途中正攻法とは違うやり方をしつつも余裕を残して30分かからずにエラーで学ぶ①を終えられました。 ②は算数の計算問題(台形、和、積、以上未満など)に戸惑い苦しんでいましたが終わらせることができました。電卓があまり使い慣れていないようだったので、別の方法で算数の問題のヒントを出してあげると良いと思いました。', null, '盛り上がり: （大原補記） 耳慣れない言葉などが出てくると一瞬だらけそうになったりもしましたが、終わらせたいという意欲が強く、時間ギリギリまで頑張って問題2つ分をクリアしていました。 くじ引きはどちらもはずれでしたが、お菓子を4つ選んで嬉しそうでした。
備考: Suicaのチャージ用に1000円お貸ししました。'),
  ('7b30fbda-63ee-5fc7-8164-ea491012ae09', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-01-15', '16:30:00', null, '通常 / くじ引き大会', '最初は困難簡単じゃんと余裕に解いていきました。半角、全角の問題では、見た目的に変化は気づきにくいので、困っていたが、数字打つときに先生なんといつも言っていると助言してあげることで、気づいてくれました。30分もかからずに、レベル1が終わったので、レベル2にも挑戦しました。変数の入れ替えに対しては、だいぶ頭抱えていました。途中、ほんとに自分でやったのか審議なところはありますが、最後のくじ引きの問題は、たかひとくんのフォローもありクリアできました。', null, null),
  ('f4a7feda-e116-5051-a42f-b295f5337b86', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-01-15', '16:30:00', null, '通常 / くじ引き大会', 'レベル②については、不等号に関する問題が多く向き違いに悩ませることがあったが、後半は注意してみてくれるようになったので、自らノーヒントで解ける問題もありました。レベル3に移ると、あともう少しの場面が増えました。マウスのクリックでは、「何秒」待つを入れて、できたとしても長押しの可能性もあったりして、頭を悩ましてくれました。けど、ある程度知識がついているので、試行の手を止めずに解答にたどり着くことが多かったです。', null, null),
  ('c0314ef9-fb7f-523e-9989-6994ee667023', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-01-15', '17:30:00', null, '通常 / エラー直し', 'レベル1問題では台形の計算問題でつまづいていましたが、計算式を教えることで解くことができました。 また、変数の入れ替えも新しい変数を作成する必要なことを教えることで進めることができました。 終盤は集中力が切れ気味でしたがレベル2の途中まで進めることができました。', 'レベル2の続き', '盛り上がり: くじ引きでは小のお菓子を当てており、うれしそうでした。'),
  ('36b376f5-14aa-5690-9aa6-94e7208f099d', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-01-15', '17:30:00', null, '通常 / くじ引き大会', '考えが煮詰まりすぎる傾向が多かったです。変数の入れ替えは考えはしっかりしているものの、コードが過剰に多かったり、別解で正解になるものが多かったです。詰まった問題では、元の原形のコードがなくなったりしていたので、最初に戻してリフレッシュすることも進めました。条件分岐系は範囲はしっかり考えられているので徳の速かったです。', null, null),
  ('82ede6f1-c823-5c97-b3e1-3936f3ed8fd6', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-01-15', '17:30:00', null, '通常 / くじ引き大会', 'かなり早く来たので、早めにレベル1から始めました。レベル1はよくありがちなミス系の問題が多かったが、スムーズに解き終わることができました。だが、そこで集中力が切れて、レベル2ではミスがあと1ぽな場面が多かったです。特に、不等号の向きは必ず反対の方を選びがちで、もう1つの存在を忘れるほどでした。こちらからのヒントもあって、以上未満の言葉はよく解けていました。', null, '盛り上がり: 大×３を2回も引いて羨ましがられていました。'),
  ('ba6dc8f8-e2b5-568b-b98c-3b836637a0fc', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-01-15', '16:30:00', null, '通常 / エラー直し', '始めにレベル1に取り組みますが、''1~5までの数を言う''の問題で、わからないとごり押しで解決に進んでしまうところがありました。 ときどき軌道修正してあげることでレベル2のまで終らせることができました。', null, '盛り上がり: くじ引きのお菓子をあててうれしそうでした。'),
  ('de8f8c5a-9473-5ae7-9877-3bf2b2e72415', 'f3102a36-fdd8-574f-bf3c-85723faf424f', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-01-15', '16:30:00', null, '通常 / エラー直し', 'レベル1から始めますが、基本的につまづかずに進めれていました。 とてもやる気をもって取り組んでおり、授業時間終了後もレベル3に取り組み、最後まで終らせていました。', null, null),
  ('680a3f63-96fc-550d-b405-7ae8610ef7c1', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-01-16', '17:30:00', null, '通常 / エラー直し', '途中から見ましたが、レベル2から取り組んでいました。 途中、以上、未満の判定、1~10までの和の問題文理解で躓くことはありましたが、サポートありで完了させることができました。', null, '盛り上がり: レベル2終了後、残り授業時間10分からレベル1問題を終らせ、くじを二回引くことができてうれしそうでした。'),
  ('ee76ec11-777e-5a5c-8cd0-b95dd537afef', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-01-16', '17:30:00', null, '通常 / エラー直し', '途中から見ました。 レベル3から始めたようで、とくにサポートがなくてもスラスラと進められていました。 レベル3終了後レベル2にも取り組み、こちらもスラスラと進めていました。 レベル2終了後も時間がありましたが、レベル1はさすがに簡単すぎるということで自由時間でけいとくんを見守っていました。', null, null),
  ('439285a9-f90f-505d-9269-60c3b860bcb7', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-01-16', '18:40:00', null, '振替 / エラー直し', 'レベル1から取り組みました。 台形の面積、1~5までの数を言う、で少しつまづきますが、面積計算の公式を説明すると思いだしたようで解くことができました。 また、スタンプの問題ではこう先生が実際のスタンプで説明することで解けていました。 それ以外の問題は基本問題なく解けていました。', null, '盛り上がり: さかなマークのマウスよりもザリガニのマウスのほうが使い易いと話していました。'),
  ('bad65d5b-aaa5-5734-b741-adbf0b7d1611', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-01-16', '16:30:00', null, '通常 / バグつぶしとくじ引き', 'レベル①からやりましたが、基礎が身についているので「簡単すぎる」と言ってすぐに解き終わりました。くじでは駄菓子(大)３個を当てて、ラーメンよりも良かったと喜んでいました。レベル②も比較的すらすらとできて、難しい「変数の入れ替え」も、３つ目の変数を使うというヒントだけ出すと変数の動きをすぐに整理して解けていました。', null, null),
  ('25674e87-1182-5a6b-82fd-ea5111c44f8b', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-01-16', '16:30:00', null, '通常 / バグつぶしとくじ引き', 'くじを引きたい一心で頑張っていました。レベル②の変数の入れ替えでは、「変数Aを変数Bにする」という文の意味を勘違いして混乱していました。(変数Aの中身を変数Bに移すという意味だと思っていました。)その誤解を解きつつ、具体的に箱と消しゴムを使って変数の動きをイメージしてもらいました。くじでは一等の大きいチョコパイを当てて喜びを爆発させていました。しかし、時間が足りないながら「さらにくじを引きたい」とレベル③まで途中まで手を出していました。', null, null),
  ('259848a0-151c-51a4-8f9a-f248d5f0dd95', '10db50c3-a153-502a-b455-c67362b9871c', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-01-16', '16:30:00', null, '通常 / エラー直し', 'レベル2、3、1の順番で取り組みました。 どの問題も基本的に躓かずに取り組めていましたが、ときどき自己流の方法で突き進んでしまうところがありました。 授業時間が終ったあとも取り組んで全ての問題を解ききることができました。', null, '盛り上がり: 階乗の計算ブロックに興味がわいたようでしばらく遊んでいました。 また、レベル3の記憶ゲームを数字の範囲を増やすなどアレンジを加えていました。 くじではラーメンを当ててよろこんでいました。'),
  ('f02a7d81-c1ea-5256-95ae-7971c998a954', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-01-16', '17:30:00', null, '通常 / バグつぶしとくじ引き', 'Robloxよりscratchのほうがやる気になったのでそうしました。問題文の日本語の意味を読みとるのに少し苦戦していました。「1から10までの和」を、1から10までの乱数を足すという意味だと認識したりしていたので、「順番に」足していくというイメージを説明したところ納得したようでした。コードの組み方自体は比較的できていて、繰り返しや不等式のバグの内容は理解していました。', null, null),
  ('6564eb3a-ac50-525b-90c6-9e39b412294d', '5fc65a36-fdbb-5af5-a6f4-16080e4e37ef', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-01-16', '17:30:00', null, '通常 / 基本操作コースを進める', 'キャラクターに様々な動きをさせるレッスンをしました。既に習った範囲はよく記憶していて、「～秒で座標を～にする」を使いこなしていました。今回はそれにランダム性を加えた「1秒でどこかに行く」を扱い、使い分けも理解できました。「滑るように動く」の項目では、「旗を押す→初期位置に瞬間移動→目的地にだんだん移動」という動作でしたが、最初はブロックを置く順番が入れ替わっていました。ここで、旗を押してからの時系列で考える練習もできました。 また、太陽の動きはゆっくりと、バスの動きは素早くというように、リアルな挙動を再現しようと頑張っていました。', null, 'タイピング: 熱心にやっていました。
盛り上がり: 今日のテーマ(キャラクターの動き)について「こういうゲームを作ってみたい！」と完全に興味を持っており、授業時間が終わっても自主的に進めるほどでした。'),
  ('4f5f12ec-87ac-59c3-98a8-05c5502c3038', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'f8ed407c-471f-52b9-9a31-249d9595d863', '2026-01-16', '17:30:00', null, '通常 / エラーで学ぶレベル①', 'レベル2から取り組んでいたが、ある程度一人で解けていた。レベル1のスタンプの問題で少し手こずっていたが軽くアドバイスするとすんなり解けていた。レベル1,2どちらも時間内に終わっていた。', 'エラーで学ぶレベル③', '盛り上がり: 景品のおかげか、やる気満々だった'),
  ('4db8c2ce-0689-5ff9-a35c-07d493587ec4', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'f8ed407c-471f-52b9-9a31-249d9595d863', '2026-01-16', '17:30:00', null, '通常', 'レベル1から手こずっていた。先生がつかないと集中力がすぐ切れてしまい他の友達のところへ遊びに行ってしまった。わからないところでむしゃくしゃしていた。レベル1は全てクリアできていた。', 'エラーで学ぶレベル②', '盛り上がり: くじが引けるのでいつもより頑張っていた。'),
  ('018e371b-b09e-53e3-b6d3-807aa1120786', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'f8ed407c-471f-52b9-9a31-249d9595d863', '2026-01-16', '16:30:00', null, '通常', 'つきっきりで指導するとスイスイ進んでいたが一人でやらせると詰まってしまった。台形や、未満以上などの学校で習っていないところで頭を抱えていた。レベル②になった途端減速した。', null, '盛り上がり: 周りより遅れながらもくじを引けて嬉しそうだった。ラーメンが当たったら僕に分けてくれるらしいです。'),
  ('974609cf-1d81-5e14-8370-7298aa82cebb', '40a476bc-72a5-5bdc-ab75-e89d5310b442', null, '9975e2b1-2972-5720-830a-6de5deffeb24', '2026-01-17', null, null, '通常 / エラー', '喋っていることが多く、喋っているときに手が止まっていたので話し始めそうな前に、次の問題を見せたほうが問題を解いてくれた気がします。問題を解くときにも喋っていたので喋る方に気を取られないように気をつけて進めるべきだと思います。', null, '時間帯: その他'),
  ('da4786fb-2936-5c6b-8463-cd6038957124', '2758b49a-c2b1-5cd0-9b37-3b988f2a5a09', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2026-01-17', null, null, '通常 / 基礎レッスン＆エラーつぶし', '最初に基本操作コース７ピンポンゲームのレッスンをしました。〇歩動かすと座標でのスプライトの移動方法の違い、ボールがパドルに当たった時の向きの反転のさせ方について細かく教えて理解してもらえたと思います。くじ引きのために、基礎レッスンはここで終了としたので、次回はゲームオーバー時とゲームクリア時の処理を一緒に作るところからできたらいいかなと思います。くじ引きはエラー学レベル１を３問ほど解いて終了となりました。', null, '時間帯: その他'),
  ('eeb04d8c-26c4-5459-81d3-64f6a92ed5d3', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, '9975e2b1-2972-5720-830a-6de5deffeb24', '2026-01-17', null, null, '通常 / エラー', '不等号にしないと超えて行ってしまう問題を解く時に等号で解こうとしてつまづいていましたが、それ以外の問題では特に問題なく解くことができていました。不等号の使い所と等号の使い所の差が分かっていないためこのエラーを直せていないのだと思います。', null, '時間帯: その他'),
  ('43eea0f5-3633-5c24-848a-9e6dfa5a062d', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2026-01-17', null, null, '通常 / エクセル', 'エクセル３級模擬試験をやってもらおうとしたら、PCの動作が重くて、なかなか模擬問題を始められなくて、PCを入れ替えて、だいぶ時間がたってから、模擬試験を開始。もくもくと勧めましたが、今日はレッスン終了時間で帰りたいとのことで、模擬試験自体を途中で終了して、今日できなかったとこのチェックをしました。正解率は35%位で、もともと半分くらいしか解いていなかったので、そこまでひどい点数ではない気がします。本人も、以前にくらべてだいぶ回答スピードは速くなったと言っていました。ただ、AVERAGEを使うところで、なぜかAVEDEVという３級では出題されないような関数を使ってしまったりとか、若干なんでそうなるのかわからん気になる点はあるので、注意してみていかないとなとは思いました。次回、いったんAVERAGEの復習をしてから、模擬問題に挑むのがよいかもしれません。', null, '時間帯: その他'),
  ('0bbfe01e-c785-5b01-8143-0654e0a94357', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2026-01-17', '16:30:00', null, '通常 / Excelの教材の進め方を知る', 'ほぼ、初めてExcelを触ったとのことです。テキストを丁寧に読んで、一つ一つちゃんとやるので上達も早そうです。逆に、丁寧すぎるので、30時間マスターのすべてのスキルをテキストに沿って全部つぶそうとすると、発想が広がらないだろうなと思うので。ある程度のスキルができたら、模擬をやって、実践で不明点のみを単元別にやる方法が良く。それも説明しました。', '来週はイラストです', 'タイピング: 割愛
盛り上がり: セルの右下「＋」をつまむとコピーできる機能に、びっくりしていました(*´艸`*)')
on conflict (lesson_record_id) do update set lesson_date = excluded.lesson_date, start_time = excluded.start_time, end_time = excluded.end_time, title = excluded.title, content = excluded.content, homework = excluded.homework, memo = excluded.memo;

insert into public.lesson_records (lesson_record_id, student_id, course_id, staff_id, lesson_date, start_time, end_time, title, content, homework, memo) values
  ('876e5eae-eb66-5d2b-a995-8a67d1580e48', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2026-01-17', null, null, '通常 / くじびきエラーつぶしとイラスト', '今日はノリ気でスクラッチのエラーつぶしを少し挑戦してからイラストをするということで、レベル１、レベル２をそれぞれ２問位ずつしてくじ引きしてから、アイビスペイント出のイラストにうつりました。基礎的なものは問題なくとけていましたし、やる気があればその点は問題ないのかなと思います。イラストではお正月にまつわる絵をかいていました。イラストはやはり楽しそうに書いていて、やはり絵が好きなんだなと感じます。', null, '時間帯: その他'),
  ('9ea610a2-4324-554e-80e6-b058cd69a18f', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '9975e2b1-2972-5720-830a-6de5deffeb24', '2026-01-17', null, null, '通常 / エラー', '数字の入れ替えでこちらの話を最後まで聞く前にプログラムを変えてしまっていたので変数を増やすのを教えたあとの入れ替え順序がなぜそうなるのか深く考える前にプログラムを編集してしまっていました。', null, '時間帯: その他'),
  ('ee2f0c58-02ff-5cb8-86e6-3db8e294a153', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-01-17', null, null, '通常 / バグつぶしとくじ引き', '普段Robloxですが、今回エラーで学ぶスクラッチにしました。元のコードをよく見て、不等号の向きなども判断しながらコツコツ進めることができました。ただ、スタンプを4つ押す問題では同じ場所にすべて押されていることを見抜けず困っていたので、実際の紙にスタンプを押してみて再現することでイメージをつかんでもらいました。全体的に基礎のブロックは忘れていない様子でした。', null, '時間帯: その他'),
  ('24a4b753-6c52-5a19-89b2-41117d9f9474', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-01-17', null, null, '通常 / バグつぶしとくじ引き', '歴は比較的長いのでレベル1だと簡単かと判断してレベル2からやってもらいましたが、結構苦戦していました。どうすればいいのか分からないというように思考停止する場面が最初は多かったです。ただ、元コードを1行ずつ読んで意味を取ろうとする姿勢は見られました。不等号の表す範囲や「かつ」「または」が苦手なようで、イメージがつかめていないようだったので、視覚的に表す説明をしてみました。数直線のこの部分が「へんすう>5」ゾーンだというように塗りつぶしてみると、大小関係では戸惑わなくなくなりました。また、2つの「ゾーン」を組み合わせるときに重なりを取り出すのが「かつ」で、全部合計するのが「または」というのも図示してみると、納得がいったようでした。最終的には集中モードで取り組めました。', null, '時間帯: その他
盛り上がり: 適切な考え方ができるように誘導することで本領発揮するタイプだと思います'),
  ('95a79892-a0dc-5226-bc89-e175dc9d9eb7', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-01-17', null, null, '通常 / バグつぶしとくじ引き', '最低でも駄菓子が保証されるクジだということに魅力を感じたようで、Robloxではなくエラーで学ぶスクラッチをやりました。スクラッチが久しぶりだったので案外詰まるところが多く、実装が少し難しい問題はヒントを出したりしました。クリックするたびに動いたり止まったりする問題では、フラグを切り替える条件を一緒に整理すると、「マウスが押された」と「フラグ=○」を組み合わせないといけないことに気づけたようでした。前半スローペースでしたが、最後はクジを引きたいと滑り込みで解き切りました。', null, '時間帯: その他'),
  ('2c1ef6c5-7bfe-58ad-af37-1955d2ffbc60', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-01-17', null, null, '通常 / Excel初回', 'エラーで学ぶスクラッチを一応やりました。最高レベルでしたが余裕でできていました。 Excelは初回なので、レッスンの進め方や検定について説明したあと1章に入りました。 1章はセルの概念、入力方法、保存など基本中の基本についてだったので、一緒に確認しました。ほとんどやったことはなかったそうですが、言うとすぐに理解・実践できていました。 続いて2章(SUM関数)は自学自習スタイルで進めました。慣れないなかで入力ミスなどはありましたが、間違ったところに気付いて直せていました。範囲選択などの操作も含め、全体的にスムーズにできていました。', null, '時間帯: その他'),
  ('869b8492-b8b6-5acb-a243-7cf69f943582', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-01-19', '16:30:00', null, '通常 / バグつぶしとくじ引き', '先週欠席だったので、エラーで学ぶスクラッチをやりました。「りんごとバナナ」は初めてだったので教えましたが、すぐに使い方を分かっていました。ペンやスタンプも慣れていないようでしたが、関連のブロックを見ると、使うべきものがどれなのか判断できていました。先週同じ問題をやった勇作くんが、隙あらばヒントを教えようとしてきましたが、制止して自分で頑張っていました。', null, null),
  ('5c57a809-ed55-5415-b80a-128cad881244', '726bac59-fe00-5b0b-a344-344f40441b6d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-01-19', '16:30:00', null, '通常 / バグつぶしとくじ引き', 'コードを拡大して細部をよく観察することで、バグの箇所を集中して探しだすことができました。例えば、全角数字や計算の順番の間違いにもすぐ気づくことができました。レベル1はスキル的に十分身についている部分だったので、その観察によりスムーズに終えられました。ただそのあとのレベル2では、変数の入れ替えを新しいスキルとして扱い、少し時間をかけて取り組みました。3つの変数で順番に値を写していくということは、実際の箱と消しゴムを動かしながらイメージできたようでした。それをスクラッチで再現するとき、値を直接指定しようとしていたので、入れ替えの意味を持たせるために変数名で指定することをポイントとして伝えました。', null, null),
  ('25de132a-de24-5ea1-87b9-02f8e22656b6', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-01-19', '17:30:00', null, '通常 / バグつぶしとくじ引き', 'obloxをやる気はあまりなく、今週もスクラッチのバグつぶしをしました。ただそれもくじを引きたいからであって、「レベル1のほうがいい」と言っていました。流石にそれは簡単すぎるのでレベル2をやってもらいました。変数の入れ替えはきちんとやったことはなかったようなのでじっくり考えていました。新しい箱を使った動かし方を思いついた後は、比較的スムーズにコードに落とし込めていました。それ以外の問題は考え方もわかっていたので順調にできました。', null, null),
  ('f5235ee1-85e3-5334-9fb5-225928784719', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2026-01-20', '17:30:00', null, '通常', 'くじ引きの問題で「かつ」「または」の論理演算で手こずっていた。他の問題はスラスラ解けていた。最後のスライムのステージ変移の問題で出てきた論理演算で手こずっていた。次回の受講はスライムの二段ジャンプから始まります。最後かなり居残りして解こうとしていたので、意欲を保ったまま指導したいです。', 'アルスタジオ/【バグを修正して！】シーンをかえる＆ジャンプ', '盛り上がり: くじを引きたいという欲求よりも問題を解きたい意欲がすごかった。
備考: ※前回当てた、くじ引きのクラス受講券で受講しました'),
  ('ca1274c8-c7dd-544a-ad1b-abfe4cd5fd7a', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2026-01-20', '17:30:00', null, '通常', '34_指定した座標で止める。で折り返した際x座標が50で止まらないところで少し苦戦していた。四捨五入を使うヒントを与えたらすぐ解けていた。他の問題はスラスラ解けていた。くじ引きより、問題を解くことに集中していた。', null, '盛り上がり: そこそこ'),
  ('9e9a5d85-d3c6-5a0c-9f12-eb8b7820edb6', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2026-01-20', '17:30:00', null, '通常', 'ラーメンを狙ってくじ引きをしていた。レベル③もサクサク進めて【バグを修正して！】シーンをかえる＆ジャンプの問題にすぐ取り掛かっていた。最後の連続ジャンプの問題をどうしても解き切りたく、居残りした。答えを渡したが自分の力で解きたく、参考程度に答えを見ながら夢中で取り組んでいた。くじを引きたいよりかは、問題を解きたい意欲が勝っているように感じた。スライムがホバリングするようにはなったが、連続ジャンプはまだできていない。次の受講の際に解くことになった。', '【バグを修正して！】シーンをかえる＆ジャンプ の連続ジャンプの修正', '盛り上がり: くじの効果もあってか、夢中になって取り組んでいた。'),
  ('ed30b570-0974-5270-a88a-02d5506573e2', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-01-20', '16:30:00', null, '通常 / Excelの体験をする', '今日はExcelの体験をする、という意識で来室しました。 はじめは、昨日社会見学で国会に行ったから疲れてるんだ～とだらだらしそうになりましたが、授業を始めるとしっかり話を聞いて、すぐに手を動かしていました。 入力に関してはあまり苦にならないようで、最初の四則演算なども自分から次の問題へとどんどん取り掛かっていました。 SUM関数などで自動で設定される範囲についてもよく見ていて、自分から範囲指定をやり直したりと、勘の良さを見せてくれました。 合計、平均、最大、最小はすぐに覚えて、オートフィルなども使って数式を入れることができました。 おまけとして、桁区切りスタイルのボタンと、小数点以下の表示桁数のボタンを教えました。 達成率以外をすべて終えて30分ちょっとでしたが、集中して取り組めていました。 内容的にも、ものすごく面白かったというわけではなさそうですが、苦手ではなさそうで、わりと向いているのではないかという印象を受け、本人にもそう伝えました。 Excelが解き終わったということでくじ引きを1回やり、残りはScratchで遊んでいました。', '本人がExcelをやる意思があれば、グラフなどをやってみたいです', '盛り上がり: 数式を入れる手順については、とても理解が早く、そこをほめるとまんざらでもない様子でした。'),
  ('75094867-fb7d-5038-8766-c9372e4f78a0', '1c7005cc-2815-558f-993a-9c7617d34c44', null, 'd45d6c5d-18cd-5aa2-99ea-932c81442c55', '2026-01-20', '16:30:00', null, '通常 / バグ探しクイズにチャレンジしてくじ引きをする！', 'エラーで学ぶ②に挑戦しました。算数系の問題も紙に書いて一緒に計算したり電卓を使いながら行ったことで修正することができました。0は何をかけても0をすでに理解していたので積の問題は直ぐに修正することができました。', null, '盛り上がり: ゆうたろうくんには難しいレベルの問題でしたが、ほかの子がくじ引きチャレンジをする雰囲気の中で頑張って取り組んでいました。 時間いっぱい頑張ったので、最後まで終わりませんでしたが、おまけで1回くじ引きをさせると、とても喜んでいました。'),
  ('4e773caf-694b-5892-9916-17d02d4c9039', '1da24088-9441-50c6-ac58-79e18ef5cc01', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-01-20', '17:30:00', null, '通常 / バグ探しクイズにチャレンジしてくじ引きをする！', '授業が始まる前にエラーで学ぶ①を終わらせることができたため、エラーで学ぶ②から取り組みました。どのブロックを使ったらいいかは理解できている部分が多かったですが、ブロックの判定の順番が掴めていないようで苦戦していました。焦ってることが多かったので、落ち着いてゆっくり考えることができると自分でエラーに気づくことができる部分が増えそうです。', null, null),
  ('29661b34-7992-5709-9add-4c858357f426', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-01-20', '17:30:00', null, '振替 / バグ探しクイズにチャレンジしてくじ引きをする！', 'ロブロックスの振替日でしたが、本人に選ばせてエラー探しをやりました。 変数の入れ替えについては「こんなのやったことあったっけ？」と言って昨年のことは覚えていないようでしたが、実際の教材を見せながら説明して、なんとか納得できたようでした。座標の範囲や演算式についてはよく理解できていたようですが、条件分岐の場所についてはまだまだ混乱が見られました。', null, '盛り上がり: なんとか時間内にレベル②を解き終わり、「なにが当たってもいいや」と言いながらくじ引きを引いていました。結果白紙でしたが、満足そうにかえって行きました。'),
  ('a22505cc-6659-5928-b7ff-d324fb156a24', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-01-20', '17:30:00', null, '通常 / バグ探しクイズにチャレンジしてくじ引きをする！', 'レベル③が残り2問だったので、その続きから、淡々と進めていました。できるごとに、ちょっと嬉しそうに先生を呼んでいました。 どの問題もほぼ行き詰ることがなく、自力でスラスラと解いていました。 今日の課題事態は40分くらいで終わってしまったので、くじ引きをして、残りは問題のアレンジをしていました。', null, '盛り上がり: くじ引きで小が5個を引いて、嬉しそうでした。'),
  ('d1119dab-defa-58b5-9ae5-79ad4ed959bc', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-01-14', '17:30:00', null, '通常 / Excel検定対策', '罫線や数式の入力あたりまでは問題なくできていたのですが、グラフにするシートを間違えてから混乱がおきたようで、全体の3割くらいが手つかずの状態になってしまっていました。 本人も、そこでペースが崩れたという自覚があったようで、画面が分割されている状態に慣れないと…と反省していました。 見慣れない指定があったら、ボタンからではなく「書式設定」というのを覚えたようで、そのあたりの設定ではだいぶ迷わなくなってきていました。', null, '盛り上がり: できている箇所はそれなりに自信がでてきたようですが、小さい画面での問題の見落としや制限時間がこわい、と反省していました。'),
  ('916dbbf4-b2ac-5c46-85b1-ed4c0ff575ea', '512b2f12-24bc-5afa-913a-d68b4a9f9e14', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-01-14', '16:30:00', null, '通常 / 見やすい資料を作成する', 'Office内でのコピー＆ペーストにも慣れ、楽しんでサンリオ紹介のパワポを作成していました。 サンリオについての紹介ということでお勧めページを探してもらい、そこのURLをQRコードにして貼り付けるやり方を教えました。こんなことができるんですね！と喜んでくれました。 PowerPointでは初めてアニメーションの機能を学習しました。 アニメーションの順番や効果、向きがいろいろ設定できるのを楽しんで設定できていました。', null, '盛り上がり: どの機能を教えても楽しんで、熱心に取り組んでくれました。'),
  ('ca31c7a6-5bd7-52e1-b0ff-17f385214f1b', '57f45872-1f3e-5540-b676-bf9023444e39', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-01-22', '16:30:00', null, '通常 / くじ引き大会', '前回レベル2まで終っていたのでレベル3から。 進めていきますが、わからないとすぐに答えを知ろうとするところがあります。 できるだけ直接的に答えを教えずにヒントを出しながら進めました。 レベル3終了後、バグ修正の方に取り組みました。 たかひと君のサポートを受けながら完了できました。', null, '盛り上がり: くじ引きではお菓子x5をあてていました'),
  ('93040e18-e6a0-5583-ad28-6ece84103c0e', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-01-22', '17:30:00', null, '通常 / くじ引き大会', 'レベル3から進めました。 リストの後ろから削除とクリックで動く、止る以外はそこまでつまずかずに進められていました。 つまずいていた点として、スペースキーを一度押して全てのリストを削除しようと試みてしまっていました。 リストの最後の位置を示す変数の必要性をふんわりと教えるとすすめることができました。 また、クリックで動く、止るを変えるのもフラグの意味と現在のフラグの値によって変更値を変えるのにもつまずいていました。', null, '盛り上がり: くじ引きで1等を当ててとてもうれしそうによろこんでいました。'),
  ('3141c9e3-ad76-5b88-8f2b-cd799519e1dc', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-01-22', '17:30:00', null, '通常 / くじ引き大会', '前回レベル2途中までだったのでそこから進めます。 レベル2の問題では、くじ引き問題でとくにつまずいていました、結果の範囲と順番で悩んでいたように見えます。 紙に数字の範囲を書き、範囲を絞っていくようにするとよいと伝えることですすみました。 レベル3は、くじ引き問題だけ取り組みましたが、レベル2の応用的な感じでとくに問題なく解けていました。', null, '盛り上がり: くじ引きではベビースターを持ちかえっていました。'),
  ('33c6fcbd-4316-56fe-a8c5-755d25831362', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-01-22', '16:30:00', null, '通常 / バグつぶしとくじ引き', '苦戦しながらもあきらめずに取り組んでいました。四捨五入や「ペンを上げる」など、ポイントとなるブロックをヒントとして出すとイメージはできたようで、それをどこに入れれば想定通りになるか考えていました。最終的にしっかり自分の手でレベル3を終えることができました。', null, null),
  ('809931cb-17dc-5f7f-827b-7101c6352348', 'f3102a36-fdd8-574f-bf3c-85723faf424f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-01-22', '16:30:00', null, '通常', '先週レベル3まで終えていたので実際のゲームのバグつぶしに取り組みました。シーンを変える部分では最初原因が分からない様子でしたが、「背景2に行く」「3に行く」「4に行く」を差別化するにはどうする？と問いかけることで、今の背景番号で区別するアイデアを思いつくことができました。背景番号のブロックは既によく知っていました。 ジャンプでは、いきなり放物ジャンプ＆地面に触れるまでの判定を作ろうとしてバグっていました。そこで段階的に、「ジャンプ」変数を使う→ジャンプ回数を変数で記録する というように組み立てていきました。それでも2回目以降の連続ジャンプが効かなかった(一度始めたジャンプを跳び終わるまで次が始められない)ので、模範解答と違うところを探してもらいました。「y座標を(ジャンプ)ずつ変える」を繰り返しの外に出してずっと動くようにするのがカギだと伝えました。 引いたクジは1等の当たりで大喜びしていました。 そのあとすることがなくて自由時間になったのですが、自分が解いた問題をこたろうくんがやっていたので、ふざけて肩代わりしようとしていました。何とか止めてこたろうくん本人にやってもらいました。', null, null),
  ('221cb920-422a-5abb-ba9c-9ca6555c452c', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-01-22', '17:30:00', null, '通常', 'クラス序盤は、不等号と場合分けをするくじ引き2の問題を苦戦しながら解いていました。ただ途中で、「元カノとトラブルになっていて、今来た連絡をすぐ返さないといけない」「親にも連絡しないと」と言って中断しました。その後はほぼずっと忙しそうにLINEで連絡を取っていました。警察沙汰になるようなものではなさそうですが、落ち込んだ様子でした。', null, null),
  ('aa19efcd-595b-5dc3-94f3-d5f0305e3d98', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-01-22', '17:30:00', null, '通常', 'くじの「中当たり」が出るようにする問題では、使う不等式自体は合っていましたが、順番を間違えることで誤判定が起きる状態になっていました。そこで、コードの上から順に時系列をたどって、不等式を入れる順番を考えてもらいました。他の不等号関連の問題は、比較的自分で考えられていました。', null, null),
  ('46b5b224-5599-57c1-b54c-dbc3fb587786', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-01-23', '18:40:00', null, '通常 / バグつぶしとくじ引き', '本来ロブロックスですが、くじ引きをやりたそうだったのでアルスタジオでやりました。③からでもよさそうでしたが、ブランクがあるからと②にしました。やはりスクラッチを忘れた部分が少しあり、「かつ」と「または」の意味や、変数の入れ替えの考え方を重点的に確認しました。最初は適当にやっていましたが、次第に必要なものを思い出してきたようでした。「シーンを変える」についてはあまり時間がなかったですが、背景番号の条件について整理していくと一問目はできました。', null, null),
  ('afbca27d-3775-5068-a324-3c5c1947d269', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-01-23', '18:40:00', null, '通常 / バグつぶしとくじ引き', '最近あまり調子がよくないとのことですが、やる気がないわけではない様子でした。ただ、問いかけなどをしたとしても、一旦そばを離れてしまうと自走するのはきついという状態でした。こちらがヒントとして必要なブロックなどを教えるとある程度組み立てることはできますが、記憶に任せてなんとなく作っているという感じが否めませんでした。例えば、「もし～なら」ブロックの範囲をきちんと認識していなかったり、ブロックを差し込む場所を適当に決めたりしていました。', null, null),
  ('c1db2bcb-b7cd-54d8-a534-cfbb37d148fa', '31feac25-f850-5d21-8e43-ed4d7badb6a0', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2026-01-17', null, null, '通常 / エラーの修正', 'レベル①の課題は、ほぼ一人で修正ができていた。わからない箇所もヒントを出すだけでしっかりと解決ができていた。 レベル②はくじ引きの課題だけやって満足したようで残り時間はゲームを少しやって満足をしていた。', 'エラー修正レベル②から継続', '時間帯: その他'),
  ('8daa7d70-c6ac-51da-b07e-9e9447b36e69', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2026-01-17', null, null, '通常 / エラー修正', 'エラーで学ぶレベル③をすべてクリアできた。 途中から修正というより作り直して解決することもできていたが、元々のコードからの修正も考えてもらってすべての問題をクリアできた。 スキルも高いのでほぼ自力で解決ができていた。', null, '時間帯: その他'),
  ('b01dcc9a-f00e-5f9b-9983-d245d06b5571', 'c47b4046-9872-56fc-a811-2f1cb7d0d1a0', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-01-10', null, null, '通常 / 【体験】', 'マインクラフトが好きでそちらでコードを少しいじっているとのこと。プログラミングにも積極的で、スクラッチで猫を歩かせるコードもすべて面白がって楽しんで作成していました。洞窟ダイヤではアレンジにハマって、敵の骸骨を増やすだけでなく、無敵モードを作ろうと頑張っていましたが、完成まで持っていけなかったのが少し残念そうでした。戦闘機に触れたら無敵モードになるというのを作りかけて終了しましたが、フラグとしての変数の使い方も熱心に聞いていました。 いつか続きを作りたがるかもしれないので、アルスタジオに作品を入れておきました。', null, '時間帯: その他
盛り上がり: 1時間半近く、とても集中して取り組んでいました。 やりたいことのアイデアもよく出てきて、作成を楽しめていたように思います。'),
  ('c90a6523-e928-5e04-8d1c-f4e278383b30', '76019ebd-2809-5e43-b3c7-1c8834a9e170', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-01-10', null, null, '通常 / 【体験】', '幼稚園生で初心者ということもあり、お兄ちゃんのようにできなくて少し焦れるような様子を見せることもありましたが、初めてのマウスを一生懸命使おうとしたりとやる気を見せていました。難しくても、やろうという意識は維持できていたと思われます。 思うようにできなくてごねだしたときは、お父さんが一度手を止めさせて本人の話を聞き、「大丈夫、焦らない」と声掛けをしたら落ち着いたので、行き詰ったら一度気分転換させるのが効果的かもしれません。', null, '時間帯: その他
盛り上がり: アレンジは難しそうにもしていましたが、プログラム自体は楽しんでできていました。'),
  ('59d7a0eb-459c-5b95-af53-b248116381fd', 'c47b4046-9872-56fc-a811-2f1cb7d0d1a0', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2026-01-24', null, null, '通常 / 基礎レッスン', '体験の記録を頼りに基礎とはいえ、かんたんな追跡ゲームの作成をしました。最初のうちは、言葉数も少なく、反応が鈍く、どれくらいできる子なのか、きちんと理解できているかの判断が難しい状態でしたが、途中から少しずつ反応が良くなってきたので、すこし人見知りする感じなのかなと感じました。こういう状況で、ある程度できるものと私が勝手に解釈してしまい、基本操作コース04のレッスンをベースにしつつも、ちょっとした追加要素をいれこんだりして、ちょっと詰め込みすぎたかもしれません。最後の方に話が普通にできるようになってから聞いたら、ちょっと難しかったということだったので、次回以降は、追加要素なしの基礎レッスンでよいと思います。ただ、次回はx座標、y座標の概念の復習、もし～ならを使った矢印キー入力での上下左右移動についての復習あたりをしてから、次の基礎レッスンを始められたらよいかと思います。', null, '時間帯: その他'),
  ('e1000a9b-e52e-521a-87cb-4a9cc1b09a2b', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-01-24', null, null, '通常 / エラースクラッチ', 'エラースクラッチレベル③はまだ終わっていなかっったので。続きをやっていきました。最初からメモリーゲームを取り組んで、2悩んでいたので、リストの機能について振り返ると、気づいてくれました。また、後ろから削除もほかの機能について、振り返ると「リストの長さ」に気づいてくれました。また、正方形作図については、ペン機能が不十分だったので、その情報を知ると、うまくできました。スクラッチレベルは高いが、機能の知識が普住免七面があったので、振り返れてよかったです。その後は順調に進んで、終わりまであと1つでしたが、よくできていました。', null, '時間帯: その他'),
  ('1794b695-1542-54f5-a279-5d83e6ff3b84', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-01-24', null, null, '通常 / エラースクラッチ', '今年最初だったので、エラーレベルⅠから始めていきました。くじが引けること自体には興味なさげでしたが、着々と進んでくれました。レベルⅠについてはケアレスミス系の問題が多いので、あまり悩むことなく進んでくれてたので、スキルは身についています。途中で寄り道をしながら、40分くらいでレベル1は終わりました。そのまま進めるがあまりなさそうだったので、背景のやつのエラーを直してもらいました。座標で何とかしようとしていたが、背景の状態には気づけていませんでした。背景の状態についても触れてあげたら、それを条件式に入れればよいと気づけたのよかったです。', null, '時間帯: その他'),
  ('dbb683c6-7602-568b-b468-c9536ed08fa4', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2026-01-24', null, null, '通常 / エクセル', '昨日エクセルの模擬問題を解いて５６％くらいだったとのことで、まだもうちょっとのところで合格点に届いていない状態。特にグラフの問題で時間がかかってしまうとのことだったので、３０時間・６章のグラフの応用問題を復習してもらいました。自走してがんばっていたようですが、途中、問題文に記載されている表示と、実際の教室のPCの表示が違うところがあるとのことでエクセルバージョンの違いからくるものだと思うのですが、一部そういうところもありうるということで説明して納得していました。', null, '時間帯: その他'),
  ('1a717699-192b-548f-b08f-5389bb88ba5d', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-01-24', null, null, '通常 / エラースクラッチ', '不等号系の問題に苦戦しているイメージがありました。特にくじ引きの問題は、大当たりの判定は出るが、余分にはずれの判定まで出てしまうことに悩んでしまいました。そこで、判定の優先度やどの後にしたらいいのか一緒にに考えていきました。意外と、「ではないなら」の認識が甘く、答えにたどり着いても先生の言葉なしには理解が難しいそうでした。 また、レベル3の問題で、行ったり来たりの50ぴったりに止まる問題では、座標がずれていることが自力で気づけていましたが、それをどうただしていくのか苦戦していました。学校では「四捨五入」の考えを学んでいないので、「その小数が整数にどっちが近いか」と伝えると、理解が通りました。レベル3はほかのものは難しいので、ほかのものに進みましょう。', null, '時間帯: その他'),
  ('601f294b-27c0-5fa9-a6b2-53ce448aa0fe', '76019ebd-2809-5e43-b3c7-1c8834a9e170', null, null, '2026-01-24', null, null, '通常 / 文字を動かし変化して、で色や大きさ、音を学ぼう', '先に完成例を見せたら、いろいろと動きがあったので、目を輝かせてやってみたいとやる気が十分にありました。自分のアルファベットを動かすものでしたが、アル君がかわかったそうで、アル君にもコードを作っていきました。1つずつ、色や大きさ、音の出し方など教えていくと、前の文字で自ら組み合わせて、遊びを広げていました。そこで、自分で新しいことをすると、見てみてと呼んでくれるので、やる気が満ち溢れています。やっぱり、ランダムに動くことが好きみたいです。また、セリフもつけてみたいのことだったので、自分では打てませんが、加えて学習しました。最後に、「スプライトを押したら」を「はたをおしたら」に変える作業をしましたが、1回やり方を教えると、下のブロックから離して、付け替えることができました。なので、マウス操作は問題なくできています。', null, '時間帯: その他
タイピング: タイピング教材はまだやりませんでしたが、「セリフ」を打ちたいとなった時に、キーボードのひらがなを見てやろうとしていたので、「ローマ字」入力は一から始めた方がよさそうです。
盛り上がり: 最後に、お父さんに見せて、本人は喜んでいました。'),
  ('15880bf6-3a40-5d6a-b14a-eb44a360ba8e', '2758b49a-c2b1-5cd0-9b37-3b988f2a5a09', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2026-01-24', null, null, '通常 / 基本操作コースの続きとエラー修正', '前回、基本操作コース７とエラーで学①やってどちらとも途中だったので、今日も同じように、前半基本操作７の続き、後半エラーで学①を実施。特に、乱数・変数についてしっかりレッスンしました。変数の概念をわかりやすく教えたつもりで、基本操作コースレッスン時では理解してもらっていたと私が思っていたのが、エラーで学①で似たような変数の修正問題のところで、ひっかかっていました。次回、もう一度変数の復習をしたうえでレッスンを始められたらよいかなと思います。それ以外は問題なく進められたと思います。', null, '時間帯: その他
タイピング: 自分から進んで挑戦していました。とても集中していました。'),
  ('1f0445e3-7832-5025-8c71-50620aa67635', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-01-24', null, null, '通常 / エラーで学レベル③', '前回、エラーで学レベル②に取り組んだ様ですが、変数の理解が苦手と言っていました。 集中力はある方ですが行き詰まることもあり、その際は紙などで「フラグが1,0のときはそれぞれどう変化してほしいか？」という糸口を一緒に考えてあげるとその後は自分で黙々と進められているようでした。エラー②をすべて終えたのでエラー③の「指定した座標で止める」に進みました。特に質問することもなく終えられていました。', null, '時間帯: その他
盛り上がり: 自分の中で問題を解決できる目途が立った時に楽しそうに取り組んでいました。'),
  ('f4173628-cafd-59a5-8a97-d261a083606a', '31feac25-f850-5d21-8e43-ed4d7badb6a0', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-01-24', null, null, '通常 / エラーで学レベル②', '数の入れ替え」では、「1つの箱に1つの値」という原則を伝え、バケツの例えを用いることで代入の向きも正しく理解できていました。和や積の計算についても、紙に書いて数値の変化を書き出すことで、スムーズに理解ができていました。「50で終了」では、正確に50で止めるためにクールダウンタイムを追加するなど、自身でアレンジを加える様子もあった。コンピュータの特性をよく理解できているようで、予定より10分早く終了したため、残りの時間は自由時間としました。', null, '時間帯: その他
盛り上がり: 類似問題において、前回使ったスキルが役立つ時が非常に楽しそうでした。'),
  ('bd15f30e-b7c7-55af-8833-346e44ebbeee', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-01-24', '16:30:00', null, '通常 / バグを修正して！シーンを変える＆ジャンプ', 'シーンの切り替えでは、見本とは異なる「x座標 ＞ 〇〇まで待つ」というブロックを使い、順番に動作するようにしていました。「ジャンプの高さを変える」課題では、多少苦戦する様子は見られたものの、変数を使い正確に作成できていました。 いずれも見本回答とは異なる方法でしたが、自身の力だけで作成できていて驚きました。その後の「連続ジャンプ」についても、変数を使い、仕組みを自分で説明できるほど深く理解できていました。 また、しも先生からの提案で難易度の高い「ホッケーのバグ修正」にも挑戦し、修正することが出来ていました。途中、判定「x座標 -125」の数値の意味について質問がありましたが、実際にホッケーのX座標を125にしたときどうなるかを伝えたところ、すぐに納得した様子でした。', null, null),
  ('5349d2e4-2cce-547d-82be-cdc39808bc3e', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-01-23', '18:40:00', null, '通常 / エラーで学レベル②', '今日は特に主体的に取り組む様子が少なく、途中であきらめそうになる部分もあったがくじがあったからか粘り強く取り組む様子が見られた。 予定ではエラーで学レベル①の予定だったが、前回の授業ですべて終えていたのでエラーで学レベル②に進むことにした。 ハードルが高すぎるのをやると落ち込むタイプと伺っていたので簡単な物から取り組みたかったが、本人が最初から順番に進めたいとのことだったので「数字の入れ替え」から取り組んだところ理解に苦戦し、嫌になってしまった。ゆき先生からの助言で数字が絡む苦手な部分を飛ばすことを提案したが、本人のプライドが許さず後回しということになった。その後同じくレベル②の「右に消える」と「くじ引き１」は嫌々ながら本人の粘り強さで乗り越えた。本人が納得してくじを引けるよう「バグを修正して！シーン変更＆ジャンプ」に取り組んだが、時間があまりなく問題全体に共通して言えることのみを伝えて終わりになった。', null, '盛り上がり: 諦めそうになると強引に終わらせようとすることがあるが、その時は一つ一つの行動に過剰に反応して一緒に笑ってあげると本人の気持ちも軽くなっていたようだった。
備考: 学年的にも数字が苦手なようであまり乗り気でなかったです。また、本人の中で感情が高ぶる瞬間があり、その時には一度中断して話題をそらすと良かったです。'),
  ('0693a86a-99d7-5753-b000-213d9a52e5e0', '5fc65a36-fdbb-5af5-a6f4-16080e4e37ef', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-01-23', '17:30:00', null, '通常 / 基本操作', '「拡大したり縮小しよう」のコースで、拡大・縮小について質問したところ、望遠鏡を例に挙げてわかりやすく説明してくれました。非常に飲み込みが早く、一度教わった操作をすぐにマスターしている姿には驚かされました。 集中力も抜群で、授業中は一度も休憩を挟むことなく、最後まで楽しんで取り組んでいました。また、想像力も非常に豊かで「ロケットに乗って土星やアンドロメダ銀河に行く」という独自の設定を考え、「場面を変えよう」のコースでは、用意された背景を使うのではなく、自ら宇宙の絵を描き上げるほど熱中していました。自分のやりたいことを実現するために、自身から過去の学習内容を復習する姿勢も見られ、感心しました。', '基本操作コース_03_08が背景の作成途中でしたので続きから進めてもらえば問題ないかと思います。', 'タイピング: １文字ずつではありましたが、キーの配置が身についてくればかなり成長するかと思います。
盛り上がり: とにかく宇宙が好きなようで宇宙に関する知識量に驚きました。スパゲッティ現象やアンドロメダ銀河について説明しているときは特にワクワクしていました。普段から宇宙の絵を描くのが好きなようで、自分で架空の星を考え命名までしているそうです。
備考: まだ入校してから間もないこともあってか、先生を呼ぶのが控えめなので意識して困っていないか見てあげると良いかと思います。'),
  ('90d89cd3-414b-5c38-8269-f12445ee2ada', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-01-16', '16:30:00', null, '通常 / エラーで学レベル②', 'とにかく元気があり、自身から取り組んでいる様子が見られました。変数の「数字の入れ替え」は変数の概念を理解するのが難しかったようで力技で進めていました。ゆき先生から「力技も認めてあげていい」というアドバイスを頂き、その後も力技を認めてあげる部分が多々ありました。しかし、座標への理解は深く、右に消えるなどは自分で座標の説明をして修正できるほど力がついていました。また、途中エラーで学レベル②の「100より小さい」は直ぐに問題点に気づき、終わらせていました。', null, '盛り上がり: レッスン様子に書いたような数字関係(座標など)の得意分野は直ぐに問題点を見つけ、楽しんでいました。'),
  ('5098dfe6-9d53-5232-b6b0-6f99133d9f66', '10db50c3-a153-502a-b455-c67362b9871c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-01-23', '17:30:00', null, '通常 / バグつぶし、Roblox体験', 'スクラッチのバグつぶしからやりましたが、レベル的には余裕なので早々に終えてしまいました。そこで、興味があるというRobloxの体験をしました。ブロックの配置や拡大縮小、アンカーなどの基本操作は、pdfで一緒に見ていきましたが飲み込みは速かったです。「体験では出てこないけど、今後やるとなったらこんなテキストプログラミングをやる」という話もしました。3Dゲームを作れることが楽しいらしく、細い道で車を運転・駐車するゲームを熱心に作っていました(車はRobloxモデルの検索から見つけてきました)。', null, null),
  ('5e4a80f8-7071-5f6a-9b2f-128b7c258775', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-01-26', '16:30:00', null, '通常 / レッスンの内容を振り返ろう', '前回、バグを修正して！】シーンをかえる＆ジャンプまでやっていたので、今日はレッスンのところでやってないものをしてもらうつもりでした。エキスパートであれば、それなりに気になるものがあるとも思い、宇宙バトルレベル③をやりました。内容としては、クローンを使って球を打ちやすくすることでしたが、クローンあまり使ったことがなかったが、早く作り終わりました。そこまで苦労するものではなく、同じ系列のゾンビのものをやってくれました。途中、先週やったものを岳君に助けてくれました。', null, 'タイピング: 久しぶりにタイピングを振ってみたら、拒否されました。'),
  ('2d48189d-3049-5b0c-b865-4bba07d1bfea', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '9975e2b1-2972-5720-830a-6de5deffeb24', '2026-01-26', '16:30:00', null, '通常 / バグ修正', '集中して授業を受けていました。すべて同じ条件の分岐だと上のみ処理されることは分かったようですが、それをどうすれば解消できるかがわからない様子でしたが、背景番号のブロックを教えると問題を解くことができました。ジャンプを変数で制御するときは変数はスコアを表示するためのものという程度の認識しかなかったため変数による高さの変更をうまくできていませんでしたが、使い方を教えるとしっかりと解くことができていました。', null, null),
  ('ae329daa-7698-5655-b18c-6bf2102e5dd8', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-01-26', '16:30:00', null, '通常 / バグを修正して！】シーンをかえる＆ジャンプ', '背景が1回しか割らないバグを最初ノーヒントでは何が違うか気づくには厳しかったです。背景の条件の違いを気づかさせるために、少しずつヒントを与えながら、やっていき制作していきました。ここで、背景番号が変数として機能していて、それを条件式に持ってこさせるの流れが一番困難を極めていました。オレンジの変数のブロックならスムーズにできていたが、ほかのパラメータに対してはまだまだみたいです。 ジャンプに関しては、「回数」と「高さ」を使うことだけ伝えて、やってもらいましたが、下がるときのマイナスの考えが時間がかかりました。引き算のブロックを持ってくるところまでがよかったが、そのあとが試行錯誤で悩んでいました。最終的には、助言もあり、「０－高さ」で持ってこれるようになりましたl。', null, null),
  ('cdb8aadf-a5c5-51bb-adeb-d307e81005a7', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-01-26', '16:30:00', null, '通常 / キラキラかくれんぼ', '2月いっぱいでロブロックスが休会とのことだったので、こちらからあと2レッスンはすすでほしいと進路の目安を伝えました。今日は来て早々にやる気がある日だったので、すぐに取り組んでくれました。内容としては、今までの復習で、クローンとＧＵＩで、悩むことなく進み終わりました。', null, null),
  ('98ad0ae8-7823-5102-b0a0-fd2ac47600b9', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-01-26', '16:30:00', null, '通常 / ロブロックススタジオの使い方、操作方法に慣れよう', '今回からrobloxが始まりだったので、基本はそばについて、操作方法を教えてくれました。動画では教えてくれないＰＣのショートカットキーや動画とはバージョンが異なるので、ＵＩの見方を補助していきました。本人はロブロックスについて触れてきてなかったので、初めのうちは捜査のやりずらさが出ていました。そして、異論差操作画面を覚えるので、次の時には覚えているか不安そうにしていました。今回は足場をつなぎ合わせる途中だったので、次回は、その続きと操作の確認、確認テストをお願いします。', null, null),
  ('e972aae2-2acf-5759-957e-7fd7b149aa43', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-01-23', '17:30:00', null, '通常 / バグ探しクイズにチャレンジしてくじ引きをする！', 'くじ引きをやりたいと、熱心に取り組んでいました。 一問クリアするごとに、得意そうに報告に来てくれました。 特に行き詰ることもなく、一人で進めることができていました。', null, '盛り上がり: 今年のコンテストに挑戦する題材を考えていると嬉しそうに話してくれました。 作成に前向きになれているようです！'),
  ('c31256d4-e90a-52f0-a277-268cacfcb9c4', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-01-29', '16:30:00', null, '通常 / ロブロックス体験', '2月からロブロックスのコースでしたが、早くやりたいとのことだったので、体験してもらいました。roblox自体初めて触れるのことだったので、まずは操作方法について慣れてもらいました。左手で移動、右マウスで視点変化になれるのが大変そうだったので、前半は元あるゲームで操作感覚を養ってもらいました。後半は、デジタネの最初の教材のアスレチックで準備されているコードを動かすことで、スクラッチとの違いを体感してもらいました。終始、操作に関しては苦になることがあったが、内容に関してはのめりこんで進んでいく様子が見られました。', null, null),
  ('0682807b-da25-5055-8cf9-c46350110f52', '57f45872-1f3e-5540-b676-bf9023444e39', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-01-29', '16:30:00', null, '通常 / 小技使用作品作成', '授業始めは他のものに集中を削がれている感じがありました。 しばらくたってから取り組みはじめますがやはり集中はできていなかったようにみえます。 元の完成品のスプライトと色を変更するアレンジを行なっていました。', null, 'タイピング: るいくんのかわりにタイピングする様子がみられました'),
  ('6a063e65-43fd-51ad-b82b-e278301e445a', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-01-23', '17:30:00', null, '振替 / Excel検定対策', '特に問題なく解けていました', null, null),
  ('30d76760-4a2d-592c-9769-c0f6de91e86b', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-01-23', null, null, '通常 / Excel検定対策', '自力でよくできていました。 本人もある程度得意だという自覚があるようでした。 自動採点も余裕のA判定でした。', null, '時間帯: その他'),
  ('b6be9273-379c-521d-8efb-e38eccc34f4a', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-01-29', '16:30:00', null, '通常 / 小技を習得しよう', '来月からのテーマ自由制作のために、小技を習得していきました。選んだ小技は、スタンプ花火ものです。最初は、過去に作ったソニックのものに続きやりたいと言い出したが、ルイ君自身がそこから何をつけ足したいか特に思い浮かんでいなかったので、それを身に着けるために小技を見ようと誘導することができました。内容は、鬼滅の柱たちをスタンプ花火に置き換えて、大渋滞の画面になっていました。途中、ある柱が前に出てこないと悩んでいたので、そこからどのようにやれば前に来るのかコードの思考をためしました。終わりにも、この小技のコードの特徴を聞いたところ、スタンプと回転を理解していたので、まだよかったです。', null, null),
  ('be5bd628-b686-5c66-85d2-465e6ae2ba54', 'f3102a36-fdd8-574f-bf3c-85723faf424f', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-01-29', '16:30:00', null, '通常 / 小技使用作品作成', '残像の小技を使用してオリジナルの2Dゲームの作成に取り組んでいました。 敵の攻撃を操作キャラクタに追尾するようにしようとしていましたが、追尾速度、消えるまでの時間の調整をがんばって行なっていました。 他の子にあまりひっぱられずに取り組めていた感じあります。', null, null),
  ('8a90c30b-cef8-54a8-9eae-07c67717e386', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-01-27', '16:30:00', null, '通常 / バグ探しをする', '今日は生徒が一人だったせいか、火曜日の先生に慣れてきたせいか、よくおしゃべりに乗ってきました。バグ探しは、バグの部分も、どう修正するかもわかっているけれど、手を動かすのがめんどくさい…とぼやいていましたが、「わかってるなら手を動かしてよ～」と声をかけると苦笑しながら操作をするくらいには機嫌がよかった？です。 30分ほどで連続ジャンプを残して手が止まってしまったので、今後の希望などを少し真剣に話し合ってみました。 前回やったExcelはやってもいいと思っていること、以前は興味ないと言っていたロブロックスも、やってみたいと思い始めていることを少しずつ話してくれました。 自分の希望を家で話し合ってみる？と聞いたところ、こちらから親に話してほしいとのことだったので、Comiruで連絡するから、自分でも家で話してね、と伝えておきました。', null, 'タイピング: 久しぶりにやってみるとチャレンジしていました
盛り上がり: 新しいことをやってみたいという希望を話してくれて、そうすけくんにしては前向きになっているようでした。'),
  ('703ebfa9-ff4a-5b65-aa79-ef569366b48e', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-01-29', '16:30:00', null, '通常 / 自由制作', '今日は、小技習得の予定でしたが、本人は自由制作に気がかなり傾いていたので、そちらを優先させました。卓球ゲームを制作しようとしていました。スクラッチから参考ゲームを基に位置から作り上げていました。コードもそうですが、コスチュームも細かい点で悩みがちなので、早く進めてほしい点はこちらから早めに回答してあげました。ゲームスタート画面からプレイ画面に移り変わる際に、プレイヤーが出てこないバグがありましたが、メッセージの送り間違えとすぐに気づけていたので、バグ直しの成果が出ていると思います。', null, null),
  ('128454f9-8575-55d6-94fb-5366a70409ac', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-01-29', '17:30:00', null, '通常 / 小技使用作品作成', 'すでにある2Dシューティングゲームに小技を追加する形で取り組みました。 小技のプログラムをそのまま移植していたため余計なブロックも付いてきたことによる不具合に悩んでいましたが、どの部分がバリアの生成に必要なプログラムなのかを考えながらヒントを出しながらで完成させることができました。 特に当り判定のメッセージのプログラムの移植に悩んでいた感じでした。', null, null),
  ('98cf5393-a66b-5f7c-b63d-6bc1a7ff2da7', '512b2f12-24bc-5afa-913a-d68b4a9f9e14', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-01-29', '16:30:00', null, '通常 / ExcelとPowerPointのいろいろな機能を学ぶ', 'いつも通り、話はとても素直にきいてくれて、学んだこともすぐに自分で確認するなど、熱心に受講をしてくれました。 PowerPointでは、ハイパーリンクの貼り方、SnippingToolの出し方（Fn＋Prtscr）、Ctrl＋Cの使い方、オーディオの貼り付けを新たに学習しました。 表示される文字列とリンク先のURLの文字列を自分で変えられることを面白がっていました。 Excelでは初めての関数として、SUM関数とRANK.EQをやってみました。SUMはすぐに覚えられたようでしたが、RANK.EQの方は一緒にはできても一人では難しそうとのことだったので、Excelで何ができるか知っておくと自分で調べたり質問したりできるから、まずはそれを目標とするように説明し、納得していました。 絶対参照は、完全に理解したかどうかはあいまいですが、感心していました。 数式以外の連続データのオートフィルは面白がっていました。', null, '盛り上がり: あたらしいことを教えるたびに、面白がってくれていました。'),
  ('c58dd7d4-3f9e-547f-bf47-1426d6aa9b25', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-01-29', '16:30:00', null, '通常 / ロブロックス体験', '今日はスクラッチの予定でしたが、ロブロックス体験してみたいのことだったので、そちらを進めました。普段はロブロックスを触れたことがなかったが、マイクラをやっているおかげで、操作感覚はすぐに慣れていきました。基本操作のショートカットキーもすぐに使えこなせて、自分で登っていくアスレチックを作っていきました。夢中に取り組んでいたので、まだ先の内容ですが、ジャンプ力アップのコードを取り入れて、さらに遊びこんでいきました。既存のゲームも紹介したら、タイムアタックに取り組んで、授業が終わってもしばらくはやっていました。2月から始めるにあたって、操作に慣れているようであれば、倍速で確認テストを取り入れて複数のレッスンを最初のうちはよいかもしれません。', null, null),
  ('81192875-a202-56cb-b1b2-347b8821ac03', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-01-15', '17:30:00', null, '通常 / エラー直し', '問題では台形の計算問題でつまづいていましたが、計算式を教えることで解くことができました。 また、変数の入れ替えも新しい変数を作成する必要なことを教えることで進めることができました。 終盤は集中力が切れ気味でしたがレベル2の途中まで進めることができました。', 'レベル2の続き', '盛り上がり: くじ引きでは小のお菓子を当てており、うれしそうでした。
備考: 送信ミスのため再送'),
  ('fa4a9feb-a343-5d8a-8ae9-c902a2d2bba9', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-01-29', '17:30:00', null, '通常 / Excel検定対策', '自宅でしっかりと模擬問題4、5をやってきたようで、いずれも80～90%以上とれた、とのことでした。 今日の問題も、わりと難しかったと言いながらも96%とれていて、満足そうでした。 わからない問題も、自分でメニューなどから探して設定できるようになったようです。', null, '盛り上がり: ここ数回の伸び率がよく、本番もいけるかも、と嬉しそうでした。時間も余裕をもってできているようでした。'),
  ('484b5df2-b369-5610-9f58-526bbe35f934', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-01-29', '17:30:00', null, '通常 / 小技使用作品作成', '授業開始後しばらく使用する小技を決めかねていました、一度体力ゲージの小技を開きますが、結局まみ先生に決めてもらう形で目玉の小技作成に取り組み始めます。 アレンジとして目玉を拳銃や、みたらし、あんこの団子に変えていました。 団子のイメージの作成は手書きでこだわって作成していました。', null, null),
  ('fea9fc22-f410-5c34-9510-d668112df726', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'f8ed407c-471f-52b9-9a31-249d9595d863', '2026-01-30', '16:30:00', null, '通常', '前半とてもやる気がなく「わからない！」と嘆いていたが、理屈を説明してやらせるより、答えを一緒に見ながらまず動くものを作ってみると食いついてくれた。答えを見ながら作ったコードを完成した後に、一つずつ解説すると少し理解したようだった。本人は今のscratchについていけてない感じがしているので、「わからない！」と嘆いた時はまず、動くものを一緒に作って成功体験を積ませてあげるのが大事かもしれない。', null, '盛り上がり: 後半は良かった。それでも集中力は終始切れ気味だった。
備考: 彼はつまずいたら一気にやる気を失ってしまうので定期的に答えを見せてからそれを解説した方が身に付くかもしれません。あと塾の先生みたいと言われました。'),
  ('a8c6994e-2d57-50eb-867a-4c7899e53d97', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'f8ed407c-471f-52b9-9a31-249d9595d863', '2026-01-30', '17:30:00', null, '通常', '一人で解かしてもすぐ集中力が切れてしまい、立ち上がって歩き回ってしまう。なので答えを一緒に見ながらまず動くものを作ってあげると集中してくれた。あとから解説をするといつもよりも飲み込みが早かった。いつもよりスピーディーに進んでことが嬉しそうだった。その後もさらに集中して解いてくれた。', null, '盛り上がり: 終始ワクワク
備考: 彼も要くんと同様、つまずいたら理屈で説明するより、まず答えを見せて一緒に作ってあげたほうがいい。成功体験を積むとやる気が倍になると思います。'),
  ('d607a234-87c2-5a3c-a4f1-d197483106c6', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-01-30', '18:40:00', null, '通常 / 基礎の再習得', '基礎をしっかり身に着けるため、過去にやった題材を復習しました。最初は「やったことあるから」と乗り気でなかったですが、「同じものでも、もう一回やると力がつくよ」と説明すると納得して始めてくれました。素材のみのまっさらから始めましたが、矢印キーで動かす、旗が押されたときに隠すといった超基本部分は自力でできました。それ以降、作ってみては動かし、「何がおかしい？」という問いかけにより修正をしていきました。例えば、初期座標の設定や、コスチュームを「右」に戻すなどを追加しました。 クリアやゲームオーバーの条件については少し難しいので、一緒に考えました。いきなりコードを作ろうとして詰まっていましたが、「まずは言葉で表現してみよう」と伝えて考えてもらい、そこからコードに変換するスタイルを取りました。 (例：アル君が歩いていて、アルごんに見られたらゲームオーバー。 歩いている→右キーが押されている、 アルごんに見られる→アルごんのコスチューム＝「左」) また、イコールという演算子を案外理解していなかったので、「～と～が同じ」という言葉で表現しました。そして、言葉で表現する際に、「誰が」という主語がすり替わりがちだったので、明確にさせていきました。 希空くんは英語と日本語を両方話すこともあり、特定の言語で深く考えるという経験が一般的な人よりも少ないのではないか、と考察しています。細分化にともなう言語化をじっくりとしていくことが、成長につながると考えます。', null, null),
  ('e2b78a04-6991-5059-b782-420e438d9d85', '10db50c3-a153-502a-b455-c67362b9871c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-01-31', '17:30:00', null, '通常 / roblox', '前回の体験で基本的な操作は身に着いたので、初めてのテキストスクリプトを書くレッスンをやりました。コードに出てくる英単語にもあまり抵抗はなく、飲み込みよく進められていました。最後はprint関数を含めてきちんと動作確認をして、見せてくれました。来週はチェックテストから始められそうです。 授業が終わったあとは、Robloxでひたすらオリジナルゲームを作っていました。素材を探してきて、車を運転するゲームを長時間にわたって(全部の授業が終わった後も)作っていました。ゲーム作成がとても楽しく熱中しているようです。ただ、授業中はテキストプログラミングをやってメリハリをつけようという話はしました。', null, null),
  ('36ad921c-5b17-56cc-b425-8996e5ca70bc', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-01-31', '17:30:00', null, '通常 / 自由製作？', 'Robloxの予定でしたが、scratchで作りたいゲームがあるとのことでそれをやっていました。たまごっちにインスパイアされた「惑星っち」を作っているそうです。太陽系の惑星のキャラと、本家にもあるようなお世話(ご飯、お風呂、掃除など)のボタンを作成していました。集中して手を動かし続けていました。ただ、隣でゆづきくんが放物ジャンプをやっていたので、ときどきヒントを出すなどしていました。', null, 'タイピング: 毎パソが近づいている話をすると、ゆづきくんと一緒に練習していました。'),
  ('4a73772a-98f1-594a-a831-ebb8a9763252', '40a476bc-72a5-5bdc-ab75-e89d5310b442', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2026-01-24', null, null, '通常 / エラー', '【エラーで学ぶレベル②】07数字の入れ替え、実際の箱と消しゴムを使っての理解はできたが、スクラッチで実現するのが難しかったようです。 急にやる気をなくしてゲームをして気分転換、おしゃべりに熱中をしていた。再度07数字の入れ替えをやろうと言ってもなかなか手をつけなかったので、もう少し早めに他のエラー修正をやってもよかったと思う。', null, '時間帯: その他'),
  ('03149d00-ac64-5c60-b5c3-7316b59d35d4', 'dbe3dbc6-eb44-5cf8-b4f8-2bf2348e73cf', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2026-01-24', null, null, '通常 / エラーで学ぶ、バグ修正', 'エラーで学ぶレベル②は、すべてクリア。12の1～10までの積で最初に「0」が入っていることに気付いたが、そのまま他をいじってしまったので少しはまった。一緒に最初から見直して気がつくことができた。レベル③は疲れたーとのことでパスし、バグ修正の背景チェンジをおこない自力でクリアできた。', null, '時間帯: その他'),
  ('9edeac95-909b-5953-9044-ef44518deff7', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2026-01-23', null, null, '通常 / エラーで学ぶレベル②', 'エラーの現象を確認しないまま、いじりはじめていたので、現象をまず見てそれから取り組んでもいいね と言ったらしっかり現象を確認してエラーの原因をさがしてくれました。 レベル②は、自力でクリアできました。時間いっぱい集中したようで疲れたーと言っていました。', null, '時間帯: その他'),
  ('a17f6c77-47d6-56d9-8b9b-2c8f45adc86f', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2026-01-23', null, null, '通常 / エラーで学ぶレベル③、バグ修正', 'スクラッチをクリアして、くじ引き参加を選択しました。 スクラッチは久々のようでしたが、レベル③もすんなりクリア。アレンジも加える余裕がありました。 バグ修正も少し考えただけで思い出したようで、背景チェンジ、ジャンプともクリアできました。', null, '時間帯: その他
盛り上がり: 久々にスクラッチを触ったようで、思い出しながら楽しんでいました。'),
  ('cf4473c8-41fa-5fd1-9311-bb223de5d7f1', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2026-01-31', null, null, '通常 / Webサイト制作の提案書づくり', null, null, '時間帯: その他
盛り上がり: エクセル検定が終わったとのことなので、本日はエクセルはお休み。今日は、はるくんが個人的に依頼されているWebサイト制作について提案書づくりを進めていました。Webサイト作りに関しては、私自身の知識・経験をある程度伝えたりアドバイスしたりしていました。'),
  ('14a027e7-a1ee-570c-b029-cce9d496d82e', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-01-31', null, null, '通常 / Excel30時間マスターを進める', '始めは前回の続きのページを読むよう言いますが、丁寧に読み進めていたので、さっと章の最後まで読んで章末の問題をわからないところがあったら教科書を読み返すor聞く感じで進めました。 SUM関数については問題なさそうでした、グラフのオプション設定は少し不安なところがあります。 章末問題は問2まで終りました。', '2章の章末問題続き', '時間帯: その他'),
  ('88e46ef3-39bf-56a0-96cd-e8b9c35bc473', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2026-01-31', null, null, '通常 / イラスト', 'タイピング検定登録されていたのですが、本人はやる気がなしとのことで、タイピング練習は結局しませんでした。今日は一応プログラミングの回として登録されていましたが、スクラッチよりはイラストをやりたいとのことだったので、スクラッチでお気に入りのゲームを少し（というか結構、、、）遊んだ後にアイビスペイントで、自分の思うがままにイラストを描いていました。イラストは、ゲームをして楽しむように取り組めるようなのでやはり幸四郎君には合っていますね。', null, '時間帯: その他'),
  ('f3261e8e-310c-5671-83ba-1e27993cdb87', '2758b49a-c2b1-5cd0-9b37-3b988f2a5a09', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2026-01-31', null, null, '通常 / タイピング、基本操作コース７復習、基本コース9', '基本操作コース７復習として、点数表示のカウンターの使い方(変数)。使い方なども忘れていなかったので口頭確認とコード箇所の確認をして終了。 基本コース9ジャンピングゲームを新規で作成。ジャンプ、敵の動作、当たり判定まで作成ずみ、敵キャラの動作については今までにないコードを使用したので次回、少し復習をしたい。残りはスコア表示、ゲームオーバー、サウンドなどを整えてゲームとしての完成を目指したい。', null, '時間帯: その他
タイピング: 慣れないツールのせいか、積極的に使っていた(お迎え待ち時間)。 スピードよりミスを少なくなくして確実にタイピングしていた。'),
  ('06bff449-dc8a-506d-9d78-3eb3c7396ffb', '1c7005cc-2815-558f-993a-9c7617d34c44', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2025-12-02', '16:30:00', null, '通常 / 検定課題', 'とても楽しげにやっていた。だが、乱数について説明した後に自分でブロックを探すよう促したが、すぐ答えを知りたがっていた。なるべく考えてもらうように促した', null, '盛り上がり: 苦戦しながらも楽しそうに解いていた。'),
  ('73f400a3-d44f-5d71-b9d8-ae48ecbf2793', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2026-01-31', null, null, '通常 / ロブロックス', '私自身久しぶりに大貴君のロブロックスを見たのですが、前回見たときからほとんど進んでいなかったように思います。やはり、よくわからないから、なかなかやる気がでないということは言っていました。今日は、特定の床に触れたらジャンプ力を高くしたり、歩くスピードを速くするっということを教えました。スクラッチでいう、「〇〇に触れたら」と「パラメータを変える」だけなのですが、スクラッチだとこれが面倒くさい。というか、一人でその仕組みを理解しようとしても、（大人でも）かなり難しいので、ひとつひとつ細分化して教えました。繰り返し使って覚えるようなものだと思うので、次回また同じことやらせてもうまくできない可能性大だとは思いますが、これはこれで仕方なくて、レッスンを進めていくしかないと思います（文法を覚えて問題は解けても、英会話はできない、みたいな感じ）。少しずつでも前にすすめたらと思います。', null, '時間帯: その他'),
  ('b7d437cd-19af-5ca7-9b8b-80cfbf7a0968', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2025-12-02', '17:30:00', null, '通常 / 小技シリーズ', '真面目に取り組んでいた。スペースキーでビームをためる論理演算は初見では理解できなかったみたいだが、完成した後のアレンジはとても良かった。猫が1秒おきにどこかに行くスクリプトを活用し、ビームがあたったらスクリプトを止めるアレンジをしていた、', null, '盛り上がり: 楽しそうだった。'),
  ('8e1fe6dd-beef-5494-b718-90ff9d02fa5d', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-01-31', null, null, '通常 / バグ修正', '始めは先週の途中だった"50で終了"の続きに取り組みました。 終了後、バグ修正の問題に取り係りますが、どう直したらいいかわからないと言う状態になってしまいました。一つひとつどんなブロックが必要か一緒に考えながら進めることで背景の遷移の問題は解くことができました。背景の番号を判定に組込むというところまで教える必要がありました。 ジャンプの問題は最初Y移動のブロックを変数の変更ブロックに変えるなど迷走していました。変数をY移動ブロックに組込めばよいのでは？とヒントを出しながらで進みますが、落下の方のプログラムで変数を使用せずに解決しようとしてしまっていました。 -1をかけることで-にすることができるということをブロックを切り分けながら教えることで完成させれました。 連続ジャンプにも興味があったようです。', '連続ジャンプ？', '時間帯: その他'),
  ('471d9012-36a0-598c-ad34-341943d0c333', '40a476bc-72a5-5bdc-ab75-e89d5310b442', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2026-01-31', null, null, '通常 / エラーで学ぶ② 7数字の入れ替えの復習、バグ修正', '先週できなかった、エラーで学ぶ② 7数字の入れ替えを再度復習としておこなった。 コードの流れに近い図を見せて何をするかを伝えた、そのまま自分のPCで見せながら教えようとしたら、進んで自分のPCでコードの再現をした。 図をみながら、丁寧にコード作成をしたせいか一度でクリアできた。 バグを修正は、順調に背景チェンジ、ジャンプともクリアできた。 背景5を作成して、階段の設置、のぼることもでき、コインまで設置していた。', null, '時間帯: その他
盛り上がり: エラーで学ぶの復習は、少し嫌がっていたが自分が書いた図を見せて、見本をみせるね。と言ったら少し興味をもったようで進んで復習をおこないクリアすることができた。とてもうれしそうにしていた。 その後のバグの修正で元々持っていたスキルが当てはまったのかとても楽しみながら背景５を作成した。'),
  ('655de64b-f136-5cdb-bff3-252d25a04b9f', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2026-01-31', null, null, '通常 / 自作ゲームの作成', '自作のサボテンを育てるようなゲームを作っていましたが、色の変化がうまくできないということで、相談にのりました。色変更ロジックがとにかく複雑で、かつ、スクラッチだと色もRGBの値を１０進数で扱ったりしていて、直感的に、リストに定義されている数字からどんな色なのかを判断しづらかったりして、解析がかなり難航しました。ついでだったので、RGBは16進数で扱うことが多く、10進数、１６進数の簡単な変更方法や、今後JavaScriptをやることから、１６進数に慣れ親しんだほうがよいとアドバイス的なこともしておきました。結局、色変更ロジックでは、RGBの範囲を超えてしまうようなことがあることがわかりました。マイナスになったり、0xFFFFFFを超えてしまったり。そこはあきらかにおかしいので、修正をしようとしたところで時間になってしまいました。来月からはエクセルになるのですが、時々こういったアドバイスができればと思います。', null, '時間帯: その他'),
  ('fcfd6c01-afe0-5db1-85bf-eca9d73c0ed9', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2026-01-31', null, null, '通常 / バグを修正', 'エラーで学ぶはレベルまで完了していた。レベル③より、バグを修正をやりたいとのことでバグを修正をおこなった。背景チェンジに時間をかけてクリアした。不等号の向きを間違えていたが、自己チェック(数字の半角、全角チェック)時に不当後の向きが逆になっていることに気付いた。背景チェンジはクリアした。 そのあとは年末におこなったゲーム大会のゲームなど攻略方法を教えてくれた。', null, '時間帯: その他'),
  ('ac16c1a7-8cf1-5eca-9aa1-a0057faeba0c', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-01-31', null, null, '通常 / [バグを修正して!]シーンをかえる＆ジャンプ', '背景の切り替えに挑戦しました。最初はどこから手を付けるか迷っている様子でしたが、「背景を変える役割のブロックはどれか？」と問いかけ、紙に「背景が1から2に変わる条件」をパラパラ漫画のように書き出すことで、背景が変わる条件を見つけることが出来ていました。ただ最初に考えていた条件は「右端に着いただけ」だったので、「右端に着いただけだと、次がどの背景かPCは迷わないかな？」という質問をしました。その結果、自分で「現在の背景が〇のとき」という２つ目の条件を見つけられていました。 ただ、座標と変数への理解があまり出来ていなかったです。特に変数の「～ずつ変える」と「～にする」の使い分けができなかったり、まだ学校でやっていない、「負の数の掛け算」の考え方に戸惑っていましたが、「ジャンプした分だけマイナス方向に移動したい」というイメージを共有することで、変数に「-1」を掛ける事を理解して、なんとか形にはなっていました。', '今回は「ジャンプの回数」を変数で置き換えるところまでやりました。次回は、高さを変数にするところから始めると良いと思います。', '時間帯: その他
タイピング: タイピングは準1級に相当するほどよくできていました。1級まであと2点という結果には非常に悔しがっていました。一方で、スピードを重視するあまりホームポジションが崩れがちで、ミスが続くと「おわる」を押してリセットしてしまう場面も見られました。
盛り上がり: タイピングが好きなようで、予定の15分を過ぎても「まだやりたい！」と言っていました。
備考: タイピングは、速さを意識しすぎて点数が落ちてしまう事があるので、少しずつホームポジションへ意識を向けるよう声をかけてあげると良いのかなと思います。'),
  ('45d8b731-d8d7-5805-8560-1da4316bc465', '31feac25-f850-5d21-8e43-ed4d7badb6a0', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-01-31', null, null, '通常 / [バグを修正して!]シーンをかえる＆ジャンプ', '問題のあるブロックをすぐに見つけ、自力で「このブロックが怪しい」と言っていました。背景が切り替わらないバグの修正では、最初は「ステージの背景の#番号？」という少し複雑なブロックを使って条件式を作っていましたが、よりシンプルな「背景の番号」ブロックを紹介したところ、スムーズに受け入れてくれました。背景2から4への切り替えは自力で構成できましたが、背景1から2への条件が抜けていたためうまく動作せず、「1から2の時はどう教えあげたらいいかな？」と問いかけることで、完成させることができました。 後半のジャンプは、変数の理解に苦戦していました。「『高さ』という変数（箱）の中身を書き換えること」と「実際のキャラクターのy座標が変わること」を混同してしまい、変数の中身を変えただけで満足してしまう様子が見られました。そこで「箱の中の数字を変えただけで、スラボーのy座標は変わる？」と一緒に動作を追ったところ、変数の中身を変えただけでスラボーは移動しないことに気づいてくれました。理解してからは、難しいとは言いながらも自力で完成まで進められていました。', '「ジャンプの回数」を変数で置き換えるところまでやりました。次回は、高さを変数にするところから始めると良いと思います。', '時間帯: その他
タイピング: 今は人差し指だけをメインに打っていますが、自身で「全部の指が使えればもっと早くなる」と言っていました。「毎日パソコン入力コンクール」へ参加したいとは言っていましたが、申し込みがされていなかったので、保護者の方にComiruを確認いただくよう伝えました。
盛り上がり: 背景が変わらないバグよりも、ジャンプした時にキャラクターが地面に埋まってしまうバグに夢中でした。'),
  ('1baef97b-8ec8-5dc1-85c7-21a551369e20', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-01-31', null, null, '通常 / [バグを修正して!]シーンをかえる＆ジャンプのアレンジ', '予定していた「シーンをかえる＆ジャンプ」のアレンジを、既に自宅で完成させていました。障害物を動かしたり、特定の色に触れると跳ね返るアレンジをしていて、「これ以上はアレンジできない」と言い切っていました。 予定を変更して、以前自分が作成した「ジオメトリーダッシュ」というゲームをアレンジしてさらに難しくする作業に集中していました。特に「自動ジャンプ装置」の作成では、ピンク色のジャンプ台は完成させていたものの、より高く跳ぶ黄色い装置には最後まで苦戦していました。ずっと自分で遊んでは、調整を繰り返していました。', '本人はゼロから作るよりも、完成してある作品を分解してアレンジすることが好きなようなので、引き続き「ジオメトリーダッシュ」の続きか、新しい作品に取り組むと良いと思います。', '時間帯: その他
タイピング: 準2級に相当する非常に速い速度でしたが、入力ミスで点数が伸び悩んでいました。「速さよりも正確さを意識した方が点数が高くなるかも」と伝えたところ、その後は正確さを意識して何度も挑戦していました。
盛り上がり: 自分がアレンジした作品を紹介してくれる時が非常にワクワクしていました。また、ジオメトリーダッシュの難易度調整中は、新しく作ったギミックを何度も嬉しそうに見せてくれました。'),
  ('19979c43-6971-5517-835f-1e364dd9eeb2', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '39c367bc-400f-521c-85a3-5b6d9099f4a3', '2025-12-11', '17:30:00', null, '通常', 'ゲーム自体にはかなり意欲的に取り組み、高得点を出すことができていました。 影武者もそこまで詰まることなくコンスタントに作り上げられていたと思います。', null, null),
  ('2c52bcc5-f125-54a7-9a96-c930aa9ed852', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'f8ed407c-471f-52b9-9a31-249d9595d863', '2026-01-30', '17:30:00', null, '通常', '放物線にジャンプさせるお手本のコードを参照しながら解かせた。周りの友達にちょっかいを出されても集中力を切らさずに解いていた', null, null),
  ('461a678c-5fba-5345-b87f-273b42f12969', '726bac59-fe00-5b0b-a344-344f40441b6d', null, null, '2026-02-01', '16:30:00', null, '通常', 'あまり喋らない子と聞いていましたが、周りに友達がいると自分のコードを見せたりしながら楽しそうに解いていました。問題を解くスピードが祥太くんより遅く、からかわれていましたが「スピードを競うものじゃない」と自分のペースでしっかり解いていた。ステージ変移のコードをヒントを出しながら教えたらとてもスラスラ解けていた', null, null),
  ('4f40519f-5bd9-5d7a-b27d-8a94a0881a07', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-02-02', '17:30:00', null, '通常 / キラキラボールかくれんぼ！', '今回も授業前に来て、始まる前に終えました。前回、2月までの進んでも欲しい目安(ドキドキ洞窟探検！できれば、シューティングゲーム前編まで)を自ら進んでやってくれました。今回は、サーバー側とクライアント側でRemoteEventで使うイベントが異なるとのことでしたが、何となく違うの認識まで理解できていたので良かったです。この内容は複数回使って覚えた方がよい内容なので、今後出てくるときにスムーズに使いこなせ要にしていきましょう。その他の新しい関数Destroyやエフェクトなどはすぐ理解できたそうでした。', '洞窟かシューティングゲーム', null),
  ('5adfa69c-5e68-598f-b0d5-da8cce4c7acd', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-02-02', '16:30:00', null, '通常 / 自由創作', '自由創作の条件を話すと、さっそく手を動かして作成を始めました。ストーリーはイメージできたようで、「アル君がダイヤを取ったらクリア」「サメに当たると体力が減る」「銃弾に当たったら即死」という処理を自然と作れていました。最初は要らないスプライトを隠すことや、一度ダメージが入ったら1秒待つといった細かいポイントも気づけていました。 ただ、「ずっと」の中に「もし～に触れたなら」を置くはずのところで、内側と外側が逆になってしまっている場面がありました。外側から内側に向かってコードが働いていくということを説明し、「ずっと」を外側に置く理由をわかってもらいました。 また、「表示する」「隠す」で制御すると良い所で「幽霊」を使ったことでバグっていました。ゲームが終わったら強制的に幽霊効果が0になってしまうことで、見えなくしたいものが見えていました。次回はまず、これらの使い分けについて押さえたいです。', null, 'タイピング: 毎パソの練習を初めてやりました。ローマ字入力は慣れないようで、ローマ字表を見ながら頑張っていました。スピードはまだゆっくりですが、ミス0で正確に打つことができていてよかったです。'),
  ('d8714668-03ad-57a6-a3f3-fb42affcae64', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-02-02', '16:30:00', null, '通常 / 自由創作day', '自由創作dayの説明を終えたら、すぐさま作り始めました。内容を覗くと、使用例の宝探しをそのまま作ろうとしていたので、これにどう追加したいのか聞きました。そしたら、ランダムで宝（コイン）を探すゲームを作りたいのことだったので、大枠はこのテーマで進めていきました。今回は、ポチ袋の中にランダムにコインを配置するコードを作りました。一人で作っていると、「えーわかんない」口走る場面があるので、こちらからやる手順を細かく分けると自力でもコードを組み立てられました。3択にする場面では、「ではないなら」と乱数のコードは持ってこれますが、組み方に苦戦していました。こちらから変数で乱数を制御することを提案しましたが。乱数の幅を１～３にすることなどは勇作くんから決められていました。現在、コインのランダム配置はできましたが、初期化の際に、ポチ袋がずれたままになるので、そこをまだ使っていないメッセージで修正していきたいです。', null, 'タイピング: 最初は、全然やっていなかったので、かなりいやいや気味でしたが、やり始めると、何回もやりたいとなっていました。両手のポジションを置けていますが、左手は、2本の指でした打てていません。'),
  ('f633dd83-9468-53bd-8dc9-9361add04590', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-02-02', '16:30:00', null, '通常 / 自由創作', '自由創作の概要を話すとすぐに作り始めました。「サメから逃げろ」のようなものをイメージしているようです。「魚がサメにつかまったらゲームオーバー」「15秒間逃げ切ったらクリア」という仕様を、言葉にして伝えてくれました。そして、スタート画面とゲーム画面を分けたいようで、「ゲーム画面になったら」はどうすれば作れる？というように疑問を自分から質問しながらできていました。ここで、「背景が～になったとき」ブロックを覚えました。そのあと、「15秒経ったら」の処理を作りました。タイムを変数で数えることはわかり、タイム=15ならゲームクリアとすることはできましたが、タイム自体を増やさないといけないことを見落としていたようです。次回、そこから進めたいです。', null, 'タイピング: 実際に毎パソに参加するかわかりませんが、練習として毎パソのホームポジションをやりました。勇作くんと競うようにやっていました。'),
  ('fc733379-2551-57ba-99c9-723b161f928a', '1c7005cc-2815-558f-993a-9c7617d34c44', null, 'f8ed407c-471f-52b9-9a31-249d9595d863', '2026-02-03', '16:30:00', null, '通常 / アルスタジオ/自由制作DAY', '条件を一つずつクリアしていくように指導した。わからない内容になると集中力が切れてしまうので、わかるところから着実に進めていった。ローマ字のタイピングに挑戦していた。最終的に初級の内容は完成した。', null, null),
  ('9288aa56-a8f6-5aeb-b979-5362da3778d7', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'f8ed407c-471f-52b9-9a31-249d9595d863', '2026-02-03', '17:30:00', null, '通常', '晴くんが作成したステージに僕が参加しようとしたが、robloxの制限で13歳未満はサーバーを立ててユーザーと交流できないらしく、悔しがっていた。調べたところ、13歳になるまでどうしようも無いらしいです。robloxで出来ることを教えてもらいながらワールドの作成を一緒に行なった。とても楽しそうに説明してくれました。', null, null),
  ('2f050ebc-b018-5d5b-abed-ec80faa9edc2', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-02-03', '16:30:00', null, '通常 / 自由制作（ミッション達成を意識して）', 'クローンはあまり学習したことがないということだったので、どんなときに使うものなのか、アルスタジオで「クローン」で検索していくつか見ていきました。「キモ目玉」と「まゆねこを探せ」が面白かったらしく、何度も繰り返して楽しそうに見ていました。 「クローンを作る」と「クローンされたとき」をペアで使って、どんな効果が得られるかを納得させてから作成に入りました。 海の中に飛行機がとぶということをテーマに、エンジン音や飛行機の外観にこだわって熱心に編集していました。 飛行機が着水する動きにもこだわって、細かく調整をしていました。', null, '盛り上がり: 乗り物の動きにこだわる秋くんらしく、丁寧にスプライトを作りこんでいました。'),
  ('fc4934b1-de03-5dca-b982-7a2b21cb7f2c', '1da24088-9441-50c6-ac58-79e18ef5cc01', null, 'f8ed407c-471f-52b9-9a31-249d9595d863', '2026-02-03', '17:30:00', null, null, '16:00頃から教室に来ており、ずっと飽きることなくパソコンをいじっていた。自由制作の方は特に詰まることなく解けていた。最後の方はrobloxが気になりだしていた。', null, 'タイピング: 今日初めてマイパソにチャレンジしていた。タイピングはとても早く検定を受けるかもしれない。ブラインドタッチはまだできていないが、練習すればすぐできそうな雰囲気でした。'),
  ('bc303fdb-a0b3-583e-abbb-3743261db575', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-02-03', '17:30:00', null, '通常 / 自由制作は上級を行いました。使うキャラクターや背景の設定を行っていました。クローンも変数も普段から使っているので問題なさそうでした。', '教室の自由制作の目的を話ましたが、条件を読んで10分くらいで「海の中をくらげが動く」「変数とクローンを使っている」という作品を完成させてしまいました。 本人はコンテストの作品の作成を進めたがっていたので、そちらを許可したところ、残り時間は熱心に取り組んでいました。 スプライトを手書きでかいていて、とまっているときと動いているときのコスチュームを変えているところが可愛くできていました。ただ、止まっているときに揺れている状態なのが、右に動いた時にも反映されてしまうことにしばらく悩んでいたので、状態を表す変数の状態をよく確認するよう指示しました。（変数を表示するところまでは自力でやっていましたが、都度状態を確認するところまではいっていなかったようです） ダンシング変数の初期値を見直したり、変数を変更するタイミングを調整することによって、最終的に動くようになりました。 緑の旗を押してもゲームが動き出さず、外で一度クリックしないといけないというところは、提出後にプレイしてもらうにはちょっと不利なようにも思われるので、おいおい対応していきたいところです。 作品自体はスクラッチで作成しているようなので、折を見てアルスタジオと共有するよう勧めたいと思います。', null, 'タイピング: 参加する、と言いながらも少しだけ練習してすぐにScratchに入っていました
盛り上がり: オリジナル作品の作成を純粋に楽しんでいるようでした。 授業後は、晴くんとやすなりくんと、ロブロックスで盛り上がっていました。'),
  ('4995b514-7943-500c-805a-b8360bdff738', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'd45d6c5d-18cd-5aa2-99ea-932c81442c55', '2026-02-03', '16:30:00', null, '通常 / 自由制作（ミッション達成を意識して）', '自由制作の上級を行いました。一から作るのは大変とのことだったので過去に使ったゲームを元にテーマに寄せて作り変えました。どのゲームを元にするかをいろいろ触っている最中で力尽きてしまい後半30分くらいはゆっくり色々なゲームで遊びました。エクセルの時の方が集中して取り組んでいたのでスクラッチはのんびり自分のペースで取り組んでいきたいです。', '次回のロブロックスは、ちゃんと授業をするよ、と伝えて、本人も「わかりました」と返事をしていました', 'タイピング: コンクールへは参加しないとのこと'),
  ('e42a299f-5f4a-5594-8a4b-cc1b4f48daf9', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, 'd45d6c5d-18cd-5aa2-99ea-932c81442c55', '2026-02-03', '17:30:00', null, '通常 / 自由制作（ミッション達成を意識して）、コンテストに向けた作品づくり', '自由制作は上級を行いました。使うキャラクターや背景の設定を行っていました。クローンも変数も普段から使っているので問題なさそうでした。', null, 'タイピング: タイピングコンクールに向けて集中して練習していました。練習の段階で2段が取れていたので前回よりも段アップができそうです。'),
  ('551dc88d-8a2e-58bc-988e-e1ddbf486084', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'd45d6c5d-18cd-5aa2-99ea-932c81442c55', '2026-02-03', '17:30:00', null, '振替 / 自由制作（ミッション達成を意識して）', '後半は自由制作の中級を行いました。アルくんが溺れないようにする？ゲームを作成していくようです。ステージのデザインを浅いところ、深いところと分かりやすいようにデザインの変更を中心に行っていました。イラストコースも始まるとのことなのでイラストの時間に書いた背景なども利用できたらいいかもしれません。', null, 'タイピング: 前半は少し長めにタイピング練習(和文)を行いました。途中変換を使っていたので正式な記録が取れていませんが、長い単語や文より短い単語の方がやりやすそうだったので次回は和文ではなく壮太くんと同じものの方が良さそうでした。'),
  ('ba3ec073-9df0-5688-9c81-e1999e172868', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-02-05', '16:30:00', null, '通常 / 自由創作day', '自由創作の時は基本的に素材をじっくり選んでからテーマを考えるので、今回もBGMから背景をネット検索している場面がメインでした。途中、海がテーマだったが川の背景でよいものが見つかったので、それを軸に考えていました。少し怖めのBGMが見つかり、スプライト側も亀のコスチュームを持ってこれていたので、次回からコードに移れそうです。最後に、白背景が一体化していモノを透明にすることが時間でできなかったので、そのサポートからです。', null, null),
  ('79a3142a-05ce-586d-8e2e-da6de3822b00', '57f45872-1f3e-5540-b676-bf9023444e39', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-02-05', '16:30:00', null, '通常 / 自由創作DAY', 'いつも通り始めて数分はゲームで遊んで集中できていませんでした。 制作物は既存のジオメトリラッシュをリミックスして作成を始めます。 海の感じを出すために障害物の色を変えていましたが、細かい作業が多く、苦戦していたようです。 背景と障害物の色を変えて海の感じを出して、本人は完成だと言っていましたが、さすがにそれだけではダメだとメッセージを使用してなにかプログラムを追加してみようと伝えたところで今回は終了しました。', '自由創作続き', 'タイピング: 三級までとれたようです。'),
  ('0eacb392-7081-58e7-8b43-0248fa55623e', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-02-05', '16:30:00', null, '通常 / 自由創作DAY', '授業開始後数分はこたろうくんとゲームで遊んでしまっていました。 ジオメトリダッシュのリミックス作品を元に作成を始めますが、障害物や背景の色を変えただけで作業を終了してしまい、ゲームで遊び始めてしまいました。 しばらく声を掛けますが、作業に戻ることはできませんでした。', '自由創作続き', null),
  ('33b42caf-c5db-5193-8f28-7e3c8a6105f2', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-02-05', '17:30:00', null, '通常 / 自由制作day', '自由創作中級を取り組みました。初めに、背景を選んでいましたが、海面の背景が見当たらなかったので、自作して白波立つ浅瀬のイラストを作っていました。そのイラストを、褒めたら、自信をもって良いデザインに仕上がりました。そのあと、ネットからの画像の方法を教えて、潜水艦を選びました。潜水艦にのって、遊ぶゲームになりそうです。今回は、ゲームのスタート画面のイラストまで仕上がりました。', null, 'タイピング: 久しぶりでしたが安定していました。'),
  ('3627a41b-d51c-579b-9fde-f376fe20ceb7', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-02-05', '17:30:00', null, '通常 / 自由創作DAY', 'タイピング終了後、上級で作成を開始します。 潜水艦の探索ゲームを作成し始め、潜水艦自身の周囲だけ明るく見せるために背景透過を使用してスプライトを作成しようとしますが、しばらく苦戦していました。 しばらく試行錯誤した後、自己解決できたらしくスッキリしていました。 今回がこの課題初日ということでここまでで満足したようです。', '自由創作続き', 'タイピング: 授業開始後数分取り組みました。
盛り上がり: Excel三級合格とのことで喜んでいました。 二級への挑戦は難しそうとまだ様子見したい様でした。'),
  ('08d98a3c-5ad1-5c54-a7de-0facf1490812', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-02-05', '17:30:00', null, '振替 / 自由制作day', '最初に、魚をクローンを使って複製するところまで始まりました。クローンが増えるたびに、連なっていて、長いウミヘビのように見えました。そこで、端についたら背景が変わるようにしたいのことでしたが、構想に何度も変わってしまうバグがありましたが、睦月君は「何秒待つ」を入れて対処していました。それでは、バグが完全に治っていなかったので、一緒に考えていきました。ずっと触れていて、何度も背景が変わってしまうことは睦月君は気づけていたので、「ではないまで待つ」を導入してあげました。そしたら、触れるたびに変わるようになったので、そこからどうゆうときに変わるのか増やせていけたらよいですね。', '中級の紙はファイルに挟んでおいたので、続きはそこから持ってきてください', 'タイピング: 指使いは本数が限られていますが、速いです。小指まで使えるようになったさらに早くなりそう'),
  ('a12242e9-baea-5aa0-8516-8a2d7e07b84a', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-02-05', '17:30:00', null, '通常 / 自由創作DAY', 'タイピング終了後、たいようくんが戦国時代の水軍のゲームを作成することに触発されたのか、同じく水軍のゲームの作成を始めました。 しばらく軍艦のスプライトの作成にこだわり、作成物をたいようくんと共有したりしていました。 なかなか進みはよくなかった様に見えます。 今回はスプライトの作成だけで終了しました。', '自由創作続き', 'タイピング: タイピング画面を開いた後、そばで見られていると緊張するということで離れましたが、あんまり進みはよくなかったようです。'),
  ('72dd6808-5c20-5a65-9e5d-5cfdecca8864', 'b91baeb5-4a26-5308-bc47-e0a265723227', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-01-31', null, null, '通常 / 【体験】', 'お母さんと来室。眼鏡をかけていましたが、あまり視力が良くないのか、コード画面を拡大して見ようとする動作が多くありました。 学校の授業でスクラッチを少しやったそうで、基本操作のネコの動きは、コスチューム以外は知っていたようでした。ゲームではマイクラが好きだそうです。 どうくつダイヤはすぐにクリアできたので、難しくしようと敵を増やしていましたが、敵の動きを速くしすぎてクリアできなくなり、かなり時間を使って調整していました。 クリアしたときの終了感を出すため、背景と音楽を作成していました。音楽は初めて扱ったようで、楽しそうに選んでいました。 タイピングは問題なさそうで、マウスも初めてといいつつ、ホイールも含めてよく使えていました。 移動とジャンプで背景画像の編集のコピーや大きさの変更などを学習しました。背景を編集したあたりで50分経過し、疲れを見せ始めたので、コンテストのゲームをいくつか紹介して終了しました。前半集中しすぎたのか、最後は結構お疲れでした💦', null, '時間帯: その他'),
  ('03399466-6d3a-594a-a18f-7508f61dafbc', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '7c6bdbc6-3838-5e84-bf07-a26ee6bfe976', '2026-01-30', '16:30:00', null, '通常 / [バグを修正して!]シーンをかえる＆ジャンプ', '「[バグを修正して!]シーンをかえる＆ジャンプ」よりも、前回の復習として「綺麗な残像の作り方」を再度学び直したいと言っていたので予定を変更しました。ブロック一つひとつの役割を質問すると、自分の言葉でしっかりと説明できているので理解はできていると思います。 その後に「[バグを修正して!]シーンをかえる＆ジャンプ」の変数を使ったジャンプができているか聞いてみたところ、自信を持って見せてくれました。ただ、空中で何回もジャンプが可能なバグが残っていたため、「ジャンプを送った後にどうなってほしい？」と問いかけたところ、何度も悩んで「↑キーが離されるまで待つ」という条件を自分で見つけ、完成させることができました。', null, 'タイピング: スピードが速く、本人も自信を持って取り組んでいます。ただ、手が小さい事もあり、手が大きく離れて片手を使いがちだったり、特定の指に頼ったりする部分がありました。
盛り上がり: ゲームがとにかく好きで、少し目を離すとゲームをしてしまっていました。しかし、「これが失敗したら戻ろうね」といった具体的な切り替えのルールをあげると、本人も納得しやすく、スムーズに学習に戻ることができました。'),
  ('e2e23ace-cd89-51e1-80d2-33ee339170af', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-02-06', '16:30:00', null, '通常 / 自由制作/初級', '海をテーマにした自由制作に取り組んでいました。海に関するフリー素材を探すとき、サイト名にフリーと書いてあっても登録が必要な物があることを伝えると驚いていました。いらすとやの絵が気に入ったようで多用していました。 海の中でクリックしたときにジャンプして障害物を避けるゲームを考えていましたが、「メッセージ」の使いどころで悩んでいました。 ただ後半はアイデアが固まらなかったからか、どんどん条件をクリアしたゲームを作って次の級に進もうとしてしまったため、「１カ月かけてみんなに楽しいと言ってもらえる作品を作ってみよう」と伝えました。', '引き続き自由制作を行いたい。今回、そこまで作りこむ様子がないまま中級に進んでしまったので、本人の気力があれば初級を作りこんでいきたい。', 'タイピング: 授業の最初に10分ほどタイピングをしていました。あと少しで1級に届きそうでしたが、前回同様、特定の指に頼ったりする部分がありました
盛り上がり: プログラミングとは関係がないですが、塾でのクラス分けテストの結果を嬉しそうに報告してくれました。'),
  ('bd8b7987-c36e-5052-bc34-0d126460b0e1', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'f8ed407c-471f-52b9-9a31-249d9595d863', '2026-02-06', '17:30:00', null, '通常', '冒頭の会話を作成していた。クイズ形式のゲームを作ろうとしていた。コスチュームの制作に夢中だった。スクラッチ内のコードに来週の自分へのメモを残していた。', null, null),
  ('bbc2e4d9-f620-5035-b27c-cd5e7d3c1a4a', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-02-06', '16:30:00', null, '通常 / 自由制作/初級', 'フリー画像を調べる際に、サイト名にフリーと書いてあっても登録が必要な物があることを伝えました。また、良真君とおすすめのフリー画像サイトを紹介しあっていました。 自由制作は少しだけ山をテーマにした作品もやりたがっていましたが、最終的には川をテーマにした作品を作ることにしていました。 背景スクロールのやり方が分からなかったようで、アルスタジオ内の作品を見て確認していました。', '引き続き自由制作を行いたい。', '盛り上がり: 自分が作った物に名前を付けていて楽しそうでした。
備考: 祥太君がどんな内容のゲームを作ろうとしているか分からなかったので次回聞きたい。'),
  ('50c70588-22ff-565a-9498-75f7e56e1fb3', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'f8ed407c-471f-52b9-9a31-249d9595d863', '2026-02-06', '16:30:00', null, '通常', '前回に比べると集中していた。自由制作ということもあってワクワクしながらのびのびやっていた。サメのスプライトに当たったらゲームオーバーになるゲームを作成したいらしい。', null, '盛り上がり: 前回よりかなりワクワク'),
  ('a366f51c-5a84-53f8-948b-4406cdd1e5b1', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'f8ed407c-471f-52b9-9a31-249d9595d863', '2026-02-06', '17:30:00', null, '通常', '宝箱に宇宙船が触れたら開くゲームを作っていた。敵を追加して、それに触れたらゲームオーバーになるようにしていた。かなり高度なゲームを作っていた。少しヒントを教えてあげるとサクサクゲームが作れていた。ただ時折集中力がきれてしまいがちだった。', null, null),
  ('c2688551-08ea-51bb-b573-5ae46fc3bcb3', '10db50c3-a153-502a-b455-c67362b9871c', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-02-06', '17:30:00', null, '通常 / 自由制作/上級', '「床を壊しながら深海に人間が潜っていくゲーム」を作っていました。 酸素や宝石などの機能を付けたいと言っていて、「取った宝石を魚に売りさばいて酸素を得る」機能も付けたいと言っていました。 自分が作りたい機能を実装するには何をしたらよいかが明確に分かっており、全く悩むことなく進められていました。変数も完璧に使いこなせていました。 3Dで作成することも考えていて授業の後には「Minecraft classic」で3Dのゲームについて勉強していました。', '引き続き個人製作を行い、3Dの制作も視野に入れています。', '盛り上がり: 新しいゲーム性を考えているときが楽しそうでした。'),
  ('aa342c71-756d-55e5-8c1a-dc963a8b5a56', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-02-06', '17:30:00', null, '休み（未対象）', null, null, null),
  ('bbdfc0ff-cff6-5ee3-9ce2-d79b854c3eea', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'f8ed407c-471f-52b9-9a31-249d9595d863', '2026-02-06', '16:30:00', null, '通常', '掛け算の答えを正解した場合に次の背景に進むゲームを作っていた。次は掛け算の問題をランダムで出題できるように改造するらしい。BGMや背景にこだわっていて、ゲーム自体の学習はあまり進んでいなかった。', null, null),
  ('e5f13384-57fd-51cf-8562-83b69aae6d85', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-02-06', '18:40:00', null, '休み（未対象）', null, null, null),
  ('c7f4330a-a900-5cf3-a29e-3cbeaa773eb2', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-02-06', '18:40:00', null, '通常 / 基礎の再習得と自由製作', '前半は、基礎固めの復習としてやっていた「だるまさんが転んだ」を完成させました。 ・メッセージ「クリア」を送ったら→このスクリプトを止める ・「クリア」を受け取ったら→音を終わるまで鳴らす→全てを止める という処理を作りました。その際、 ・メッセージを送ったときと受け取った時の処理が頭の中で混ざっていそうだったので整理しました。その際、口頭だけでやると覚えていられないかもしれないため、紙に書いて穴埋めをする形式をとるとスムーズにいきました。 ・何種類かある「止める」ブロックの使い分けを押さえました。 ・「音を鳴らす」と「終わるまで音を鳴らす」の使い分けも押さえました。 後半は自由製作に入りました。ゲームの内容を決めるときも、まずは言葉にして明確化していきました。普通の風船を割った時とダミーの風船を割った時の処理を、それぞれ分けてプリントの裏に書きました。背景やスプライトも置いて、実際の作業を少し進めることもできました。', null, null),
  ('e6b0f8ee-1183-5c53-a1c4-7d7c77092654', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-02-06', '18:40:00', null, '通常 / roblox', 'if-else文の入ったスクリプトを扱いました。スクラッチの「もし～なら、でなければ」と対応を取って理解できたようで、あまり詰まるようなことはありませんでした。主人公を追いかけてくるオオカミのキャラクターを使って、運頼みで選ぶはずの橋の正解を見抜くギミックを作ったりもしていました。', null, null),
  ('ca73c752-c46b-52a5-ad07-c6ec66c42ae9', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-02-07', null, null, '通常 / 自由制作/上級', '突然、ゲームを作ることになって戸惑う様子は見られたが、「上からサメや宝箱が降ってきてキャッチしたりよけたりするゲーム」を作ることにしていました。 条件のステージの変更はスタート画面に、変数は潜水時の上下の動きをリアルに再現するために使用していました。ボタンを押していないと沈んで行ってしまう動きがリアルに再現できていました。 サメのコスチュームを反転させるために回転したら逆さまになってしまう問題に悩んでいましたが、回転回転方法を左右のみに限定するブロックを教えたらスムーズに使いこなせていました。 途中で大きな問題にぶつかることなく自立して進められていました。', null, '時間帯: その他
盛り上がり: 新たなゲーム性を考えて作っているときが楽しそうでした。'),
  ('dba0429f-849b-57a8-afa9-0ef9d4817614', '40a476bc-72a5-5bdc-ab75-e89d5310b442', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-02-07', null, null, '通常 / 自由制作/初級', '授業が始まった時にはもう自由制作を始めていました。どんなゲームを作るか聞いたところ「ヒラメと熱帯魚がダンスをしてタイミングよく方向キーを押すゲーム」との事で、いわゆるリズム天国の様なゲームを作ろうとしていました。 ただ、役割を理解しないままリストを使っていて、変数でよい部分を遠回りして実装している部分がありました。そのような部分は本人のしたいことを注意深く見てあげて、必要がないようであれば「こっちを使った方が簡単じゃない？」と近道を教えてあげると良いです。 リストをどのように使うのか聞いてみましたが、「スペースが押されたときにタイマーの値を追加する？」ことしかわからず、その追加されたリストがどのようにゲームに使われるのかまでは理解できませんでした。 後半は思うように動いてくれず少し嫌になっていたので次回、続きからやるように勧めました。', '今回の自由制作の続きからお願いします。', '時間帯: その他
盛り上がり: 自分のミスに気付いて直せたときに楽しそうに笑っていました。
備考: 使わないブロックをそのまま放置してしまったり、他のブロックへの影響を考えずに進めてしまい、自分でもどのように動くか分からなくなっている部分があるので、１つ1つ確認しながら進める必要があると思います。'),
  ('fbf345bb-040b-5b56-8aee-54ba5f55174d', '28d52d6e-7571-5090-a2d9-492c997b719e', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-02-07', null, null, '通常 / 自由制作/初級', '中級をやりたい様子だったので、早めに初級を終わらせて中級に取り組むと言っていました。最初の方はゲームの内容が決まっておらず、「魚型の超高性能の潜水艦」を作るために既存のコスチュームをアレンジしていました。ふじまる号と命名していて楽しそうでした。 ゲームの内容を中々教えてくれず、「完成してからのお楽しみ」と言っていましたが最後には「敵と戦って早く倒した方の勝ち」ゲームを作っていると教えてくれました。 条件にある基本操作コース06の内容からは、「クリック」をやりたいと言っていて、青い物体をクリックしたときにCP01(おそらく敵の名前だと思います)を登場させる時に使うと言っていました。', '本人は最初の方は早く中級をやりたいと言っていましたが、初級の製作に熱中していたのでおそらく引き続き初級をやると思います。', '時間帯: その他
盛り上がり: 主人公であるふじまる号を書いている様子が楽しそうでした。'),
  ('87822024-1ca1-5bfb-9baa-6e3fecef908e', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2026-02-07', null, null, '通常 / Webサイト作成', 'エクセル2級向けの練習を提案したが、検定おわったばかりで、エクセルは小休止したいとのこと。いまお願いされているWebサイト作成の事前準備的なものをすすめることにしました。具体的には、マウスポインタを通常のものではないデザインで表示されるようにしたことと、Webサイトをひらくと、画面上部からひらひらと雪のようなものが舞い落ちてくるような動的な動きのあるものをつくっていました。途中、生成AIの力を使っていたようですが、良いのか悪いのか、生成AIの出力がよろしくなかったようで（多分嘘だったり、憶測で勝手に進められてしまって、コードがぐちゃぐちゃになったんだと思う。あるあるだと思う。）、これにだいぶ懲りたようで、もうAIは使わないようにするかも、みたいなことを言っていました。最初のうちは自分の力でやってほしいので、ある意味よかったのかもしれません。', null, '時間帯: その他'),
  ('ca6f235b-d6de-5f2f-b203-7c1ef6e3f773', 'dbe3dbc6-eb44-5cf8-b4f8-2bf2348e73cf', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-02-07', null, null, '通常 / 自由創作DAY', '上級を選択して開始しました。 一定時間逃げつづける"お魚サバイバルゲーム"の作成を始めました。 オープニングのムービー内の魚の動きや効果音など拘って作成していました。 放物線の動きを魚に付けたいということで、作成した動きのプログラムを見せながら一緒に作成しました。 泡の動きにも流用して作成しようとしますが、クローンで動きの変数が共通なことによるおかしな動きの修正しようとがんばっていました。', '自由創作続き', '時間帯: その他
タイピング: 授業終了後に少しだけ触りました。 ちょっとだけ見ましたが、あまりタイピングは慣れていないようです。
盛り上がり: 家で作成してきたオリジナルのゲームを見せてくれました。 かなり自宅でもスクラッチを触っているようです。'),
  ('a87505f0-8991-5681-b9ef-56f6b3e15b0a', 'b91baeb5-4a26-5308-bc47-e0a265723227', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2026-02-07', null, null, '通常 / ②基本操作コース_02', '基本操作コース_02は、個別で着実に理解をしていた。 名前を使って各コードを組み合わせた作品を作りたいと思いますが、本人は他の新しいことをやりたいとも言っていたので復習と新しいことをやるのが良さそうです。', null, '時間帯: その他'),
  ('b9ea506d-643f-50e3-997d-49757e193fdd', '2758b49a-c2b1-5cd0-9b37-3b988f2a5a09', null, '9975e2b1-2972-5720-830a-6de5deffeb24', '2026-02-07', null, null, '通常 / 基本操作コース 09 条件分岐', 'ジャンピングゲームの途中までだったところを最後まで終わらせました。条件分岐の使い方も教えれば使うことができていました。基本的には次に何をするべきかを教えてあげればできていた印象でした。ジャンピングゲームを完成させるときにメッセージの使い方を軽く教えましたが、なんとなくは使えている様子でした。', null, '時間帯: その他
盛り上がり: スプライトを選択するとき楽しそうに選んでいました。'),
  ('d9f46a88-6ed3-5ea1-99af-2245ecf87633', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-02-07', null, null, '通常 / 自由創作DAY', '最初に初級と中級どちらがいいか聞き、中級を選択しました。 どんどん深く潜っていく潜水のストーリーゲームを作成し始めます。 拡張機能を使用したかったらしく、音声合成を使って操作キャラがしゃべるようにしていました。 また、クローンを使用して移動する魚の魚群を作成していました。 シーン変更後に魚群のスプライトを停止させるのに困っていたので、スプライトのスクリプトを止めるブロックを教えました。', '自由創作続き', '時間帯: その他
盛り上がり: 画像に対して背景透過の塗り潰しで回りの余分な部分を削除できることにおどろいていました。'),
  ('53329196-8bb9-5e08-9972-b9b783459c80', '5b56509a-ab37-5b95-9b2b-2750525ad8a5', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-02-07', null, null, '通常 / Excel', '前回2章の章末問題途中までだったので、その途中から取り組みます。 特に問題なく解くことができ、3章も章の内容を軽く読んで章末問題に取り組み、こちらも問題なく解けたようです。', null, '時間帯: その他'),
  ('06b0e0d6-1980-5312-8a2d-706e9e757e65', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2026-02-07', null, null, '通常 / ロブロックス', 'いつものように、「ロブロックスで遊ぶ」と「レッスン」が半々くらいな感じで、時間を決めて進めました。遊んでる時は鋼士郎君に話しかけられていろいろとロブロックスの話をしていたようです。レッスンでは、今日は、ブロックを前後に往復させる処理をプログラムで作りました。for文の使い方、whileとforの違いについて学びました。レッスンとしては、１週間に１度触れる程度だと、記憶の定着もすくないだろうし、片手間な感じで、ものすごい集中して話を聞くという感じではないので、難しい部分（ステージ２で増えてくる）についてはまだ全然身についていないなと感じます。ただ、基礎的な部分はまあ大丈夫だとは思います。', null, '時間帯: その他'),
  ('9f9d742b-d270-5efc-ac1d-f65b35351778', '31feac25-f850-5d21-8e43-ed4d7badb6a0', null, '9975e2b1-2972-5720-830a-6de5deffeb24', '2026-02-07', null, null, '通常 / 自由制作DAY', '自由制作の中級をしました。 一度ゲームの案をひらめいた後はあまり引っかかることもなくスムーズに作ることができていました。中級の条件の一つになっていたクローンの扱いもしっかりできていて、スムーズに作っていました。リスト以外使ったことのないブロックはないようですが、単体ではなく複数のブロックの組み合わせについては本人に確認していないのでわかりません。', null, '時間帯: その他
盛り上がり: 魚の色を自分オリジナルに変えることを楽しんでいました'),
  ('c2572c18-efeb-5085-9c0a-054f1113a9e8', 'c47b4046-9872-56fc-a811-2f1cb7d0d1a0', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2026-02-07', null, null, '通常 / ②基本操作コース_03', '基本操作コース_03をはじめからおこない、基礎的なことの理解を確認しながら、パレメーター変更、複数のコードを組み合わせてのアレンジをしました。 次回は自由創作もやってみる？と聞きましたが、あまり自信がないようでした。 ただ、基本操作コースのパラメータ変更、アレンジの追加も集中してできたので、基礎操作コースと並行して自由創作もやっていけると思います。', null, '時間帯: その他'),
  ('8a053474-c282-5b58-9138-d0ab7b988291', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '9975e2b1-2972-5720-830a-6de5deffeb24', '2026-02-07', null, null, '通常 / 自由制作DAY', '上級の内容でも引っかかることなく進めることができていました。 思いついたゲームの内容的にシーンの切り替えが難しいようでその部分の修正は必要なように見えました。', null, '時間帯: その他
盛り上がり: プログラミングを楽しいと言っていました。'),
  ('9abca0f8-444d-5bad-8b8f-6c8def6fd8f9', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '9975e2b1-2972-5720-830a-6de5deffeb24', '2026-02-09', '16:30:00', null, '通常 / 自由制作', '画像効果系はすべてを止めたときにリセットされることと代わりに「表示する」「隠す」を使うことを教えると使うことができていました。体力の判定を「=」でしてしまっていたので超えると終了判定が働かない場所は修正が必要だと思います。「ずっと」の付け忘れで判定ができていない場面が多かったので、次回は判定が必要な時に「ずっと」が必要なことを意識してもらいたいです。', null, 'タイピング: ローマ字が不慣れなようでキーボードを見ながら入力をしていました。スピードはゆっくりですが、確実に入力することができていました。
盛り上がり: 画像を引き延ばしたりなど画像を加工することを楽しんでいました。'),
  ('cecec5d8-98cd-5280-a1e7-8510790932c0', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-02-09', '16:30:00', null, '通常 / 自由創作day', '今回は、サメから逃げきれた食べられた後の演出を主に作っていきました。家で勝ち負けの背景は作ってきてくれたので、それをメッセージでつなぐ処理は自然とできていました。しかし、魚サメの消えるタイミングがずれて、消えなかったり動いたままだったりする複数のバグがあったのでそこを重点的に直していきました。「15秒逃げ切れたら勝ち」と仕組みでしたが、実際は17秒立ったらクリア画面に遷移になっていたので、2つの改善点を共有しました。１つは、岳君は17になったら切り替わることに気を取られていたので、その差の2秒のずれがコードで見るとどこで生まれているか伝えました。すると、セリフの2秒だと気づけて直せました。2つ目は不等号の仕組みについて、＞はその数を超えないと条件を満たさないと伝えると、自ら「14」にすればよいと気づきました。そこから、「ほかのスプリクトを止める」も自分で使いこなせていたので、大方直せました。残るは、「食べられた時の魚が消えるタイミングが遅い」バグが残っているので、そこ直すことともうひとつ展開が欲しいです。', null, null),
  ('2dab8d2a-d1c0-53db-aed2-9c4cd51eddda', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-02-09', '16:30:00', null, '通常 / 自由創作day', '前回やったことを完全に忘れていたので、まずは振り返りました。コインのランダム配置がしたことは思い出せました。そこで、バグとなっていた「旗押したら初期化されずに位置がずれたまま」をはじめに直していきました。初期化の同時処理が重なって先のコードが進んでいたことは理解しづらかったので、メッセージで順序をつけてあげように切り替えたら本人も理解してくれました。そのダイバーをむらっちに変え、ポチ袋に進む方向を選べるようできるコードを作ってもらいました。矢印を押したら、その方向の場所へ進むことは最初は「もし」の重ねて作っていたが、コインの時に「でなければ」を使ったことを思い出し自ら修正できました。歩数については自分で自己修正していたが、あまりにもでかすぎるので修正が必要です。ほかに、当たった時とはずれたときのリアクションもつけられたら良いなと思います。', null, null),
  ('8bc2b3fb-9897-5552-ab0f-d46c00be6451', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-02-09', '17:30:00', null, '通常', '本日はやる気のないただ遊びに来た日でした。全然ゲームを切り上げようとはせず、自分で決めた区切りもだらだらそのままやり続け、さぼった日でした。', 'マイパソ金曜本番ですM9 ドキドキ洞窟探検！', 'タイピング: 苦手だからって1回で済まな。何回もやるように勧めましたが1回で辞めました。'),
  ('6ae564be-373a-51a4-b8b3-29bac210ecc9', '1c7005cc-2815-558f-993a-9c7617d34c44', null, 'f8ed407c-471f-52b9-9a31-249d9595d863', '2026-02-10', '16:30:00', null, '通常', '回答をなるべく見せずに、自力で解いてもらった。わからないところは答えを見せて、集中力がきれないように授業を進めた。スタンプを5,6個押せていい感じに進んだ。', null, null),
  ('974e4eec-44b4-5009-8586-7c152717a73f', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, 'f8ed407c-471f-52b9-9a31-249d9595d863', '2026-02-10', '17:30:00', null, '通常 / 自由制作', '今日はロブロックスをやることなくscratchに取り組んでいた。木の見た目の敵のモーションの作成を5コマくらいで作成していた。となりの晴くんと楽しく話しながら自分の課題をこなしていた。', null, null),
  ('830deac3-24cb-517c-a359-51382a97263b', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'f8ed407c-471f-52b9-9a31-249d9595d863', '2026-02-10', '16:30:00', null, '通常 / 自由制作', '自由制作の上級を進めていた。自分でデザインしたキャラクターをうごかしながらステージを変化させていた。となりの奎歩くんにアドバイスをされながら、話しながら作成していた。', null, null),
  ('48a1277d-c516-56f1-9aa4-05e414f35664', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, 'f8ed407c-471f-52b9-9a31-249d9595d863', '2026-02-10', '17:30:00', null, '通常 / robloxオンデマンド', '最初のロブロックスの授業でしたが、本人は余裕そうでした。まだ最初の内容なので、コードをガツガツ書く感じではないのでわかりませんが、オンデマンドに対する集中力はあると思います。', null, 'タイピング: かなり集中していた。教室に来てから20分くらいはずっとタイピングをしていた。
盛り上がり: 実際にrobloxをいじってプレイできるので楽しそうだった。'),
  ('807283eb-5cc7-58d1-92c9-b4fafabb4bd8', '726bac59-fe00-5b0b-a344-344f40441b6d', null, 'f8ed407c-471f-52b9-9a31-249d9595d863', '2026-02-10', '16:30:00', null, '通常 / 自由制作', '飛行機を左上から右下に動かすコードを作っていた。飛行機が端についた時にステージが変わるようにしたいらしかったのでヒントを与えながら教えた。今日はとても静かだった。', null, 'タイピング: とても集中して取り組んでいた
備考: 祥太くんがいると楽しそうに喋りながら学習するかもしれないです。'),
  ('9e46ffab-23f1-5d77-99c9-de35752adcd9', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-02-05', '17:30:00', null, '通常 / 自由制作（ミッション達成を意識して）', 'お題に対してのアイディアはわりとすぐに出るようで、楽しそうに作成していました。 やりたいことがたくさんわいてきて、収拾がつかなくなるところもあるので、今回の作成を通して、的をしぼった作成を学んでいくのもありかもしれません。', null, '盛り上がり: U13大会の未来賞の賞状をもってきて見せてくれました！ モチベーションもあがっているようで、楽しそうに作成に取り組めていました。'),
  ('3079bb0c-1962-5499-b966-32b88e83bb6c', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-02-05', '17:30:00', null, '通常 / 自由制作（ミッション達成を意識して）', 'Excel検定が受かって嬉しそうでした。 今日は久しぶりにScratchの作品作りに取り掛かっていて、軽くやってみると言いながらもかなりこだわりを持って作成していました。 潜水艦のまわりを四角ではなく丸く切り抜いて照らすところに悩んで、時間をかけて解決していました。', null, '盛り上がり: 久しぶりに、ストーリー系ではないScratch作品を作っていましたが、見た目などにこだわりをみせて熱心に作成していました。'),
  ('2cf7e036-04ec-520a-85df-a4c51e9d1b24', '57f45872-1f3e-5540-b676-bf9023444e39', null, 'f8ed407c-471f-52b9-9a31-249d9595d863', '2026-02-12', '16:30:00', null, '通常 / 自由制作初級', '僕と会うのは初めてでしたが、うまく打ち解けて会話しました。常にスクラッチには集中せずに、周りの友達とスクラッチのゲームをしたり、ずっと飴を食べていました。授業内容を一緒に小さなアレンジをやろうと催促してみましたが、コードを書くことには専ら興味がないようでした。隣の塁くんが、コスチュームをカスタマイズしてくれていました。', null, 'タイピング: 今日は検定日でしたが、「ょ」を打つのに苦戦し序盤の方でタイムオーバーになっていました。syaやryoのローマ字打ちはできるが、拗音単体の入力の仕方を理解するとスコアはもっと良くなると思います。'),
  ('f7d5889e-f3a4-52e8-aebf-36a1f20f2809', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, 'f8ed407c-471f-52b9-9a31-249d9595d863', '2026-02-12', '16:30:00', null, '通常 / 自由制作初級', '自身が作ったゲームはコスチュームに著作権があるものばっかりなので、フリー素材に変更するところから始めた。だがあまり集中力が続かなかった。となりに座ってるこたろうくんのパソコンでは楽しそうにコスチュームの編集をしていた。', null, null),
  ('5f84884a-454b-55ba-abdf-a0e37af1a660', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '168c1514-32b0-599c-8e0d-9db86e72b9e6', '2026-02-12', '17:30:00', null, '通常', 'タイピングの試験が終わってから、びっちり動画を見ながら集中していた。チャプター0から4まで終わらせており、特にわからないところもなくスラスラ進でいた。先生を呼んだ時はツールの場所がわからなかった等なので、プログラミング自体でつまずいたりはしていなかった。', null, 'タイピング: 検定だったが、後ろから見る限りとてもスムーズにタイピングできていた。
盛り上がり: とても集中していた'),
  ('8ee2dc1e-aae3-59d0-a163-151919297911', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-02-12', '16:30:00', null, '通常 / ロブロックスに慣れよう', '隔週で2回目で初めは操作方法におぼつかなさがありましたが、すぐに慣れてアレンジに走りました。序盤なので、難しいことはなく、コードを動かすことはできていました。ツールからいろんなものを引っ張り出してきて、アスレチックを極めていました。最後の確認テストでは、ロブロックスの大枠に関する問題でしたが、1回目は４０％で気になりはしたが、ただの問題文を読んでいないだけで、内容は理解できていました。', null, null),
  ('3b7055ad-6953-5ab4-9a7c-d8e32846c5a5', 'f3102a36-fdd8-574f-bf3c-85723faf424f', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-02-12', '16:30:00', null, '通常 / 毎パソ大会本番/自由創作DAY', '落ち着いた後、先週お休みだったので課題について説明し、本人に中級と上級を見せた所、中級の深度移動の条件がめんどくさそうとのことで上級を選びました。 ゲームの内容は、クローンを使用した魚をつかまえるゲームを作成していました。 魚の動きは、操作キャラが近づくと離れるなど動きにこだわっていました。 ひととおり作成したあと、本人はこれで完成と言っていましたが、ステージ変更も入れなきゃだめ、と伝えるとしぶしぶ第二ステージを追加していました。', '自由創作続き', 'タイピング: 今回大会本番とのことで暫く練習してから本番に挑戦しますが、途中で周りの騒音(こたろうくん等)で集中力が切れてミスタイプしてしまい、少し泣いてしまいました。 しばらく宥め、落ち着きました。 本番のスコアは本人が途中で止めてしまったためあまり高くないとおもいます。
備考: こたろうくんとは授業終了後一緒に遊んでいたので仲直りできたのだとおもいます。'),
  ('7a48c43d-1380-5c4b-a442-ccdc2adbdb07', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-02-12', '17:30:00', null, '通常 / 自由制作day', '今回は前回に続いて、もう1艦船が書き上げていました。かなり味があるものが仕上がっていて、たいようくんから褒められていました。そこから、作品について方向性をどうするか悩んでいる場面がありました。船をクローンを使ってランダム配置をするコードをつくれていましたが、そこから発想がうまく続いていなかったです。ゲームの流れの種を少し共有してあげた方が、うまく制作が続いていくと思います。次は最初から声をかけてみてください。', null, null),
  ('13f45dcd-f511-5152-a281-7c2ae372ceea', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-02-12', '17:30:00', null, '通常 / 自由創作DAY', '前回の続きから、戦国時代のタワーディフェンスゲームの作成を始めましたが、アイデア出しに悩んでいた様で、AIを使用してアイデア出しを手伝ってもらったりしていました。 また、ゲーム内の地図のイメージなどもAI生成を使用して作成を試みたり、AIを積極的に活用していました。 途中から信長の野望にでてくるような戦闘システムの戦闘シュミレーションを別作品から持ってくるなど、構成の振れがあるような印象がありました。', '自由創作続き', null),
  ('051d0fd2-ebc5-56a2-8f66-53b453f7be90', '512b2f12-24bc-5afa-913a-d68b4a9f9e14', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-02-05', '16:30:00', null, '通常 / PowerPointのいろいろな機能を学ぶ', '前回、貼り付けたオーディオがそのスライドでしか再生できないのを気にしていたので、バックグラウンド再生の設定を一緒にやりました。バックグラウンド再生の設定をしても、オーディオを貼り付けたページになるまでは再生がされないことを確認し、全体のBGMとして最初のページに貼り付けをして納得していたようでした。 イベントスペースでゆいちゃんのサンリオお勧め動画を流す、という設定で、作成したプレゼンテーションから録画機能で動画を作る、QRコードの作成（クロームで）、見やすいレイアウトを意識するなどの課題をこなしました。', '次回はExcelの予定と予告しました', '盛り上がり: サンリオをアピールする動画、というのでイメージがわきやすかったのか、楽しんで作成してくれていました。'),
  ('edc49c7a-a089-5aac-815e-2f228c824def', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-02-12', '17:30:00', null, '通常 / 自由創作DAY', '前回の続きから取り組み始めました。 今回はスタート時のメニュー、ルール説明、難易度変更などの画面遷移の作成をしていました。 画面遷移時、どの背景ならこのボタンを表示するなどの条件のプログラムに苦戦していました。 プログラムは背景の番号を使用するといいのではと伝え、作成することができましたが、ボタンごとにどの背景なら表示できるのかでこんがらがってしまっていたので、背景名前と番号、ボタンの名前で対応表を紙に書いたら分かり易いのでは？とアドバイスしました。 その後書き込んでいき、うまく作成できたようです。', '自由創作続き', 'タイピング: 今回大会本番でしたのでしばらく練習してから本番に挑戦しました。 とくに問題なく本番にも取り組めていたようです。
盛り上がり: 家でも続きに取り組みたいと言っていました。'),
  ('e99746f0-9fca-5c3e-876b-6c27794ad167', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-02-12', '17:30:00', null, '通常 / 毎パソ本番 自由制作', '前回に続いて作品作りをしました。今回は潜水艦の動きについて制作していました。回転の動きでキーを押し終わったら自動的にまっすぐに戻っていく面白い動きを作っていました。タイピングで集中が切れたのか残りの時間はゆったり過ごしていました。塾に入れられる心配をしていたそうです。', null, 'タイピング: 20分ほど練習をしてから本番を臨みました。'),
  ('552a7754-5745-5c3f-a711-a4ea7f6e6632', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-02-13', '16:30:00', null, '通常 / 自由制作/初級', '今日は前回作っていた自由制作の続きを進めました。背景のスクロールがまだ出来ていないと言っていたのでアルスタジオの背景スクロールの作品を見て方法を学びましたが、隙間ができるバグがある度に良真君の毎パソを見に行っていてあまり進まなかったです。 どんなゲームを作るか聞いたところ「川の中でぶりを動かす、ただそれだけのゲーム」と言っていました。次回以降どんなゲーム性を持たせるか一緒に考えてあげてください。 背景スクロールは最終的には出来ていたが、荒業でやっている部分があったので要確認です。', '引き続き自由制作を行いたい。', null),
  ('8a40752d-0632-5abb-b99c-50554a10824a', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-02-13', '16:30:00', null, '通常 / 毎パソ検定受験,自由制作/初級', 'タイピングの検定を受けるまでに沢山練習をしたので自由制作の方には半分ほどしか時間を割けませんでした。前回同様、ジャンプして障害物を避けるアスレチックを作ると言っていました。 ただ、スプライトで足場を作ろうとしていて挫折していたので背景で足場を作る方法を提案しましたが、「アスレチックのアイデアが思いつかない」と言って既存のゲームを模倣してそれをアレンジする方向に代わりました。 3月の中旬までゲームが決まらないで悩んでいると制作の時間が短くなってしまうので次回くらいにはゲームの方向性を決めて制作に入りたいです。', '自由制作の内容を決めるのが良いと思います。', 'タイピング: 不安からか中々本番を受けることが出来ず何回も練習していました。あと少し頑張れば1級に届きそうでした。 検定は上出来だったようで、本人が「0か1ミスしかしてない」と言っていたので期待大です。'),
  ('840ae165-0ae9-5de8-9935-3b5670d92cbf', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-02-13', '17:30:00', null, '通常 / 毎パソ,自由制作/初級', '「陸から潜水艦にのって海に潜りに行く」ゲームを作っていました。特に困っている部分は無いと言って基本的に自走して進められていました。 唯一悩んでいた点はメッセージの名前の区別をどうつけるかで悩んでいたので「〇〇1」や「〇〇2」で区別する方法を伝えました。', '最初に必ず毎パソの検定を受けさせてください。引き続き自由制作の初級が良いと思います。また、ゲームの完成度が把握できていないので確認をお願いします。', 'タイピング: 取り組んでいる様子が見れなかったのですが、本人が準1級まではいくが1級になかなかたどり着けないと言っていました。 今日毎パソの検定が受けられなかったので次回検定を受けると良いと思います。'),
  ('852043e1-7c21-5e9f-af70-a3b782ca9578', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-02-13', '18:40:00', null, '通常 / 自由制作/初級', '今日が初の自由制作でしたが、偶然にも授業前に海をテーマにしたゲームを作っていたので、それに初級の条件を足した物を作ることにしました。 ゲームの内容は「こけすけ(主人公)が魚に奪われた彼女を探しに行く」ストーリーでした。 前回までは嫌々やっていたからか、全く進まなかったのですが、今日は自由制作だからか「この機能はこれを使えばできそう」などと夢を膨らせていたので縛られるのがあまり好きじゃないのかなと思いました。', '宝箱を置きたいが、いい素材がないのでネットで探すと言っていました。著作権等の説明が出来ていないのでそこからお願いします。', null),
  ('776bfc0f-0d0f-55f2-8781-769679253c61', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2026-02-13', '16:30:00', null, '通常 / Excel', '練習問題の3を解きました。', null, null),
  ('58bef40a-7fcc-5d3d-a015-147f2a798701', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2026-02-13', '18:40:00', null, '通常', 'だるまさんが転んだはもう飽きたらしいので基本操作コースのりんごが落ちてくるやつをやりました。前回の記録シートに「メッセージを送る」の理解が曖昧と書いてあったので再度説明したがまだあまりピンときていなかったので次はもっと噛み砕いて説明したい。', null, 'タイピング: アルファベットが表示されているタイピングだとスラスラ打てていたが、マイパソのひらがなだけのタイピングは怖いと言っていました'),
  ('70643e1b-3003-5c4b-af3f-e6132230c03f', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2026-02-13', '16:30:00', null, '通常', 'プレイヤーを追いかけてくるサメから逃げるゲームを作っていた。集中力が続かないので逐一答えを教えながら進めた。どんなゲームを作りたいかがまだ定まっていなかったので色々提案しながらゲーム内容を固めた。本人はどんなゲームを作りたいかより、いろんな動きを再現したいみたいだった。', 'サメに当たったらゲームオーバーの画面を表示させる', 'タイピング: 今日初めてタイピングだったみたいなので、まずホームポジションの勉強からさせた。プレイグラムでf,jと母音の練習をしたので、次も忘れずやらせてあげてほしい。'),
  ('3e3cfabc-693a-5f61-932c-67f92ecff740', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2026-02-13', '18:40:00', null, '通常', 'ステージの作成をしていた。受講中も躓くことなくスラスラ進でいた。3本くらい動画を進めたと言っていました。', null, '備考: 五条悟をホワイトボードに書いていました。上手です'),
  ('571b95de-78c0-5aff-b828-31673371e710', '5fc65a36-fdbb-5af5-a6f4-16080e4e37ef', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2026-02-13', '17:30:00', null, '通常', '基本操作04の復習をしました。問題文を見てからまず自分で解く姿勢があり、答えは最後に見ていた。若干答えと違う部分もありましたが、6個目の項目に一つスタンプを押しました。', null, 'タイピング: ほとんどタッチタイプでできていた。キーボードを見ないことをかなり徹底していてとても伸び代があると思いました。
備考: 小2にしてはとてもタイピングが早いので、もっと伸ばせそうです。'),
  ('b5737374-16a7-5169-9420-70ad36223664', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2026-02-14', null, null, '通常 / ロブロックス', 'まず最初に、ロブロックスのアカウントがないとのことだったので、アカウント作成をお願いしました。で、今回は、前回に引き続き、IT自由研究室のアカウントでレッスンを進めてもらいました。前回の復習からしましたが、、難しいところは特になかったようですが、役に立つショートカットキーや、操作方法の小ネタ等を教えておきました。途中まですすめていた頂上をめざせはすぐに終わって、確認テストも簡単に１００％で問題なしでした。すぐにクイズロブロックスに進んで問題も質問も特になく時間終了となりました。', null, '時間帯: その他'),
  ('ddcb05d3-0329-5429-8cc6-97761195769e', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-02-14', null, null, '通常 / Excel', '一週間時間があいていたため思いだしながら章末問題の続きに取り組みました。 グラフ生成、SUM関数については基本的な作業は問題なさそうでした。 三章ではAVERAGE関数もSUM関数と同じように記述して使えると教え、問題なさそうでした。 じっくり読みながら進めたい様でした。', null, '時間帯: その他'),
  ('e535659a-164f-5e9b-b55e-feddef096307', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2026-02-14', null, null, '通常 / イラスト自習', 'タイピングは申し込みをしていたのですが、本人は全くやる気なしで、結局実施しませんでした。レッスンは、イラストをやるとのことで、アイビスペイントでイラストの自習をしていました。ただ、スクラッチでも使えるイラストの作成を進めていたようで、あとで、スクラッチのゲームで、そのイラストを利用する可能性があるので、その点きにとめてあげて、スクラッチをすすめるのもありかなと思いました。', null, '時間帯: その他'),
  ('f570465a-aef3-5861-be52-2f2de1ed95e9', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-02-14', null, null, '通常 / 自由創作DAY', '前回の続きから取り組みました。 本人は完成と言っていましたが、見せてもらうと背景遷移が端に触れた判定や、ゴールが無いなど結構粗が多かったので、ひとつずつこれも追加したほうがいいのでは？と伝えながら取り組みました。 背景の遷移に端に触れたらではなく座標を使って行う方法と、遷移後に場所を移動することで連続して遷移してしまうのを防げることを教えました。 修正後は、登場する魚のデザインを描いていました。なかなか上手でした。', '自由創作続き', '時間帯: その他
タイピング: タイピング大会本番だったので、しばらく練習し、本番に取り組みました。'),
  ('ef1bf50f-915b-5275-b3a9-af3ee39d869d', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2026-02-14', null, null, '通常 / webページ作成', '前回から引き続きWebサイトの作成をしていました。今回は、Webサイト作成ツール(Studio)の、有料版に登録されたとのことで、JavaScript等のコードを利用できるようになったので、StudioでそのWebサイトの作成を進めていました。生成AI(copilot)でいろいろ聞きながら進めていたようですが、中学生の段階からこのような進め方がありかどうかは、私は判断しづらいですが、生成AIでのハルシネーション（推測とかで自信たっぷりに嘘いったりとか）とか、扱いに慣れないと大変とのことは伝えてみました。', null, '時間帯: その他'),
  ('ace599ca-14a3-5793-8a40-ddb7370db3e9', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-02-14', null, null, '自由創作DAY', 'タイピング練習でかなり時間を消費して疲れていた様だったので、好きに自由創作を行なわせていました。 四角形を組み合わせて、手足をバタバタさせているようなアニメーションを作っていました。', null, '時間帯: その他
タイピング: 大会本番日だったので、授業開始後しばらく練習していましたが、ノートパソコンの不調や、取り替え後もキーボードが打ち辛いとのことで、ランキングには乗らないということを伝えた上で今日は見送りました。'),
  ('6d50b171-4c1f-5590-ad36-7e8b2c8a5c5e', 'b91baeb5-4a26-5308-bc47-e0a265723227', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2026-02-14', null, null, '通常 / 基本レッスン', '矢印キーでの上下左右移動、動くターゲットキャラに触れたら音が鳴ってスコアアップする。スコアが１０点になったらゲームクリアにする。という一連のながれを作成しました。「もし～なら」のブロックを、詳細な説明なしにささっと使おうとしたりと、全体的にはわかっているような雰囲気だったので、スムーズに進めていきました。が、反応が薄いのと、口数が極端に少ないので、正直、本当に理解できているかどうかが判断できませんでした。（「わかったかな？」と聞いてうなずいたちょっとあとに、同じようなことについて、「むずかしい、わからない？」と聞いてもうなずいたりと..、実際にしゃべったのも、２，３回のみで感情も読み取れませんでした）。教え方というか、聞き方、対応の仕方をなにか考えたり気を付けないといけないかなと感じました。また、ゆき先生情報だと、マウス操作とかもまだそんなに慣れていないので、イライラ迷路みたいなもので遊んでもらって、ちょっとしたマウス操作を遊びながら慣れてもらうとか、してもよいと思うとのこと。', null, '時間帯: その他'),
  ('87729b47-6964-52c1-85bb-31871d903d1d', '40a476bc-72a5-5bdc-ab75-e89d5310b442', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-02-14', null, null, '通常 / 自由創作DAY', '授業開始前から今回の課題とは関係ない新しいゲームの作成に取り組んでいました。 かなり集中して取り組んでいましたが、前回の作品のスコア追加だけやってみようか？と声を掛け前回の続きに持って行くことができました。 作成途中だったリズムゲームのスコア追加を同じ効果のプログラムが二つあるなどのバグを潰しながら実装しました。 その後は登場するキーの種類を増やそうとしますが、途中で諦めてしまいました。 こうしろうくんと話しながら、サムネイルの作成に力を入れていたようです、フォントに影を追加したり一部の文字を斜めにするなど実際にありそうなゲームのタイトル画面のサムネイルを作成できていました。', null, '時間帯: その他'),
  ('052ce682-9fbe-50f7-8a09-71529a991feb', 'c47b4046-9872-56fc-a811-2f1cb7d0d1a0', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-02-14', null, null, '通常 / 基本操作6/ストーリー作成', '今回でまだ二回目だったので、一対一で取り組みました。 ストーリーを作るのは得意？と最初に聞いた時、わからないと答えていましたが、実際に作業を始めると他のカードそっちのけでキャラクター同士の会話を作るなど、ストーリー作成は得意なのだと思います。 会話のやり取りをn秒待つを使用して構築していたので、それだとややこしいよね、メッセージを使ってみない？と声を掛け、他のカードの内容に触れるように促しました。 また、自分の声で台詞だけでなく効果音も作成するなど、力を入れて作成していました。 n秒かけて移動する、クリック時に動作する、この二つのカードの内容は前に使ったことがあるということもあり、今回は使用しませんでした。', null, '時間帯: その他
盛り上がり: 作成後はお父様にゆきくんと一緒に見せに行っていました。 褒めてもらえて嬉しそうでした。'),
  ('8f36ab04-eafc-5224-813e-154baaa54da7', '76019ebd-2809-5e43-b3c7-1c8834a9e170', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2026-02-14', null, null, '通常 / 基本レッスン', '前回やった基本操作コース02「文字の操作」を思い出して復習してもらうところから始めました。まだ幼稚園年長さんなので、ひとつのことに集中するのはまだ難しく、前回作ったもので遊びはじめてしまい復習にならない状況だったので、今日のレッスンをはじめました。まだ年長さんなので、覚えることをしぼって遊びながらブロックを使ってもらいました。今日覚えたのは主に３点。「キャラクターが話をすること」「矢印キーでキャラクタがー上限左右に動けるようになること」「別のキャラが動き回ること」XとYについても、きちんとわかってくれたようですし、マイナスについてもわかってくれたようです。ただ、小数点については、難しい感じでした。この３つをいろんなキャラクターで試して、楽しんでいました。（背景をサッカー場にして、サッカーボール、プレイヤー、ゴールキーパー等を動かしまくって喜んでいました）。今までで教えた中で一番小さかったので、正直どういう教え方をすべきかよくわかりませんが、今回は教えることを絞って、その中で遊んでもらいながら実際に使ってもらって慣れ親しんでもらう。というような形をとってみました。', null, '時間帯: その他'),
  ('ba860d4f-4e52-5194-918c-69cdf958edef', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-02-16', '16:30:00', null, '通常 / 自由創作day', '前回の「食べられてから魚が消えるのが遅い」バグに取り組んでくれました。変わるまでに時間がかかることが気づけていたので、セリフ分の2秒分の「待つ時間」を三津から解決してくれました。周りが録音ブームだったので音声を入れて、楽しんでいました。タイトルと髪の設問も仕上げたので、最後にみんなでゲームを共有しました。', null, '盛り上がり: 勇作君のコインを探すゲームのボイスで笑いあっていました。'),
  ('82818bba-1bba-5251-a3a0-0a09726ebd11', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-02-16', '16:30:00', null, '通常', 'ランダムに変わるコインの場所の当たりはずれを作っていきました。コインのランダムを分ける条件と同じだとヒントを与えても勇作君はピントは来ていませんでした。そこで、一緒にコインの条件のコードを振り返りました。そこで、変数の「こいん」の等式で条件を分けていることに気づけたので、当たり外れ判定のコードの作成に臨めました。そのコードに録音の音声を入れて大いに楽しんでいました。時間をかけられたけど、、、、最後にむらっちの位置関係を最前面に直すことを進めたら、見栄えよくなりました。プリントタイトルを書かせて、最後にみんなでゲームを共有しました。', null, '盛り上がり: 自分の撮る声で爆笑していました。'),
  ('4ed9c073-2ee3-5fbf-8ac1-6f41ffc56f3a', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-02-16', '16:30:00', null, '通常 / 毎パソ本番自由創作', '体力の条件式にバグがあったところを、年始のバグ直しの効果もあって、「または」＜=以下の条件を活用したコードに修正できていました。録音ブームに流されて、新しい音をいくつも試していました。ゲームオーバーとクリア時に自作の音声が流れるようになりました。最後にプリントとタイトルを考えて、共有して盛り上がりました。', null, 'タイピング: 1回の練習だけで、本番に臨みました。'),
  ('1182337a-ae0f-5a97-83ff-0be1097c888a', '2758b49a-c2b1-5cd0-9b37-3b988f2a5a09', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-02-14', null, null, '通常 / 自由製作', '自由製作初回をやりました。キャラクターを探すところから始めたいとのことだったので、フリーイラストを検索して使う方法を教えたところすぐ飲み込めていました。かわいらしい雰囲気のイラストを厳選したり、ふたりのキャラが仲良くなっていくストーリーを作ったりと、自分らしい世界観が現れた作品になりそうです。ただ、今の流れだとアニメっぽいものができそうなので、ゲームとして面白い要素も入れることを勧めました。すると二人が追いかけっこゲームをして仲良くなるアイデアが浮かびました。', null, '時間帯: その他
タイピング: 家でも練習してきたとのことでやる気十分でした。教室でも少し練習し、奥の席で集中して本番を無事に終えました。'),
  ('a95b7aae-ed4e-5f1e-8177-3e05778c446e', '31feac25-f850-5d21-8e43-ed4d7badb6a0', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-02-14', null, null, '通常 / 自由製作', '自由製作を進めました。いろいろな魚を採るゲームを作っていきました。網で魚を捕まえて、捕まった魚の種類を記録する必要がありました。そこでリストや「コスチューム=○○」の判定、影武者といったスキルをフル活用して進めていました。何も見ずに使いこなせていたので流石でした。レアな魚も用意して面白い要素も入れられていました。来週は、「では魚を採るとなにが起こるのか？」という展開を一緒に考えていきたいところです。', null, '時間帯: その他'),
  ('5a024b41-1d7b-5b40-934d-a52fcae2fba6', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-02-14', null, null, '通常 / roblox', '前回扱ったスクリプト(while,for文)の軽い修正や内容の復習をしました。一応全部やったので次回はチェックテストに行けそうですが、英語が苦手なのもあり、内容が定着しているかは少し怪しい所です。 今回はRoblox Studio へのログインに時間を要しました。 だいきくんは普段ブラウザ経由でログインしているのですが、今回はブラウザの不調により正常に起動できませんでした。 パスワードは自分では覚えられない自動生成のものをChromeに保存しているため、ブラウザ経由でしかログインできないと言っていました。 来週以降は、以下の手順だとよりスムーズだと思われます。 1.ブラウザ経由ではなく、スタートメニューからRoblox Studioを直接起動する。 2.GoogleパスワードマネージャーからIDとパスワードをコピーし、貼り付けてログインする。', null, '時間帯: その他'),
  ('460ddc9f-046d-53e3-a2d0-95892e09fae3', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-02-14', null, null, '通常 / 自由製作', '海中で酸素を補充しながら敵を倒したり宝を取ったりするゲームを作成しました。クローンを使って味方キャラ(敵を自動で倒してくれる)を実装し、自由製作上級の条件も満たしていました。ゲームの構成を自分で整理しながら、比較的自走して進められています。', null, '時間帯: その他
タイピング: 好きなだけ練習していいという説明をしましたが、早めに決着をつけたいとのことで、数回練習するとすぐに本番に向かいました。結果を楽しみにしていました。'),
  ('4e73e585-b17c-5426-936a-5f8fe70a5d4a', '28d52d6e-7571-5090-a2d9-492c997b719e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-02-14', null, null, '通常 / 自由製作', '先週の自由製作初回である程度進んでいたのですが、「どんなゲームだったっけ？」と自分でも忘れていたようでした。既に作った部分を、コードを見ながら思い出していきました。それが終わると新しい部分の製作に進みました。対戦パートで、HPが切れたらメッセージを送って敗北になるようにしていました。ただ、旗を押したときに「敗北」スプライトなどを初期状態に戻せていなかったので次回進めたいです。', null, '時間帯: その他
タイピング: まず練習をして、ゆうとくんと結果を競っていました。本番も全力を尽くしていました。'),
  ('7ef0a224-d827-51e6-9cab-9a8531f87941', 'dbe3dbc6-eb44-5cf8-b4f8-2bf2348e73cf', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-02-14', null, null, '通常 / 自由製作', 'キャラクターのスペック設定に力を入れていました。「サメは動きが速いが止まると死んでしまう」「クリオネは透明な攻撃を出してくる」など色々考え、各キャラに個性を与えていました。そのキャラを選択して、キャラのスペック変数を初期化してゲーム開始するところまで無事にできました。お迎えに来たお父さんにも進捗を見せていました。', null, '時間帯: その他
タイピング: 淡々と練習をして、本番も冷静に終えていました。'),
  ('bbc26202-253f-5082-b055-61f5529098ca', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-02-10', '16:30:00', null, '通常 / ロブロックスになじむ', '本人の希望でロブロックスの初回をやりました。アカウントがまだないので、先生のアカウントでデジタネにログインしました。 動画を見ているうちにフードをかぶって机に伏せながらみていたので、ロブロックスをやるということは、自分で動画を見て勉強するスタイルができないと、という話をすると、一応素直にうなずきながら聞いていました。 今回は、開こうとするロブロックスのゲームが重かったのか、どれもうまく開けなかったりプレイヤーを動かせなかったりで、最後はちょっとへこんでいました。ライオンパソコンがいまいち？', null, '盛り上がり: ロブロックスをやりたいという気持ちはあったようですが、自分のアカウントがなかったこと、全体的に動作が重かったこともあり、あまりイメージがつかめなかったようでした。 ただ、こちらの話は素直に聞く姿勢が見られたので、次回以降に期待？'),
  ('e09eb1b4-23c3-5ae9-b649-12435b8209d4', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-02-10', '17:30:00', null, '振替 / 自由制作（ミッション達成を意識して）', '素直に自由制作に取り掛かっていました。条件があるというのは、「自由制作」じゃないよね、とぼやきながらも、クローンで面白いギミックを作っていました。それを指摘すると嬉しそうな様子も見せていました。 エリアを作成するのがちょっと面倒そうでしたが、最後まで遊ばずに取り組めていたと思います。', null, '盛り上がり: 先生の人数に余裕があったせいか、何か発言するとすぐに先生の誰かから返答があるのが嬉しそうでした。'),
  ('8af1222e-1f01-51d4-bda7-894d1a6de39b', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'd45d6c5d-18cd-5aa2-99ea-932c81442c55', '2026-02-10', '16:30:00', null, '振替 / 自由制作（ミッション達成を意識して）', '2時間よく頑張っていました。前回の続きの計算ゲーム(?)の作成を行いました。割り算の余が出てしまうのが嫌とのことなので一緒に対策を考えました。前にいた子のロブロックスを覗いていてたまに遊ぶと言っていたので少し興味がありそうな様子でした。', null, null),
  ('54ac3ea9-ddbb-5d0b-a193-eb4910bae88c', '5fc65a36-fdbb-5af5-a6f4-16080e4e37ef', null, 'd45d6c5d-18cd-5aa2-99ea-932c81442c55', '2026-02-10', '17:30:00', null, '振替 / 基本的なスキルを学ぶ', '前回の追跡ゲームの続きを行いました。どこにどのブロックがあるのかも覚えてきたようでスムーズに行えました。音にもこだわってフリーの効果音から一緒に探しました。宇宙の知識が豊富で地球の秒速などを楽しそうに教えてくれました。次は続きのレベルアップから行えるとよいです', null, null),
  ('7717718f-ade0-5fd8-8d77-8205abf324a6', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2026-02-17', '17:30:00', null, '通常 / アルスタジオ/自由制作上級', '主人公の攻撃のコード作成に取り組んでいた。ジャンプしながら攻撃した時と、歩きながら攻撃したときのモーションの作成をしていた。コードはScratch上に転がっているコードを参照してコピペしていた。イラストは自分で作成していた。', '攻撃モーションの作成', 'タイピング: 数回練習して本番に挑んでいた。手応えはあまりないらしい。
盛り上がり: ゲーム作成自体を楽しんでいました。'),
  ('ff21421b-26d9-59b0-9079-dc689aa3336c', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2026-02-17', '17:30:00', null, '通常 / 自由制作', '主人公がEキーを押すと伸びて敵を攻撃するモーションを作成していた。前回の制作からかなり進んだように見えた。HPのコードを他の制作者からコピペして実装していたがまだ完璧に動くわけではないらしいです。', null, 'タイピング: 特に何も言わずさらっと本番に挑んでいました。
盛り上がり: ゲーム自体の制作に集中していた。'),
  ('471058ee-ebaa-58c6-8af0-ba8b9eef4aea', '1da24088-9441-50c6-ac58-79e18ef5cc01', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2026-02-17', '17:30:00', null, '通常', 'メッセージを受け取ったらを駆使して順番にキャラクターを動かしていた。ゲームよりかは物語に近い内容だった。基本的に自分が再現したい動きをコードに起こせていた。キャラクターを自分で操作できるようにするとゲーム感が増して良い気がする。', null, 'タイピング: キーボードを見ながらタイピングしていたので間違っていることにしばらく気づかず打ち続けてしまっていた。まだ慣れていなさそうです。
盛り上がり: 授業終わりのRobloxをとても楽しみにしていた。ユーザーIDとパスワードを記した紙を持参して授業終わりに楽しんでいた。'),
  ('edf3477b-ed1f-5940-9d1e-e5a7e8f265ae', '10db50c3-a153-502a-b455-c67362b9871c', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2026-02-13', '17:30:00', null, '通常 / 自由制作・上級', '前回の続きを制作、床をつくり終えて、海を追加した。床の傾斜をスムーズに上り下りできるるように調整していた。スプライト(人間)の酸素を吸う判定をつくり、海に潜るところまでできた。細かいところまでしっかり作りこんでいるので少し時間がかかっていた。', null, null),
  ('2e35ba3b-a635-5d7c-a5b5-460dca2c0fb2', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2026-02-13', null, null, '通常 / ロボロックス', 'ExcelかRobloxのどちらをやるか迷っていた。予定はRobloxだと伝えるとRobloxを進めていた。レッスン中かなり集中していた。帰る間際に制作もかなり進んだと言っていましたが内容の確認が漏れてしまいました。', null, '時間帯: その他
備考: スクラッチ以外のRoblox、Excel受講生についてももう少し様子の確認をしたいと思います。'),
  ('51050304-3ad7-557c-a550-85f18de19e49', '512b2f12-24bc-5afa-913a-d68b4a9f9e14', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-02-12', '16:30:00', null, '通常 / Excelの基本スキルを身に着ける', 'サンリオのデータ入力でExcel操作に慣れてきたので、検定を意識した勉強をおすすめしてみました。自分でテキストを見ても難しそうだったけれど、MOSがとれるといいねと支援所の人と話していたとのことで向上心も意欲もあるようでした。 これまでの作成で、基本的な操作はできるはず、と自信を持たせて、30時間マスターの実習１と２を学習しました。SUMの入力とグラフの作成は覚えていて、オートフィルもできていました。 実習2でSUMを入れる列が右端にあるため、範囲選択のし直しが必要だったり、グラフのデータ範囲が離れているところが難しかったようです。難しい、というので、この問題は何を目的としているかを説明して納得させ、シートにもメモを残させました。 タイピングコンクールも次回受けてみたいとのことでした。', null, '盛り上がり: これまでのサンリオ紹介資料作成で基本的なスキルが身についていて、できる問題が意外とあるということに驚きつつも嬉しそうでした。いろいろと資格を取りたいと前向きになっていました。'),
  ('eea7185e-2a0b-5580-8d42-a3d05c09cfc1', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-02-17', '16:30:00', null, '通常 / Excelの基本操作を学ぶ', '今日はExcelの気分ということで、グラフの作成を新たに学習しました。 説明しているときは比較的素直に聞いて、手も動かしていましたが、新規の学習が一段落すると気が抜けるのか、集中力が途切れてしまいます。 今日は前半30分はまじめにExcelに取り組めましたが、それ以降はほぼ休憩モードでした💦', null, 'タイピング: あまり乗り気ではないようです💦
盛り上がり: グラフは素直に作成して、円グラフの切り離しなどをいじって遊んでいました。
備考: お母さんがお迎えにいらして、オンラインを受ける場合の教室の通い方について聞かれたので、今の生徒さんたちには以下の3パターンの例があると話しました。 ・教室に毎週通い、そうすけくんの場合はExcelとロブロックスを隔週で学習＋オンライン ・教室に隔週＋オンライン ・オンラインのみ 今のところ、Excelは前向きに取り組んでいることは報告しました。 中学に入ってから部活を考えるため、中学生活の様子が見えてきてからコースを検討したい、とのことでした。'),
  ('c99d4dc1-8977-5650-83fb-7b864b6475b1', '1c7005cc-2815-558f-993a-9c7617d34c44', null, 'd45d6c5d-18cd-5aa2-99ea-932c81442c55', '2026-02-17', '16:30:00', null, '通常 / 条件分岐を使う', '前回の続きのキャッチゲームが早めに終わったので音楽をつくろうの制作を行いました。一緒に音階を確認したり楽器の音の違いやリズムを楽しんでいました。コードを見本と全く同じで作りたいというこだわりがあるようなので自由制作よりも見本のコードの再現の方が得意かもしれません。', null, null),
  ('65a6d536-28ce-5e70-9370-aec70fe00a6b', '337872be-4ce4-5436-88f8-5f97e8c5252e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-02-17', '17:30:00', null, '通常 / 作成している内容を意識し理解する', '自由制作（ミッション達成を意識して）', null, 'タイピング: 練習では三段一歩手前まで出せていたようですが、本番はミスがあったと少し残念そうでした。
盛り上がり: タイピングの本番だった為、30分ほどかけて真剣に練習をしていました。初段は安定して取れていたように見えたので前回よりも記録は伸びそうです。作成は背景スクロールの調整とプレイヤーのキャラクター選びを行っていました。ロブロックスと交互なので次回からはスクラッチにコメントを残して何をやったか思い出しやすくしたいです。'),
  ('78cd8503-c58b-5a62-afb4-d23e1d203e5b', '57f45872-1f3e-5540-b676-bf9023444e39', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-02-19', '16:30:00', null, '通常 / 自由創作DAY', '前回までの続きで、初級または中級の条件のどれか一つを追加してもらう方向で始めました。 いつも通りゲームを始めてしまい。集中できていないようでした。 初級の条件である基本操作6の内容でもよいと伝え、自分の声を追加することになりました。 自分の声でプレイ中とゲームオーバー時のボイスを録音し流れるようプログラムを追加しますが、ゲームオーバー時の音だけ流れない不具合を修正せずに終ってしまいました。 途中でLINEを弄りはじめるなど今回は特に他の物に目移りしてしまっていたように思います。', '自由創作続き', null),
  ('fef6500b-fd3f-5919-bd64-6cb674e2c343', '512b2f12-24bc-5afa-913a-d68b4a9f9e14', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-02-19', '16:30:00', null, '通常 / Excelの基本スキルを学ぶ', '前回、いろいろな資格や検定にチャレンジしたいと言っていたので、タイピングの体験版をやってみました。ゆっくりで良いからミスを少なく、といったアドバイスを素直に聞いて、丁寧にタイピングしていました。慣れれば1級くらいは目指せそうなので、これから半年くらい、少しずつ練習して上級の認定証取得を目指そうという話をしました。 Excelについては、サンリオの資料作成で一通りのスキルは身についているので、テキストを使って体系的に復習と未履修項目の穴埋めをすることを目指しました。 罫線は、いろいろなパターンの設定がしやすいため、セルの書式設定ウィンドウからやる方法に統一しました。そのほかの設定についても、パッと見てボタンがわかるものはそこから、ボタンが見つからないなど迷ったときは書式設定を出す、塗りつぶしは色名が出るのがボタンのみのため、そちらから、ということで納得していました。 表示形式では日付のところで、余談として曜日の出し方を見せました。難しそうな機能にはしり込みする傾向があるので、今はやり方を覚えなくても構わないことを強調し、こういうことができるということだけ頭の片隅にとめてほしいと伝えました。こうきさんの出勤表でこの機能を使っていることを見せると感心していました。 文章を読み取るのが苦手なのか、試験の時に問題を読んでできるかどうかが不安とのことだったので、基本は完成例を見てできるようにし、必要なところは文章の中から拾い出せるよう訓練をしていこうと伝えると、安心したようでした。', 'Chapter3_6から。行列の挿入は履修したので、軽く復習してから次へ。', 'タイピング: ローマ字部門の体験をしてみました。3回ほどチャレンジしてみて、準2級から2級に記録を伸ばすことができました。 毎回少しずつ練習して、次の大会を目指したいとのことでした。 和文は漢字がちょっと自信がない、といった様子でした。
盛り上がり: 非常に素直なので、タイピングもExcelも感心しながら取り組んでくれていました。'),
  ('d22fbd4d-2874-55a4-b7e3-3984aa7a0cc4', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-02-19', '16:30:00', null, '通常 / 自由創作DAY', '授業開始後しばらくはいつも通りゲームをしてしまっていましたが、初級か中級の条件のどれかを追加するだけでよいと伝えると、ネットからクジラの画像を取ってきてプログラムの追加を始めました。 その後、クジラの使用はあきらめ、スタート画面の追加をはじめました、今回は途中でゲームを開くこともなく取り組めていたように見えます。 スタートの画面を追加しましたが、ただの虹色の背景だけだったので、スタート画面だとわかるようになにか文字を追加してほしいと伝えましたが、そこで集中力が途切れてしまったようで、ゲームにもどってしまいました。 来週はスタート画面の改修とタイマーの不具合修正に取り組めるか聞いたところ、来週に絶対やると言っていました。', '自由創作続き', null),
  ('f54bfce1-7a2b-5e3d-8dd0-32e05a3643f7', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-02-19', '16:30:00', null, '通常 / 自由製作', '前回時間切れでできなかった画像透過については、方法は覚えていたようですぐにできました。 ただ、ゲームの方向性を忘れてしまったようで、再び決めなおしました。 カメが散歩するゲームを思いつきましたが、面白い展開が作れなそうとのことで、自分の過去の作品なども色々見ながら考えました。結果、【小技】超初級 きも目玉 から着想を得て、「カメが草を食べて成長し、増殖して世界征服するゲーム」にしました。 カメが草を食べる動作は作れました。ステージ番号を使って、ステージごとに違う位置に草を配置することができました。世界征服完了した地球のステージも設置して、流れが見えてきました。', null, null),
  ('636925d8-8b88-56a6-a948-076dd611a444', 'f3102a36-fdd8-574f-bf3c-85723faf424f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-02-19', '16:30:00', null, '通常 / 自由製作', '前回で一応完成したというので、そのバージョンのコピーを保存してからアレンジに取り組みました。まず、海の深さごとに違うステージを作りました。深くなる時に斜面を作ったり暗くしたり、また深海魚を置いたりと、リアリティを出していました。一方で、今回は何をするゲームなのか聞いてみると「魚を見るゲーム」とざっくりとしている状況なので、次回はプレイヤーがすることを膨らませたいところです。', null, null),
  ('d884636f-7c06-5e72-8e35-08bf793a0140', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-02-19', '17:30:00', null, '通常 / 自由創作DAY', '今回は、前回の続きから、船のスプライトの画像を描く作業をするようでした。 途中プランBも考えておくか、と別の構成を考えようとしているようでしたが、あまり内容はおしえてもらえませんでした。 たいようくんと話ながら楽しく作業に取り組めていたように見えます。 最後まで船の俯瞰の絵など、スプライトの作画作業で終りました。 このままのペースで三月中旬までに終るのかすこし心配です。', '自由創作続き', null),
  ('e8a8ab0d-6981-50f5-b31e-6eba7e144857', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-02-19', '17:30:00', null, '通常 / 自由製作', '作業対象が曖昧になりがちなので、最初に「今日は何を作るか」を確認しました。レベル選択ボタンとルール説明を見るボタンを押したときの動きを作るとのことでした。メッセージを送って表示/隠すを行ってほぼ順調にできていたのですが、一つバグが出ました。ルール説明を見ているときに、隠れているはずのレベル選択ボタンを押せてしまうようでした。コードを見てみると、ボタンを隠せてはいるのですが、それでも触れた判定が働いていました。次回はここの修正から入ることになりそうです。そうたろうくんのコードでは「マウスポインターに触れた」かつ「マウスが押された」を使っていますが、シンプルに「このスプライトが押されたとき」でもよさそうです。', null, null),
  ('75dea84f-21f7-5fd0-a78b-058698f3e1a6', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-02-19', '17:30:00', null, '通常 / 自由製作', '今まで作ったところが思うように動いていなかったので、ゲームの仕様を整理しました。深さを変えたら背景が変わるようにはしていたのですが、深さが変わっていませんでした。そこで、キーを押したら沈むのか自動で降りるのかという仕様を聞くと、自動にするとのことでした。 また、背景の切り替わりができていない部分があったのでコードを一緒に確認しました。背景を変えたあとにセリフを言うようにしようとしていましたが、逆になっていたので、どの順番でやるといいか考えてもらいました。 ゲームの本題は、潜水艦が沈んでいく中で定期的にクイズが出され、それに正解すると宝をゲットするという内容で作っていました。ここで、「ーと聞いて待つ」ブロックを初めて使いましたが、使い方にはすぐに慣れられました。', null, null),
  ('caab541e-124c-5ae8-b152-b1ec07506ac5', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-02-19', '17:30:00', null, '通常 / 自由創作DAy', '前回の続きから、操作キャラの作画から始めました。 最初にタワーディフェンスのままなのか聞いたところ、戦国無双のような見下ろし型の戦闘ゲームにする方向に変更したらしいです。 スクラッチの方から他の人が作った作品から素材を集め、描き変えつつ追加していました。 操作キャラ以外にも、背景やサムネ用の作画も行ない、プログラムの作成に入りました。 基本的には躓かずに取り組めていたように思います。 最後に障害物にぶつかった時に先にすすまなくなるようにするプログラムの作成でつまずいていたところで授業終了になりました。', '自由創作続き', '盛り上がり: 削除したスプライトの戻し方を教えると、驚いていました。'),
  ('ad1355f5-6ba2-562a-a24e-01eefcb1b529', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-02-20', '16:30:00', null, '通常 / 自由制作/初級', '今日は前回同様自由制作の続きを進めました。 どんなゲームを作るか聞いたところ「魚を操作してとげに当たったらゲームオーバーというゲーム」と言っていました。初級の条件はすべてクリアしていたので動作確認までしました。 その後、良真君とゲームを始めてしまったのでゲームオーバーの画面だけ完成させようと勧め、完成させました。 今日は全体的にプログラミングよりもタイピング、ゲームがやりたいらしくゲームとタイピングを行ったり来たりしていました。最後はみんなでゲームのチーム戦をして楽しんでいました。', '引き続き個人製作ですが、中級に進んでヘビゲームを制作すると言っていました。', 'タイピング: 良真君とタイピングで競っていました。自由制作の合間にタイピングを挟むことが多かったです。'),
  ('0364f78c-05ec-5b64-b50a-c821d77a9761', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2026-02-20', '18:40:00', null, '通常 / 単元別演習', 'だるまさんが転んだの演習で「メッセージを送る。」の仕組みをあまり理解しきれていなかったみたいなので、単元別演習Dメッセージをやりました。本人はまだ難しいと言っていますが、問題自体は解けていました。来週も引き続き「メッセージを送る。」の単元をやって行きたいと思います。', 'アルスタジオ/単元別演習Dメッセージ/D-3', 'タイピング: 前回はひらがなを見てのタイピングに苦戦していたが、今日やってみると前回よりかなり上達していた
盛り上がり: だるまさんが転んだはもうやりたくないらしいので気をつけてください。'),
  ('91214a3d-25f4-5232-9150-976f7f755829', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '7c6bdbc6-3838-5e84-bf07-a26ee6bfe976', '2026-02-20', '17:30:00', null, '通常 / 自由制作の続き', '自由制作の初級で、「陸から潜水艦にのって友達を助けに海に潜りに行く」ゲームに宝箱を追加するところから始めていました。宝箱の画像をネットで調べて持ってきていたので著作権について説明しました。宝箱をクローンで増殖させていたが、増えすぎて困っていたので違うコードで解決した。', null, 'タイピング: タイピング本番でした。気が済むまで練習してもらいました。その後本番できると言っていたので本番をやりました。
盛り上がり: 自分が作りたいゲームが残りの授業じゃ完成しないかも、と不安気でした'),
  ('f637a0e1-a33c-5e7c-8bf7-ff26b8392b1e', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-02-20', '16:30:00', null, '通常 / 自由制作/初級', '今日は前回同様自由制作の続きを進めました。 前回まで作っていたゲームで、主人公から弾が出るようにしたかったのですが、どうしても表示がズレてしまう原因を考えていました。私が修正可能か試している間に、本人は諦めてしまったようで、データも消して新しいゲームを作り始めていました。 新しいゲームは「ぎりぎりの当たり判定を使ったゲーム」で、バグを知っている人だけクリアできる宝さがしゲームのような面白い物でした。 今日は全体的にプログラミングよりもタイピング、ゲームがやりたいらしくゲームとタイピングを行ったり来たりしていました。最後はみんなでゲームのチーム戦をして楽しんでいました。', '引き続き自由制作中級ですが、クローン機能が使えていないのでどこかに使えないか相談してあげてください。', 'タイピング: あ段のタイピングの速さを自慢していました。自由制作の合間にタイピングを挟むことが多かったです。'),
  ('56f9a349-15a2-5835-aeb6-f31d535b1812', '5fc65a36-fdbb-5af5-a6f4-16080e4e37ef', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-02-20', '17:30:00', null, '通常 / 基本操作コース05_音楽を作ろう', '基本操作コース_05は音楽に興味があればやる事にしていましたが、本人が「音楽に興味がある」と言っていたのでやることにしました。 良いリズムを作るためにアルスタジオにある色々な音を聴き比べて作っていました。スペースキーが押されたときにドラムが鳴るようにしたり、ドラムを鳴らすとドラムが伸び縮みする動作も出来ていました。 段々パソコンに慣れてきたのか、最初に比べてマウスを使った操作にも慣れて、ポップアップなど予期せぬ挙動をしたとき自分で対処できるようになっていました。', '基本操作コース05_音楽を作ろうが満足のいくレベルまで言っていたら基本操作コース06に進んでよいと思います。', 'タイピング: 自分からタイピングを5分だけやると言って始めました。画面だけを見て、あまり指先を見ないでタイピングできているのが良いと思います。'),
  ('809398cc-acd5-57ce-9322-e5589a3e0a08', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-02-20', null, null, '通常 / 自由制作/初級', '前回に引き続き、「こけすけ(主人公)が魚に奪われた彼女を探しに行く」ストーリーでした。 今日は予定通りアイテムの追加と宝箱の追加をしました。宝箱は良いデザインのものがアルスタジオに無かったため、著作権の説明をしたうえでいらすとやの物を使用しました。 自由制作だからか、嫌がることもなく自分で進められていました。方向性や多くの条件に縛られるのがあまり好きじゃないのかなと思いました。', '引き続き自由制作/初級をお願いします。', '時間帯: その他'),
  ('0c38ce45-780a-5b08-9b5a-f72243130df7', 'd3885e29-ee68-501b-bf31-6c050fd50c36', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-02-20', '16:30:00', null, '通常 / 自由製作', 'スライムがサメにつかまったときに背景を変えるという処理を少しだけ作りました。ただ、タイピングで力尽きたのか、あまりプログラミングの作業は進みませんでした。', null, 'タイピング: ローマ字をあまり覚えていない状態でしたが、ローマ字表を見ながらゆっくり練習していました。わからないなりに真剣に練習し、本番まで終えました。'),
  ('8d238c65-185f-5f6f-948c-11a2beb313b9', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-02-20', '17:30:00', null, '通常 / 自由製作', '宇宙船がサメをよけながら宝箱を取るゲームの作成を進めました。 まずは、宇宙線が宝箱に触れたときのコードを作りました。ただ、最初に行う処理と宇宙船に触れたときの処理がごっちゃになっていました。そこで「このときは何をするか？」を問いかけて整理しようとしましたが、なかなか難しかったようです。使うブロックについてはこちらからかなりヒントを出して、「このブロックをどこに入れるか？」を考えさせる形で進めました。 最後に、サメを倒すためのビームやサメの仲間を作りました。', null, null),
  ('b0a51a7e-b244-58ce-ab16-2d16ca7b4996', '80660755-d846-5cdd-91a4-0ab78fe29034', null, null, '2026-02-20', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('b6ffc1f3-4c93-53b2-8c50-f6178756d2b2', '10db50c3-a153-502a-b455-c67362b9871c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-02-20', '17:30:00', null, '通常 / roblox', 'クイズRobloxが完成し、print出力を含めた動作テストまで終わったので、初めてのチェックテストに取り組みました。軽々と全問正解し、内容はよく理解しているようでした。次にレインボーロードに移り、同様に動画学習していきました。質問は特になかったですが、"script.Parent"の概念などを分かっているか、次回robloxのときに確かめながら進めたいところです。レッスンが終わった後はアルスタジオの自由製作を自主的にやっていました。', null, null),
  ('de2a714b-6247-5d62-9bee-69faf56b6a17', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-02-20', '18:40:00', null, '通常 / Excel', '検定が終わり、30時間マスターの続きを進めました。検定対策前にどこをやっていたのか少し忘れていたようですが、今日の内容はしっかり理解して進められました。', null, null),
  ('a86d9d0b-6617-5b82-91df-4fbaaddaf367', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-02-20', '18:40:00', null, '通常 / 自由製作', '自由製作dayの初回をやりました。方向性はすぐ決まり、潜水艦から釣り糸を垂らして魚を釣るゲームにしました。画像素材をインターネット検索するとき、もともと著作権のことは知っていたそうで、フリー素材の話はスムーズに通じました。釣り糸をどうやって垂らそうか考えていたので、ペンを使うことを提案してそれで進めることにしました。ペンの使い方は以前少しやったくらいでそこまで定着していなかったので、ペンを下ろすところから一緒にやっていきました。', null, null),
  ('5b4c4115-b240-51ca-bf0b-0479e58fb74a', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-02-20', '18:40:00', null, '通常 / roblox', 'プロジェクト内にオブジェクトが散乱してきたので、フォルダの使い方を復習しました。 また、printやcancollideも出てきたので、内容を覚えているか口頭で復習しました。一瞬「なんだっけ？」とはなるものの少し考えれば思い出せるようです。 本題のscriptでは、乱数の書き方が少しややこしく最初間違えていましたが、speedを〇から〇までの乱数にして座標を動かすという内容は分かったようでした。', null, null),
  ('434e6520-715c-54be-a070-41e3a12792c1', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, null, '2026-02-20', '17:30:00', null, '休み（未対象）', null, null, null),
  ('a94467d5-8638-53db-8852-cf6282fa0ad0', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, null, '2026-02-20', '18:40:00', null, '休み（未対象）', null, null, null),
  ('45e6e709-f0cd-518f-8cc1-5bdb3d81fe23', 'ec153bd8-5b4d-5684-9704-382af23cf64a', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-02-21', null, null, '通常 / 自由制作/上級', '前々回の自由制作に引き続き、「サメや宝箱が流れてきてキャッチしたりよけたりするゲーム」の続きでした。 サメを倒すために、スペースキーを押してビームが出るようにしていた。 途中、連続でビームが出てしまう問題に直面していたが「スペースキーが押されない状態まで待ってほしくない？」という問いかけをする事で解決できた。 また弾数がなくなった後、サメよりも低い頻度で流れてくる宝箱に触れたらランダムな数の弾数が増える機能も追加しました。 宝箱の画像は著作権の説明をした上でいらすとやの物を使用しました。', null, '時間帯: その他'),
  ('ee17e0dd-2e0e-5d71-9b9e-b7450c1b428c', 'c47b4046-9872-56fc-a811-2f1cb7d0d1a0', null, 'd8fdbd48-c21b-5d6c-8db9-abba90c50ddf', '2026-02-21', null, null, '通常 / 基本操作コース08_01', '今日は基本操作コース_08の「さぁ、踊ろう」に取り組みました。 躍らせるコスチュームに色々絵を描くことに夢中で踊るまで時間がかかりました。また、メッセージの使い方で戸惑っていた部分がありました。 答えは見せずに「こういう動きをするためにはどのブロックを使えばいいかな？」という感じで進めましたが１つ1つのステップが小さいので基本的につきっきりで付くことになりました。', '残り3個ほど基本操作コース_08が残っている(スタンプが押されていない)のでそちらをお願いします。', '時間帯: その他'),
  ('5986cc82-b7f7-5c8f-b0a9-0341166c00e0', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2026-02-21', null, null, '通常 / Webサイト作成', '前回に引き続きStudioでのWebサイト作成をしていました。トップページをどうすべきか悩んでいるようだったので、進め方のアドバイスをしたくらいで、あとは自力で進めていました。ChatGPTやCopilotを使って、進めているようでした。中学生という年代での生成AIの扱い方についてどうあるべきか、判断が難しいので、この年代での生成ＡＩの向き合い方はなにか考えたうえでアドバイスできれば良いなとは思いました。', null, '時間帯: その他'),
  ('f5fec731-6f62-5408-b19c-6c19f9c1421b', '31feac25-f850-5d21-8e43-ed4d7badb6a0', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2026-02-21', null, null, '通常 / 自由制作', '前回からのつづきで獲った魚を出荷する流れを作ろうとしていたが、イメージがわかないようでその企画は一旦考え直すとのこと。 レアキャラ追加を進めていた。(戦闘機、ネコ魚、刀魚)', null, '時間帯: その他'),
  ('32d72ec6-ba97-5d9a-93b3-9e59bde71a8d', '40a476bc-72a5-5bdc-ab75-e89d5310b442', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2026-02-21', null, null, '通常 / 自由制作', '前回からの自由制作の続きで、ヒラメ・熱帯魚のリズムゲームで、矢印がヒラメに向かって動いて行って、 ヒラメに重なったタイミングで矢印キーを押すことで得点になるというものはすでにできていました。ただ、右矢印のみだったのと、同じようなスピードで10回繰り返すだけというシンプルなもので、ゲーム性が低いので、なにかもう一点アクションを追加してゲーム性を上げるようにしたらとアドバイスして、それを受け入れてくれました。結果、バスケットボール（海なのに何故とは思いましたが、あえてスルーしました）が矢印と別方向からヒラメに向かって言って、ヒラメと重なる瞬間にA,Ｄキーを押すことでスコアアップ、バスケットボール跳ね返る等の処理を追加、効果音も追加して、それなりにゲーム性も上がり、初級レベルとしてはなかなか良い感じになってきたのではと思いますし、本人的にも結構満足できている感じです。次回以降は、このゲームをすこしずつもっと良い感じに更新したいし、新しいゲームも作りたいとのことだったので、また、次回話し合いながら進め方を決められたらよいかと思います。ちなみに、ちかと君は、わからない状態が長い間続くと、うなだれてやる気をなくす傾向があるので、今日もそんな感じを察知して、ヒントを多めにしたり、悩んでる部分はあきらめて別のやり方を進める等したら、ずっと集中力を継続できて楽しく進められたと思います。', null, '時間帯: その他'),
  ('d89ecb03-f3be-59eb-851b-866ac9650c8a', '655ad2c9-dfb5-5fc7-b41a-1d784603c1d0', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2026-02-21', null, null, '通常 / 自由創作DAY', '自由創作中級は、前回で完成していた。上級については特にやりたくないニュアンスでした。 本日は、フリー素材の入手方法とルールについて説明をし、背景をダウンロードした。 中級の内容を少し触りながら、上級につながることをやってみようと提案して、次回以降やりたいとのこと。 まずは、宝箱のフリー素材、中級でできている背景チェンジをレベルチェンジに変えていくなどを提案しています。', null, '時間帯: その他'),
  ('f6645054-008c-540e-a4b2-29fc8dd0c2c0', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2026-02-21', null, null, '通常 / 自由制作', '前回から引き続きのゲーム製作で、基本、自力でスムーズに進めていましたが、何点かうまくいかないところをアドバイスしました。一点は、「〇〇が押されていない」まで待つをやっているのに、ボタン押しっぱなしでずっと攻撃してしまうというもの、ブロックの置き方の順番に問題があることを指摘すると、すぐわかって自力で修正していました。もう一点にたような修正のアドバイスをしたくらいで、あとは問題なく進められていました。音楽を追加したいというところで、レッスンが終わったので、次回は音楽決めからと思います。', null, '時間帯: その他'),
  ('45e3ff6f-b963-5b3b-a574-7deda9a436ff', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '86c6b69e-4c02-52b3-8076-47643289a712', '2026-02-21', null, null, '通常 / 自由創作中級', '前回の続きから、海中にフリー素材の宝箱を置いた。ただアルスタジオ上での背景余白の編集ができなかったため、こう先生に教えてもらった、画像背景除去ツール(Web上)を使って背景余白の除去をして使用をした。 ゲームとしての全体像はできてきたので、今後は仕上げをすすめるか、上級要素を取り入れるかになると思います。', null, '時間帯: その他'),
  ('3188f771-030b-578d-b5fc-fce58b786dea', '2758b49a-c2b1-5cd0-9b37-3b988f2a5a09', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-02-21', null, null, '通常 / 自由製作', 'おしゃべりから追いかけっこのシーンに移行するためにメッセージを使いました。メッセージを送るブロックと受け取るブロックがごっちゃになっていたので、区別して押さえました。追いかけっこするときに、「～へ行く」を試してみて、瞬間移動になるから変だと気付きました。その流れで、「～に向ける→10歩動く」という方法を学びました。 追いかけっこが終わった後どうする？という問いかけに対しては、じっくりと考えていました。こちらからはもう一度おしゃべりをさせることを提案しました。最終的に、それに加えて、背景を変えることにしました。そのとき、背景の名前がわかりづらかったので変え方を伝えました。 実現したいものに合わせて少しずつスキルを身に着けてきていると思います。', null, '時間帯: その他'),
  ('60713e07-2efa-5443-a119-3bfa8c5575ed', 'b91baeb5-4a26-5308-bc47-e0a265723227', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-02-21', null, null, '通常 / 基本操作', 'マウス操作が苦手だというので、最初にマウス練習としてイライラ棒のゲームで遊びました。すぐ壁にぶつかっていたのが、次第に遠くまで行けるようになっていました。 プログラミングはピンポンゲームをやりました。基本操作の番号的には音楽や物語が先ですが、それよりもゲーム性のあるもののほうが興味を持てるかなと思い、やりたいものを選んでもらいました。予想通りピンポンゲームがいいようでした。 「～に触れたとき」や「全て止める」といった今までに扱ったブロックはほぼ自力で使えるほどでした。一方で回転操作が苦手なようで、バウンドさせるときに角度でなく座標を変えてしまうことがありました。バウンドの前後で向きが変わっていることを観察してもらいました。 対話するのが苦手なようですが、「○○？○○？」と選択肢を示したうえで聞くとややスムーズに答えてくれた感じがしました。', null, '時間帯: その他'),
  ('f951cd42-b627-55e9-a9e2-83031201b56e', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-02-21', null, null, '通常 / 自由製作', '主人公が新しい姿に変化するようにしていました。ある姿では遠距離攻撃を繰り出せるようにしたり、別の姿では攻撃の威力を上げたりとゲーム性を高める工夫をしていました。それが終わるともう完成だといってゲームで遊び始めてしまいましたが、音が全くなっていなかったので演出としてつけることを提案するとやる気になったようでした。フリーBGMを検索したりもしましたが、やすのりくんを真似するように、自分で「音楽」ブロックを配置して曲を作ることに決めました。', null, '時間帯: その他'),
  ('ed8b03d2-abd7-5baf-bc18-8094c3df1dce', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2026-02-21', null, null, '通常 / ロブロックス', 'いつも通り、ロブロックスで半分遊びながら、レッスン時間を決めて、少しずつ進めていきました。やっとで、アスレチックで冒険！（後編）を終了させて、確認テストを実施しました。が、さすがに、1週間に１回、しかも片手間にやった程度では、身につくわけはなく、if文やfor文等のスクリプトに関する質問には回答できる状態ではありません。もちろん、それらを教えますが、if文のtrue, falseに関する考え方とかは、もっとまじめに集中して考えて、それを日常的にプログラムで使うようにならないと、腹落ちしないんじゃないかなと、毎回思ってしまいます。（if文の話だけに限らず）個人的にはデジタネの教材だけではロブロックスのゲームを思い通りに作れるようにはならないと思うので、というか、よっぽどやる気のある子で、デジタネで学んだこと以外を自力で覚えようとする意志のある子しか、ゲームを作れるようにならないという感じかな。ということを含めて考えると、ロブロックスの進め方は何か考えた方がよいのかなと思っています。（どうすべきかまでは案はありませんがm()(__）m', null, '時間帯: その他'),
  ('a540da38-ef6d-5742-b867-6b66609c891a', '76019ebd-2809-5e43-b3c7-1c8834a9e170', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2026-02-21', null, null, '通常 / 基本操作', 'ひとつずつ全部やっていくとなると興味がそれてしまいそうだったので、自然な流れで新しいスキルに誘導しました。例えばピアノの音を一つ鳴らしたタイミングで、「もっと鳴らしてメロディーにしてみない？」と提案しました。ここですべての音を同時に鳴らしてしまったので、1秒待つことで順番に鳴らすという考え方を伝えました。1秒待つ自体は見たことがあったようですが、こういう使い方は初めてだったので、お手本コードを見せて同様に作ってもらいました。音楽とは関係ないですが、キャラにセリフを言わせるのもやりたいと言ったので、「～と言う」を扱いました。タイピングも初めてでしたが、ローマ字表を見ながら真剣に一文字ずつ打っていました。', null, '時間帯: その他
盛り上がり: 何か追加するたびに面白がって、あやとくんに見せていました。'),
  ('1a3cb35c-5017-5493-8bf2-b6ea7bdde027', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-02-24', '16:30:00', null, '通常 / ロブロックスの学習をスタートする', '動画を一人で見て学習することを改めて説明すると、「めんどくさー」とくねくねし始めました💦が、動画の速度は、自分がわかる範囲ならあげてもOKなこと、毎回必ず動画を見て確認テストをするなら、自分で時間配分して、ロブロックスのゲームをしても構わない、そのかわり、必ずその日の目標のテストまでは進むこと、という約束をすると、表情が柔らかくなって「わかった」と返事をしました。 前回のPCで開けなかったロブロックスのバスの運転？ゲームが、今日の「ミント」PCだと開けたのが嬉しかったようで、しばらく遊んでは動画に戻って視聴する、というのを繰り返していました。最終的に確認テストをし、1度目は60パーセントでしたが、間違えた問題をやり直して100パーセントを出して、終了していました。', null, '盛り上がり: ロブロックスの初めの方は、楽しいという内容ではないかもしれないけれど、自分でいろいろできるようになるまでは地道に学習することを約束し、自己責任で、授業時間内に確認テストができるように随時休憩してゲームタイムを挟むことは可、という取り決めが納得できたのか、時間としてはゲームの方が長かったですが、テストはきちんとできるまで取り組もうとする姿勢が見られました。'),
  ('023767bf-dd04-5482-83ac-42b9c3a80994', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2026-02-24', '17:30:00', null, '通常 / 自由制作', 'エフェクトの作成にこだわっていた。YouTubeで楽しいゲームの作り方の動画を見ながら、根本的に楽しいゲームとは何かを勉強していた。斧を振るアクションと敵の攻撃を作っていた。', null, '盛り上がり: 授業終わりは自分の過去作をプレイしていた。'),
  ('400efa62-5e26-5f32-8624-8e8e78187114', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2026-02-24', '17:30:00', null, '通常', '最初はRobloxただプレイしているだけで動画をあまり見ていなかった。18時から動画を見ながら受講していたが、授業終わりに様子を聞くと、よくわからない！と言っていました。動画通りの教材を開くところから指導したいと思います。', null, '盛り上がり: Roblox自体は楽しくプレイしていました。'),
  ('d0c37597-6a77-5c9c-b8c9-e8903d0293cf', '1c7005cc-2815-558f-993a-9c7617d34c44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-02-24', '16:30:00', null, '通常 / 基本スキルを学ぶ', '今日は3人の生徒に対して先生が一人だったため、つきっきりというわけにはいきませんでしたが、カードを自分で見てやってみる、という練習の良い機会になりました。 音楽をつくろうでは、とにかく見本と同じように作る、という意思がはっきりしていて、見本の英語の音名などもすべて日本語ではどう書いてあるのか聞いてきて、同じように作成していました。録音などは、はじめは「めんどくさそう」と言って嫌がりましたが、ブロックは１つだけだからとなだめて進めていくと、机をたたいた音が想像以上に面白かったのか、得意そうに何度も鳴らして喜んでいました。 基本操作コースのコースは踊ろう以外は一通りさらったので、自分で問題を読む練習もかねて、ドリルに進みました。 はじめはカードの問題を数字順に一緒に音読して、このブロックはどれだっけ？という形で進めましたが、問題1～2の範囲のブロックはきちんと覚えていて、問題2は自力で進めることができました。（そばで見守っていてほしそうでしたが💦）', null, '盛り上がり: 問題文が1行くらいなら、それほど抵抗感なく読むことができ、自分でブロックが見つけられたのも嬉しそうで、難しい問題でなければ、ドリル形式はわりと向いているかもしれないという感触でした。'),
  ('504655d2-295e-5024-bb3e-c9f4517566c1', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'baf0d64d-8a04-5f1d-b7ba-c0c76d280c08', '2026-02-24', '17:30:00', null, '通常', '今日自由制作のゲームがちょうど完成したみたいです。サメから逃げながら宝箱を集めるゲームでした。かなり良くできていて本人も満足気でした。細かい場所を修正すればもっといい感じのゲームになると思います。', null, '盛り上がり: 自由制作に入ってからいつもより楽しそうにゲームを作っています。'),
  ('4c611751-2a3b-539a-abcf-203ef21277ad', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-02-24', '16:30:00', null, '振替 / 自由制作（ミッション達成を意識して）', '次の通常クラスと続けて2時間だったので、休憩をはさみながら取り組みました。 条件達成という課題はよく意識できていて、今日は条件2と3をそれぞれの時間内に達成するということを目標に進めました。 前回作成した計算ゲームにクローンをどう取り入れるか迷っていたので、正解したら画面を彩る感じにしてみたら？と助言すると、すぐに作成にとりかかっていました。フリー素材を検索してアルスタジオに取り込むのはすべて自分でやれていました。 クローンを作成する以外のブロックを忘れていたとのことなので、「作成する」と「クローンされたとき」と「クローンを削除する」のブロックのを口頭で説明しました。 わりと無駄のない作成をしていて、いずれの条件も短時間で「できたから見て」とアピールしてきていました。 後半の時間が余ったため、なにかアレンジの課題を出してほしいというので、棒人間アスレチックをプレイさせて、クリアできるようなアレンジを加えていました。', null, '盛り上がり: 休憩してゲームをすることも多かったですが、きちんとやることはクリアしていました。先生にも積極的に声掛けをして、自分の作品を見てもらいたがっていました。'),
  ('49659ca4-daa9-5ca9-b932-569fb1081b7a', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2026-02-24', '17:30:00', null, '振替 / 自由制作（ミッション達成を意識して）', 'クローンしたときの魚の動きが面白いらしく、何度も先生を呼んでは楽しそうに見せてくれました。 条件3について、背景を用意するところまでできていたので、そこからステージを変えるきっかけをどうするか、クリアの条件をどうするかについて、かなり時間をかけて悩んでいました。ステージの変更については、最初に選択ボタンを出すことにしたようで、コスチュームを試行錯誤しながら編集していました。 背景やスプライトを選択する一覧のところで、絵をchromeのタブのところに持っていくと、画像ファイルとして開けることを発見したそうで、とても熱心に実践して見せてくれました。 今日は考えている時間が多く、実際のコード作成はあまり進んでいませんが、やりたいことは見えてきたようなので、次回以降、それを形にしていければと思います。', null, '盛り上がり: クローンされた魚が動き出すタイミングなどに一工夫していて、うまく自分の魚を動かすとクローンの動きを制御して、魚をまとめることができるなど、作成中のいろいろな発見を楽しそうに詳しく教えてくれました。'),
  ('24b3c392-7045-5b09-b402-41acee832b0a', '57f45872-1f3e-5540-b676-bf9023444e39', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-02-26', '16:30:00', null, '通常 / 自由創作DAY', '前回音声の追加までだったので、正しく流れるようにするのを目標に始めました。 ちょくちょく立ち上がったりゲームをしてしまい、前半30分ほどはあまりすすみませんでした。 後半、音声をちゃんと流れるようにするのはあきらめ、距離に応じて背景が変るプログラムの追加を目標に変えました。 促しながら、背景をダウンロードし、距離300ごとに二つの背景を繰り返して変えたいとのことで、300ごとに0と1で返す演算だけ教え、作成しました。', '自由創作続き', '盛り上がり: 授業終了後たかひとくんと仲良く遊んでいました。'),
  ('cef961ec-935c-5668-a29a-c1f709bc1785', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-02-26', '16:30:00', null, '通常 / ロブロックスの操作を使いこなそう', 'ロブロックスはレッスンで、作成に当たる操作方法を復習しました。動画で言っていないショートカットキーのことは覚えぬけていたので、選択移動拡大回転を再度確認しました。ある程度動画を見ると、ひと速くアレンジに進めたくなるので、なるべく外れない程度にアレンジをしました。虹色のらせん階段をかなり高くまで作っていました。そこで、複製の方法を知りたかっていたので、Ctl+C,Vについて教えてあげました。レッスン序盤はコード作成までまだ先なので、このようなPC上のスキルを習得できる良い機会だと感じました。', null, '盛り上がり: M2 頂上を目指せ！続き'),
  ('a19527f1-d7d3-51f5-a330-18ff6e1c0780', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-02-26', '16:30:00', null, '通常 / 自由創作DAY', '最初に先週話した通り、スタート画面がスタート画面だと解るようにするのと距離のカウントが正しく始まるようにするのを目標に設定しました。 スタートの背景に文字を追加し、改善しましたが、距離のカウントの方は集中力が切れてしまったようで、ゲームを始めてしまいました。 その後、距離のカウントのプログラムがどこにあるのか、どのように変えたらよいかを伝え、再開しました。 修正後、まだ時間があったので、距離に応じて何か変更するのを新たな目標にしました。 演算を使用して距離を判定する方法を教えて、あとは自分で距離が一定を超えると操作キャラクターがクジラに変るように改良していました。 また、クジラに変ると連続ジャンプができるようになり、それのバランスのためにコースの上の方に障害物を設置していました。 来週はゲームオーバー時にプログラムがちゃんと終了するのを目標にすることを確認しました。', '自由創作続き', null),
  ('b40c1ef3-2b1b-5f12-aa79-0d43aeb3ed47', 'f3102a36-fdd8-574f-bf3c-85723faf424f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-02-26', '16:30:00', null, '通常 / 自由創作', '自由創作を完成したと言ってきたので、条件をすべて満たしているか確認しました。条件を満たしていたものの、クリアの演出がなかったので付け加えてもらいました。それも完成したので、次の作品に移りました。 過去に別の教室で似たようなものをやったと言っていましたが、自分なりにアレンジを加えて一から作成してもらいました。迷路上のゲームでしたが、触れる判定で簡単に作成できていました。アレンジとして、自分で動かす剣がずっと回転していて、剣の向きによって通れる瀬正道を作って難易度を調整していました。また、学校でラグビーボールを使ってサツマイモに似ていたことから、サツマイモのが位置を邪魔してくるようになる仕組みを加えて面白みを増えていました。', null, 'タイピング: 今回は結果振るわずでしたが、次回頑張ろう
盛り上がり: 完成したゲームをルイ君に遊んでもらって喜んでいました。'),
  ('55242bbc-be0e-5e17-a043-5d85458f534a', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-02-26', '17:30:00', null, '通常 / 自由創作DAY', '自宅でも作成していたようで、作品の読み込みにトラブルがありましたが解決し、そこから開始しました。 敵の足軽の攻撃の動きのバグ修正に取り組みました、攻撃のプログラムがクローン作成時のスクリプト内ではなく、メッセージによって実行されていたため、同時に実行できないのが原因でした。 原因を伝え、修正できました。 その後、回復アイテムや中ボスの追加を始め、敵の特殊攻撃なども実装していました。 中ボスのしっかりした動きはまた今度実装するようです。 撃破数のカウント表示の変数を追加し、授業時間終了になりました。', '自由創作続き', '盛り上がり: そうたくんと歴史雑談を楽しそうにしていました。'),
  ('53389c08-4bd9-5cb5-8703-2ca7e4d3f003', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-02-26', '17:30:00', null, '通常 / 自由創作day', '前半は船が強襲してきて、砲撃で撃ち落とす展開の始まりと終わりを作っていましたが、その間のアイデアがなかなか絞り込めず、作っては直すことが多かったです。それでも悩みまくっていたので、いったんこのプランAを保存して、プランBを別途作り始めました。こちらの方は、どんぐりみたいな船で自分で動かし、HPがあるものにしたいそうです。今日はHPの残量がわかるように小技のHPゲージを持ってきました。次回はこれをどのようにHPを減らしていくか作れてたらいいです。', null, null),
  ('d594013b-4298-5e17-8b42-dbf94d3144ec', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '6655587e-c4e8-51d8-9eb8-f0b9160cf544', '2026-02-26', '17:30:00', null, '通常 / 自由創作DAY', '前回の続きからクイズの追加を始めました。 クイズに答えると宝箱が開き、宝石が入手できるというゲームになるようです。 クイズの内容を見ましたが、海に関する問題を10問作成しており、こだわって作成しているようでした。 クイズに正解後、宝箱が宝石のコスチュームに変るようにしたいようでしたが、うまくいっていませんでした。 コスチューム変更が一瞬で変わってしまっているのでn秒待つを追加したら良いのでは？と伝え、解決できました。 また、クイズの出題のプログラムに定義を使用していましたが、あまり有効に活用できているように見えませんでした。', '自由創作続き', '盛り上がり: タイピング大会の結果を伝え、喜んでいました。'),
  ('1814eccc-9f30-534f-99af-07edf82acfe9', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2026-02-26', '17:30:00', null, '通常 / ロブロックス', '授業前から自由創作の作品を作っていました。前回指摘された当たり判定の貫通するバグを直していたみたいです。前の時間では終わらなかったので、前半30分はアルスタジオでその作業をしました。区切りよく直せたので、後半はロブロックスをしました。M1のレッスンはロブロックスを体験をしてみようの風味があるので、ここでできるアレンジを単身でもらいました。素材が豊富にあるので、たくさん追加して、ゾンビから追い掛け回されるようなものに変わっていました。最後にぎりぎりで確認テストを行い、内容は理解していました。', null, null),
  ('096e34a2-778b-5fa8-9152-0533ec645310', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, null, '2026-02-27', '17:30:00', null, '休み（振替対象）', null, null, null),
  ('8e97feaa-1324-56e4-a640-532ca6e28fd0', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-02-24', '18:40:00', null, '通常 / 図形を描く □を描く、（レベルによって）△を描く、〇を描く', '正方形を描いてペン機能の使い方を確認しました。その後、〇を描いてもらいましたが、角度の考え方はバッチリでした。できる限り滑らかに動かすときの角度の設定のポイントを共有しました。 「動かす」ということを忘れてしまうようです、オリンピックマークを作るときも大きさの調整に苦労していました。複数のスクリプトを使ってプログラムしていましたが、メッセージをうまく使って丁寧に作れていました。最後に三角形を作ってもらいました。ばっちりでした。図形は得意なようです。', '・検定2級をもう一題…②か応用課題 ・検定受検日の決定', 'タイピング: ミスタイプ率が22%とかなり高かったです。速度を重視してしまうのかな。
盛り上がり: さらちゃんと作品について話したり、検定についてお母さんと話したりと、楽しそうにしている様子が作品作りにも良い影響を与えているようで、コンテストにも検定にも前向きの様子が見られました。
備考: 眞子ちゃんの話では、中学受験はやめたとか…？'),
  ('5a645a0a-091b-5744-ae43-a937b8dc0fe4', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '39c367bc-400f-521c-85a3-5b6d9099f4a3', '2025-12-04', '17:30:00', null, '通常', '積極的にアレンジに取組んでいました。スプライトの変更に特に力を入れており、持ち時間の大半をつぎ込んでいました。 コード自体の変更は特に行わず、追記していく形で新機能の実装を行っていました。 序盤はスプライトの変更の操作に手間取っている様子でリミックスのやり直しなどを複数回行っていました。', null, '盛り上がり: ゴキブリのスプライトの作成について、かなりリアル志向で楽しみながら進めていました。')
on conflict (lesson_record_id) do update set lesson_date = excluded.lesson_date, start_time = excluded.start_time, end_time = excluded.end_time, title = excluded.title, content = excluded.content, homework = excluded.homework, memo = excluded.memo;

commit;
